# Instagram session cookie rotation
# Supporte plusieurs noms de variables d'environnement (priorite haut en bas) :
#   - INSTAGRAM_COOKIE (le plus simple, recommande pour user)
#   - INSTAGRAM_SESSION_IDS (legacy multi-cookies, separes par virgule)
#   - INSTAGRAM_SESSION_ID (legacy single)
# On filtre les valeurs placeholder fakes ('cookie1', 'cookie2', etc.)
def _filter_real_cookies(raw: str) -> list[str]:
    """Garde uniquement les cookies qui ressemblent a de vraies sessions Insta.
    Vrai sessionid : commence par chiffres + %3A + texte (ex: '12345%3AABC...')
    Fake : 'cookie1', 'cookie2', 'test', etc.
    """
    cookies = [s.strip() for s in (raw or '').split(',') if s.strip()]
    real = []
    for c in cookies:
        # Un vrai sessionid Insta a au moins 30 chars + contient '%3A' (= : encode)
        if len(c) >= 30 and ('%3A' in c or ':' in c):
            real.append(c)
    return real

_raw_cookie = os.environ.get('INSTAGRAM_COOKIE', '').strip()
_raw_sessions = os.environ.get('INSTAGRAM_SESSION_IDS', '').strip()
_raw_legacy = os.environ.get('INSTAGRAM_SESSION_ID', '').strip()

# Priorite : INSTAGRAM_COOKIE > INSTAGRAM_SESSION_IDS > INSTAGRAM_SESSION_ID
INSTAGRAM_SESSIONS: list[str] = (
    _filter_real_cookies(_raw_cookie)
    or _filter_real_cookies(_raw_sessions)
    or _filter_real_cookies(_raw_legacy)
)
# Single alias for backward compat
INSTAGRAM_SESSION_ID = INSTAGRAM_SESSIONS[0] if INSTAGRAM_SESSIONS else ''
_instagram_session_index = 0

def _extract_ds_user_id(session: str) -> str:
    """Extrait le ds_user_id du cookie sessionid Instagram.
    Format: 'USER_ID%3A...' (URL-encoded). Renvoie '0' si extraction echoue.
    """
    if not session:
        return "0"
    try:
        # %3A = ':' URL-encoded
        if '%3A' in session:
            return session.split('%3A')[0]
        if ':' in session:
            return session.split(':')[0]
    except Exception:
        pass
    return "0"


def _build_instagram_cookie_header(session: str) -> str:
    """Construit le header Cookie Insta complet (sessionid + ds_user_id extrait)."""
    if not session:
        return ""
    ds_uid = _extract_ds_user_id(session)
    return f"sessionid={session}; ds_user_id={ds_uid}"


# ── ROTATION INTELLIGENTE COOKIES INSTAGRAM ──
# Si un cookie retourne 429 ou est bloque, on le marque "bad" pour eviter
# de le re-utiliser pendant qu'Instagram le surveille.
# DUREE COURTE (5 min) car beaucoup de cas le rate limit IG est temporaire.
# Si 3 echecs consecutifs : on monte a 30 min puis 2h.
_INSTAGRAM_SESSION_BAD_UNTIL: dict = {}  # cookie -> timestamp jusqu'a quand bad
_INSTAGRAM_SESSION_BAD_DURATION_SEC = 300  # 5 minutes (au lieu de 1h)
_INSTAGRAM_SESSION_FAILURE_COUNT: dict = {}  # cookie -> nb echecs consecutifs

def _mark_instagram_session_bad(cookie: str, duration_sec: int = None):
    """Marque un cookie comme bad (429/banni) pendant N seconds.
    Apres 3 echecs consecutifs, on monte a 30 min puis 2h max."""
    if not cookie:
        return
    duration = duration_sec or _INSTAGRAM_SESSION_BAD_DURATION_SEC
    _INSTAGRAM_SESSION_FAILURE_COUNT[cookie] = _INSTAGRAM_SESSION_FAILURE_COUNT.get(cookie, 0) + 1
    # Backoff sur echecs consecutifs (sans depasser 2h)
    if _INSTAGRAM_SESSION_FAILURE_COUNT[cookie] >= 3:
        duration = min(duration * 6, 7200)  # max 2h
    _INSTAGRAM_SESSION_BAD_UNTIL[cookie] = time.time() + duration
    logger.warning(f"Instagram session marquee bad pour {duration//60}min (echecs={_INSTAGRAM_SESSION_FAILURE_COUNT[cookie]})")

def _mark_instagram_session_good(cookie: str):
    """Reset le compteur d'echecs apres un succes."""
    if cookie and cookie in _INSTAGRAM_SESSION_FAILURE_COUNT:
        _INSTAGRAM_SESSION_FAILURE_COUNT[cookie] = 0

def _get_instagram_session() -> str:
    """Round-robin INTELLIGENT : skip les cookies marques bad recemment.
    Si tous les cookies sont bad : on retourne le moins recemment marque."""
    global _instagram_session_index
    if not INSTAGRAM_SESSIONS:
        return ''
    now_ts = time.time()
    # Cherche un cookie valide dans l'ordre round-robin
    for _ in range(len(INSTAGRAM_SESSIONS)):
        cookie = INSTAGRAM_SESSIONS[_instagram_session_index % len(INSTAGRAM_SESSIONS)]
        _instagram_session_index += 1
        bad_until = _INSTAGRAM_SESSION_BAD_UNTIL.get(cookie, 0)
        if bad_until <= now_ts:
            return cookie
    # Tous les cookies sont bad -> on prend celui qui sera disponible le plus tot
    best = min(INSTAGRAM_SESSIONS, key=lambda c: _INSTAGRAM_SESSION_BAD_UNTIL.get(c, 0))
    logger.warning(f"⚠ Tous les cookies Insta sont bad — on tente quand meme {best[:20]}...")
    return best
