# Channel IDs YouTube test
YOUTUBE_TEST_CHANNELS_FALLBACK = [
    "UCBR8-60-B28hp2BmDPdntcQ",  # YouTube officiel
    "UC-lHJZR3Gqxm24_Vd_AJ5Yw",  # PewDiePie
    "UCq-Fj5jknLsUf-MWSy4_brA",  # T-Series
    "UCpEhnqL0y41EpW2TvWAHD7Q",  # SET India
    "UCX6OQ3DkcsbYNE6H8uQQuVA",  # MrBeast
]

_WATCHDOG_FAILURES: dict = {"instagram": 0, "tiktok": 0, "youtube": 0}
_WATCHDOG_LAST_CHECK: dict = {}


async def _run_watchdog_check(platform: str) -> dict:
    """Test scrape sur le compte test pour verifier que la cascade marche.
    Renvoie {success, source, count, error, duration_ms}."""
    username = WATCHDOG_TEST_ACCOUNTS.get(platform)
    if not username:
        return {"success": False, "error": "no test account"}

    start = time.time()
    try:
        if platform == "youtube":
            videos = await _fetch_youtube_videos(username, since_days=7)
        elif platform == "tiktok":
            # FIX: la signature est (username, since_days, user_id) — pas platform_channel_id
            videos = await _fetch_tiktok_videos_async(username, since_days=7, user_id=None)
        elif platform == "instagram":
            videos = await _fetch_instagram_videos_async(username, platform_channel_id=None, since_days=7)
        else:
            return {"success": False, "error": "unknown platform"}

        duration_ms = int((time.time() - start) * 1000)
        success = bool(videos and len(videos) > 0)

        if success:
            _WATCHDOG_FAILURES[platform] = 0  # reset
        else:
            _WATCHDOG_FAILURES[platform] = _WATCHDOG_FAILURES.get(platform, 0) + 1

        _WATCHDOG_LAST_CHECK[platform] = {
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "success": success,
            "video_count": len(videos) if videos else 0,
            "duration_ms": duration_ms,
            "consecutive_failures": _WATCHDOG_FAILURES.get(platform, 0),
        }

        # Pas d'auto-alerte basee sur seuil arbitraire.
        # Le user consultera _WATCHDOG_LAST_CHECK pour voir les status reels.
        return {
            "success": success,
            "platform": platform,
            "test_account": username,
            "video_count": len(videos) if videos else 0,
            "duration_ms": duration_ms,
            "consecutive_failures": _WATCHDOG_FAILURES.get(platform, 0),
        }
    except Exception as e:
        _WATCHDOG_FAILURES[platform] = _WATCHDOG_FAILURES.get(platform, 0) + 1
        err_str = str(e)[:300]
        _WATCHDOG_LAST_CHECK[platform] = {
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "success": False,
            "error": err_str,
            "consecutive_failures": _WATCHDOG_FAILURES.get(platform, 0),
        }
        return {"success": False, "error": err_str, "platform": platform}


async def watchdog_loop():
    """Tourne toutes les heures, teste chaque plateforme."""
    while True:
        try:
            for plat in ("instagram", "tiktok", "youtube"):
                try:
                    await _run_watchdog_check(plat)
                except Exception as e:
                    logger.warning(f"Watchdog {plat} error: {e}")
                await asyncio.sleep(2)  # petit delai entre plateformes
        except Exception as e:
            logger.error(f"Watchdog loop error: {e}")
        await asyncio.sleep(3600)  # 1h entre checks


async def track_videos_loop():
    """Scheduler HORAIRES FIXES : tick toutes les 5 min, scrape les campagnes DUES
    a leur prochain horaire fixe (8h ou 20h Paris).

    Lock global _TRACKING_RUN_LOCK : si le tick precedent n'est pas encore termine
    (ex: 50+ campagnes prennent > 5 min), le suivant skip pour eviter 2 runs en
    parallele (qui causeraient doublons + double rate limit Insta).
    """
    TICK_MINUTES = 5
    while True:
        if _TRACKING_RUN_LOCK.locked():
            logger.warning("Skip tick scheduler : un run precedent est encore en cours")
        else:
            async with _TRACKING_RUN_LOCK:
                try:
                    await run_video_tracking()
                except Exception as e:
                    logger.error(f"Video tracking loop error: {type(e).__name__}: {e}", exc_info=True)
        sleep_seconds = TICK_MINUTES * 60
        logger.info(f"Next scrape tick dans {TICK_MINUTES}min (horaires fixes 8h/20h Paris)")
        await asyncio.sleep(sleep_seconds)


@api_router.get("/scrape-schedule")
async def get_scrape_schedule():
    """Retourne les horaires de scrape (Europe/Paris) + le prochain en UTC.
    Public — affiché sur les campagnes."""
    next_utc = _next_scrape_time_utc()
    return {
        "timezone": "Europe/Paris",
        "schedule": [f"{h:02d}:{m:02d}" for h, m in SCRAPE_SCHEDULE_PARIS],
        "next_scrape_utc": next_utc.isoformat(),
        "next_scrape_paris": next_utc.astimezone(PARIS_TZ).strftime("%H:%M"),
    }


async def _cleanup_dirty_usernames(scope_query: dict = None) -> dict:
    """Nettoie tous les comptes dont username = URL ou contient des caractères louches.
    scope_query : optionnel, restreint à une campagne via account_ids.
    Retourne {fixed: int, sample: [...]}."""
    query = scope_query or {}
    accounts = await db.social_accounts.find(query, {"_id": 0}).to_list(2000)
    fixed = 0
    samples = []
    for acc in accounts:
        old_username = acc.get("username") or ""
        if not _looks_like_url_or_dirty(old_username):
            continue
        platform = acc.get("platform")
        new_username = extract_handle_from_url(old_username, platform)
        new_username = (new_username or "").strip().lstrip("@").strip("/")
        if not new_username or new_username == old_username:
            continue
        # Update DB : nouveau username + reset status pour re-vérification + reset channel_id
        await db.social_accounts.update_one(
            {"account_id": acc["account_id"]},
            {"$set": {
                "username": new_username,
                "status": "pending",
                "platform_channel_id": None,
                "error_message": None,
                "last_scrape_error": None,
                "_username_fixed_from": old_username,
                "_username_fixed_at": datetime.now(timezone.utc).isoformat(),
            }}
        )
        # Re-launch verification in background
        try:
            asyncio.create_task(_verify_and_update_account(acc["account_id"], platform, new_username))
        except Exception:
            pass
        fixed += 1
        if len(samples) < 20:
            samples.append({
                "account_id": acc["account_id"],
                "platform": platform,
                "old": old_username,
                "new": new_username,
            })
    return {"fixed": fixed, "samples": samples}


@api_router.post("/campaigns/{campaign_id}/cleanup-and-rescrape")
async def cleanup_and_rescrape(campaign_id: str, user: dict = Depends(get_current_user)):
    """Pour une campagne : nettoie les usernames sales + re-scrape tout.
    Accessible agence/manager."""
    if user.get("role") not in ("agency", "manager"):
        raise HTTPException(status_code=403, detail="Réservé à l'agence et au manager")
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")
    if user.get("role") == "agency" and campaign.get("agency_id") != user["user_id"]:
        raise HTTPException(status_code=403, detail="Cette campagne n'est pas la vôtre")

    # Cleanup limité aux comptes de cette campagne
    assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).to_list(500)
    account_ids = [a["account_id"] for a in assignments]
    cleanup = await _cleanup_dirty_usernames({"account_id": {"$in": account_ids}})

    return {
        "ok": True,
        "fixed_count": cleanup["fixed"],
        "samples": cleanup["samples"],
        "message": f"{cleanup['fixed']} comptes nettoyés. Re-vérification en cours (~30-60s). Lance ensuite 'Scraping maintenant'.",
    }


_REFRESH_STATS_COOLDOWN_SEC = 300  # 5 min entre 2 refresh manuels par campagne (anti-abus)
_REFRESH_STATS_LAST: dict = {}  # campaign_id -> timestamp dernier refresh

@api_router.post("/campaigns/{campaign_id}/reset-tracking-data")
async def reset_campaign_tracking_data(campaign_id: str, body: dict = None, user: dict = Depends(get_current_user)):
    """🗑️ PURGE ABSOLU : supprime toutes les tracked_videos + snapshots de cette
    campagne, et relance un scrape complet depuis zero. Utile quand des stats
    fausses persistent en DB (ancien scraping bugue, anciennes valeurs gonflees,
    etc).

    ATTENTION : action destructrice — l'historique des videos trackees est perdu.
    Confirmation requise via body['confirm'] = true.
    """
    if user.get("role") != "admin":
        raise HTTPException(
            status_code=403,
            detail="Reserve a l'admin. Le reset / re-scrape complet d'une campagne ne peut etre declenche que par l'administrateur."
        )

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    body = body or {}
    if not body.get("confirm"):
        raise HTTPException(
            status_code=400,
            detail="Confirmation requise — body must contain confirm: true. Cette action efface toutes les stats actuelles."
        )

    # 1. Compte ce qu'on va supprimer
    videos_count = await db.tracked_videos.count_documents({"campaign_id": campaign_id})
    snapshots_count = await db.video_views_snapshots.count_documents({"campaign_id": campaign_id})
    daily_snapshots_count = await db.views_snapshots.count_documents({"campaign_id": campaign_id})
    user_snapshots_count = await db.user_views_snapshots.count_documents({"campaign_id": campaign_id})

    # 2. Supprime
    try:
        await db.tracked_videos.delete_many({"campaign_id": campaign_id})
        await db.video_views_snapshots.delete_many({"campaign_id": campaign_id})
        await db.views_snapshots.delete_many({"campaign_id": campaign_id})
        await db.user_views_snapshots.delete_many({"campaign_id": campaign_id})
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Erreur suppression : {e}")

    # 3. Reset budget_used + last_growth des comptes
    try:
        await db.campaigns.update_one(
            {"campaign_id": campaign_id},
            {"$set": {"budget_used": 0, "next_scrape_at": datetime.now(timezone.utc).isoformat()}}
        )
        # Reset les compteurs cache des comptes pour forcer un fresh scrape
        assignments = await db.campaign_social_accounts.find(
            {"campaign_id": campaign_id}, {"_id": 0}
        ).to_list(500)
        for a in assignments:
            await db.social_accounts.update_one(
                {"account_id": a.get("account_id")},
                {"$set": {
                    "last_growth": None,
                    "last_total_views": 0,
                    "last_tracked_at": None,
                    "last_scrape_error": None,
                    "last_scrape_warning": None,
                }}
            )
    except Exception as e:
        logger.warning(f"reset-tracking-data : reset secondaires failed : {e}")

    # 4. Lance un fresh scrape immediat en background
    cutoff = _parse_utc(campaign.get("tracking_start_date")) or datetime.now(timezone.utc)
    days_back = max(2, int((datetime.now(timezone.utc) - cutoff).total_seconds() / 86400) + 2)
    days_back = min(days_back, 90)

    async def _fresh_scrape():
        try:
            assignments = await db.campaign_social_accounts.find(
                {"campaign_id": campaign_id}, {"_id": 0}
            ).to_list(500)
            sem = asyncio.Semaphore(3)
            async def _scrape_one(a):
                async with sem:
                    acc = await db.social_accounts.find_one({"account_id": a["account_id"]}, {"_id": 0})
                    if acc and acc.get("status") == "verified":
                        try:
                            await _scrape_one_account_into_campaign(
                                acc, campaign, cutoff, since_days=days_back, wait_verification=False
                            )
                        except Exception as e:
                            logger.warning(f"reset fresh scrape failed for {acc.get('username')}: {e}")
            await asyncio.gather(*[_scrape_one(a) for a in assignments], return_exceptions=True)
            logger.info(f"reset-tracking-data : campagne {campaign_id} re-scrapee après reset")
        except Exception as e:
            logger.error(f"reset fresh scrape error: {e}")

    asyncio.create_task(_fresh_scrape())

    return {
        "ok": True,
        "deleted": {
            "tracked_videos": videos_count,
            "video_snapshots": snapshots_count,
            "campaign_snapshots": daily_snapshots_count,
            "user_snapshots": user_snapshots_count,
        },
        "message": f"Reset effectue : {videos_count} videos + snapshots supprimes. Re-scrape lance, donnees fraiches dans 1-3 min.",
    }


@api_router.post("/campaigns/{campaign_id}/refresh-stats")
async def refresh_campaign_stats(campaign_id: str, user: dict = Depends(get_current_user)):
    """Force un scrape immediat de la campagne. RESERVE ADMIN UNIQUEMENT.
    Les agences / managers / clippeurs n'ont PAS acces au scraping a la demande :
    le scraping suit les horaires fixes definis par leur abonnement (ex: 2x/jour Business).
    Rate-limit a 1 refresh par 5 minutes par campagne (anti-spam).
    """
    if user.get("role") != "admin":
        raise HTTPException(
            status_code=403,
            detail="Reserve a l'admin. Le scraping se fait automatiquement sur les horaires fixes definis par votre abonnement."
        )

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    # Rate limit
    last_refresh = _REFRESH_STATS_LAST.get(campaign_id, 0)
    elapsed = time.time() - last_refresh
    if elapsed < _REFRESH_STATS_COOLDOWN_SEC:
        wait_min = round((_REFRESH_STATS_COOLDOWN_SEC - elapsed) / 60, 1)
        raise HTTPException(
            status_code=429,
            detail=f"Refresh deja effectue recemment. Reessaye dans {wait_min} min."
        )
    _REFRESH_STATS_LAST[campaign_id] = time.time()

    # Force le next_scrape_at a maintenant pour declencher au prochain tick (max 30s)
    await db.campaigns.update_one(
        {"campaign_id": campaign_id},
        {"$set": {"next_scrape_at": datetime.now(timezone.utc).isoformat()}}
    )

    # Background : scrape immediat tous les comptes
    cutoff = _parse_utc(campaign.get("tracking_start_date")) or datetime.now(timezone.utc)
    days_back = max(2, int((datetime.now(timezone.utc) - cutoff).total_seconds() / 86400) + 2)
    days_back = min(days_back, 90)  # cap 90j pour refresh manuel

    async def _scrape_campaign_now():
        try:
            assignments = await db.campaign_social_accounts.find(
                {"campaign_id": campaign_id}, {"_id": 0}
            ).to_list(500)
            sem = asyncio.Semaphore(3)
            async def _scrape_one(a):
                async with sem:
                    acc = await db.social_accounts.find_one({"account_id": a["account_id"]}, {"_id": 0})
                    if acc and acc.get("status") == "verified":
                        try:
                            await _scrape_one_account_into_campaign(
                                acc, campaign, cutoff, since_days=days_back, wait_verification=False
                            )
                        except Exception as e:
                            logger.warning(f"refresh-stats scrape failed for {acc.get('username')}: {e}")
            await asyncio.gather(*[_scrape_one(a) for a in assignments], return_exceptions=True)
            logger.info(f"refresh-stats : campagne {campaign_id} rescrapee ({len(assignments)} comptes)")
        except Exception as e:
            logger.error(f"refresh-stats background error: {e}")

    asyncio.create_task(_scrape_campaign_now())

    accounts_count = await db.campaign_social_accounts.count_documents({"campaign_id": campaign_id})
    return {
        "ok": True,
        "message": f"Refresh lance : {accounts_count} comptes en cours de scraping (1-3 min).",
        "accounts_count": accounts_count,
    }


@api_router.post("/campaigns/{campaign_id}/force-scrape")
async def force_scrape_campaign(campaign_id: str, user: dict = Depends(get_current_user)):
    """Force le scraping immédiat de TOUS les comptes d'une campagne.
    Réservé ADMIN uniquement (les agences ne peuvent pas forcer le scrape, ça se fait sur les horaires fixes).
    Auto-cleanup d'abord les usernames sales (URLs) puis attend 30s pour re-vérification."""
    if user.get("role") != "admin":
        raise HTTPException(status_code=403, detail="Réservé à l'admin. Le scraping se fait automatiquement sur horaires fixes.")

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    # Auto-cleanup : si des comptes ont des usernames sales, on les nettoie d'abord
    pre_assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).to_list(500)
    pre_account_ids = [a["account_id"] for a in pre_assignments]
    cleanup_res = await _cleanup_dirty_usernames({"account_id": {"$in": pre_account_ids}})
    if cleanup_res["fixed"] > 0:
        logger.info(f"force-scrape: nettoyé {cleanup_res['fixed']} usernames sales avant scrape, attente 30s pour re-vérification")
        await asyncio.sleep(30)  # laisse la vérification se faire

    # Calcule cutoff = tracking_start_date sinon assigned_at par compte
    campaign_tracking_start = _parse_utc(campaign.get("tracking_start_date"))
    days_back = 30
    if campaign_tracking_start:
        days_back = max(2, int((datetime.now(timezone.utc) - campaign_tracking_start).total_seconds() / 86400) + 2)
        days_back = min(days_back, 365)

    assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).to_list(500)
    if not assignments:
        return {"ok": True, "message": "Aucun compte assigné à cette campagne", "results": []}

    # Lance les scrapes en parallèle (max 5 concurrents)
    semaphore = asyncio.Semaphore(5)

    async def _scrape_with_semaphore(assignment):
        async with semaphore:
            acc_id = assignment.get("account_id")
            account = await db.social_accounts.find_one({"account_id": acc_id}, {"_id": 0})
            if not account:
                return {"ok": False, "error": "compte DB introuvable", "username": "?", "platform": "?"}
            cutoff = campaign_tracking_start or _parse_utc(assignment.get("assigned_at")) or datetime.now(timezone.utc) - timedelta(days=30)
            return await _scrape_one_account_into_campaign(
                account, campaign, cutoff, since_days=days_back, wait_verification=False
            )

    results = await asyncio.gather(*[_scrape_with_semaphore(a) for a in assignments], return_exceptions=True)
    final_results = []
    total_inserted = 0
    total_fetched = 0
    total_skipped = 0
    total_errors = 0
    total_warnings = 0
    for r in results:
        if isinstance(r, Exception):
            final_results.append({"ok": False, "error": str(r)[:300], "username": "?", "platform": "?"})
            total_errors += 1
        else:
            final_results.append(r)
            if r.get("ok"):
                total_inserted += r.get("inserted", 0)
                total_fetched += r.get("fetched", 0)
                total_skipped += r.get("skipped_pre_cutoff", 0)
                if r.get("warning"):
                    total_warnings += 1
            else:
                total_errors += 1

    # Marque la campagne avec last_force_scrape
    await db.campaigns.update_one(
        {"campaign_id": campaign_id},
        {"$set": {
            "last_force_scrape_at": datetime.now(timezone.utc).isoformat(),
            "last_force_scrape_by": user["user_id"],
        }}
    )

    # Calcule la date cutoff humaine pour le résumé
    cutoff_str = None
    if campaign_tracking_start:
        cutoff_str = campaign_tracking_start.astimezone(PARIS_TZ).strftime("%d/%m/%Y")

    return {
        "ok": True,
        "campaign_id": campaign_id,
        "accounts_scraped": len(assignments),
        "total_videos_fetched": total_fetched,
        "total_videos_inserted": total_inserted,
        "total_skipped_pre_cutoff": total_skipped,
        "total_errors": total_errors,
        "total_warnings": total_warnings,
        "since_days": days_back,
        "tracking_start_date_human": cutoff_str,
        "results": final_results,
    }


@api_router.get("/campaigns/{campaign_id}/scrape-status")
async def get_campaign_scrape_status(campaign_id: str, user: dict = Depends(get_current_user)):
    """Retourne le status de scraping de chaque compte (last_tracked_at, errors).
    Permet à l'agence de savoir où en est le scraping.

    Stats ALIGNEES avec la realite "live" :
    - Horaires selon le PLAN de l'agence (Business=8h30+15h30+23h30, sinon 23h30)
    - Comptes : seuls les non-deleted comptent
    - Vidéos : filtrees par tracking_start_date + accounts actifs (meme logique que views-chart)
    - Erreurs : uniquement comptes non-verified avec erreur (pas overlap avec verified)
    """
    if user.get("role") not in ("agency", "manager", "admin"):
        raise HTTPException(status_code=403, detail="Réservé à l'agence et au manager")

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).to_list(500)
    account_ids = [a["account_id"] for a in assignments]
    # FILTRE : on EXCLUT les comptes status=deleted (ne plus afficher dans le panel scraping)
    accounts = await db.social_accounts.find(
        {"account_id": {"$in": account_ids}, "status": {"$ne": "deleted"}},
        {"_id": 0, "account_id": 1, "platform": 1, "username": 1, "status": 1,
         "last_tracked_at": 1, "error_message": 1, "last_scrape_error": 1, "user_id": 1,
         "consecutive_failures": 1, "tracking_paused_until": 1}
    ).to_list(500)
    non_deleted_ids = [a["account_id"] for a in accounts]

    # Comptes des vidéos par account — ALIGNE avec la logique "live" (tracking_start + non-deleted)
    tracking_start = campaign.get("tracking_start_date") or campaign.get("created_at")
    pipeline_match: dict = {"campaign_id": campaign_id, "account_id": {"$in": non_deleted_ids}}
    if tracking_start:
        pipeline_match["published_at"] = {"$gte": tracking_start}
    pipeline = [
        {"$match": pipeline_match},
        {"$group": {"_id": "$account_id", "count": {"$sum": 1}, "total_views": {"$sum": "$views"}}},
    ]
    video_stats = await db.tracked_videos.aggregate(pipeline).to_list(500)
    stats_map = {s["_id"]: s for s in video_stats}

    enriched = []
    for acc in accounts:
        st = stats_map.get(acc["account_id"], {})
        enriched.append({
            **acc,
            "videos_tracked": st.get("count", 0),
            "total_views": st.get("total_views", 0),
        })

    # Determine les horaires selon le plan de l'agence (Business 3x/jour vs Starter/Pro 1x/jour)
    agency = await db.users.find_one(
        {"user_id": campaign.get("agency_id")},
        {"_id": 0}
    ) if campaign.get("agency_id") else None
    if agency:
        limits = _get_plan_limits(agency)
        tracking_per_day = limits.get("tracking_per_day", 1)
    else:
        tracking_per_day = 1
    schedule_for_plan = _get_schedule_for_plan(tracking_per_day)

    # Prochain scrape : utiliser le schedule du plan, pas le defaut global
    now_paris = datetime.now(timezone.utc).astimezone(PARIS_TZ)
    candidates = []
    for h, m in schedule_for_plan:
        cand = now_paris.replace(hour=h, minute=m, second=0, microsecond=0)
        if cand > now_paris:
            candidates.append(cand)
    tomorrow = now_paris + timedelta(days=1)
    for h, m in schedule_for_plan:
        cand = tomorrow.replace(hour=h, minute=m, second=0, microsecond=0)
        candidates.append(cand)
    next_scrape_local = min(candidates)
    next_scrape_utc = next_scrape_local.astimezone(timezone.utc)

    return {
        "campaign_id": campaign_id,
        "tracking_start_date": tracking_start,
        "last_force_scrape_at": campaign.get("last_force_scrape_at"),
        "next_auto_scrape_paris": next_scrape_local.strftime("%H:%M"),
        "next_auto_scrape_utc": next_scrape_utc.isoformat(),
        "scrape_schedule_paris": [f"{h:02d}:{m:02d}" for h, m in schedule_for_plan],
        "tracking_per_day": tracking_per_day,
        "accounts": enriched,
    }

