@api_router.post("/social-accounts/{account_id}/add-video")
async def add_video_manually(account_id: str, request: Request, user: dict = Depends(get_current_user)):
    """
    Clipper manually adds a video URL (TikTok, YouTube, or Instagram).
    Fetches real stats and saves to tracked_videos for all campaigns where this account is assigned.
    """
    body = await request.json()
    video_url = (body.get("video_url") or "").strip()
    if not video_url:
        raise HTTPException(status_code=400, detail="URL de vidéo manquante")

    account = await db.social_accounts.find_one(
        {"account_id": account_id, "user_id": user["user_id"]}, {"_id": 0}
    )
    if not account:
        raise HTTPException(status_code=404, detail="Compte introuvable")

    platform = account.get("platform", "")
    url_lower = video_url.lower()

    # Validate that URL matches the account platform
    url_valid = (
        (platform == "tiktok" and "tiktok.com" in url_lower) or
        (platform == "youtube" and ("youtube.com" in url_lower or "youtu.be" in url_lower)) or
        (platform == "instagram" and "instagram.com" in url_lower)
    )
    if not url_valid:
        examples = {
            "tiktok": "https://www.tiktok.com/@user/video/123",
            "youtube": "https://www.youtube.com/watch?v=XXXXX ou https://youtu.be/XXXXX",
            "instagram": "https://www.instagram.com/reel/XXXXX/",
        }
        raise HTTPException(
            status_code=400,
            detail=f"URL {platform} invalide. Exemple : {examples.get(platform, 'URL valide')}"
        )

    # Fetch stats based on platform — always succeeds (fallback to 0 views if API fails)
    stats_partial = False
    try:
        if platform == "tiktok":
            try:
                vid_data = await asyncio.wait_for(
                    _fetch_tiktok_single_video_tikwm(video_url), timeout=15
                )
            except Exception:
                vid_data = None
            if vid_data:
                # Validate video belongs to this account if we could identify the author
                vid_author = (vid_data.get("_author_username") or "").lower()
                account_username = account.get("username", "").lower().lstrip("@")
                if vid_author and account_username and vid_author != account_username:
                    raise HTTPException(
                        status_code=400,
                        detail=f"Cette vidéo appartient à @{vid_author}, pas à @{account_username}. Ajoutez uniquement vos propres vidéos."
                    )
            else:
                # TikWm failed — extract video ID from URL and save with 0 views
                m = re.search(r'/video/(\d+)', video_url)
                video_id = m.group(1) if m else f"tk_{uuid.uuid4().hex[:8]}"
                vid_data = {
                    "platform_video_id": video_id,
                    "url": video_url,
                    "title": None,
                    "thumbnail_url": None,
                    "views": 0, "likes": 0, "comments": 0, "published_at": None,
                }
                stats_partial = True
        elif platform == "youtube":
            try:
                vid_data = await asyncio.wait_for(
                    _fetch_single_youtube_video(video_url), timeout=15
                )
            except Exception:
                m = re.search(r'(?:v=|vi=|youtu\.be/|/shorts/|/embed/|/v/|/live/)([a-zA-Z0-9_-]{11})', video_url)
                video_id = m.group(1) if m else f"yt_{uuid.uuid4().hex[:8]}"
                vid_data = {
                    "platform_video_id": video_id,
                    "url": video_url,
                    "title": None,
                    "thumbnail_url": f"https://img.youtube.com/vi/{video_id}/mqdefault.jpg" if m else None,
                    "views": 0, "likes": 0, "comments": 0, "published_at": None,
                }
                stats_partial = True
        elif platform == "instagram":
            try:
                # 120s pour Apify Reel Scraper (peut prendre 30-90s)
                vid_data = await asyncio.wait_for(
                    _fetch_single_instagram_video(video_url), timeout=120
                )
            except Exception:
                m = re.search(r'/(?:p|reel|reels)/([A-Za-z0-9_-]+)', video_url)
                video_id = m.group(1) if m else f"ig_{uuid.uuid4().hex[:8]}"
                vid_data = {
                    "platform_video_id": video_id,
                    "url": video_url,
                    "title": None,
                    "thumbnail_url": None,
                    "views": 0, "likes": 0, "comments": 0, "published_at": None,
                }
                stats_partial = True
        else:
            raise HTTPException(status_code=400, detail=f"Plateforme non supportée : {platform}")
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))

    # Find all campaigns where this account is assigned
    assignments = await db.campaign_social_accounts.find(
        {"account_id": account_id}, {"_id": 0}
    ).to_list(100)

    now_iso = datetime.now(timezone.utc).isoformat()
    saved_count = 0
    for assignment in assignments:
        campaign_id = assignment["campaign_id"]
        campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
        rpm = (campaign or {}).get("rpm", 0)
        earnings = (vid_data["views"] / 1000) * rpm

        set_fields = {
            "platform_video_id": vid_data["platform_video_id"],
            "account_id": account_id,
            "user_id": user["user_id"],
            "campaign_id": campaign_id,
            "platform": platform,
            "url": vid_data["url"],
            "title": vid_data.get("title"),
            "thumbnail_url": vid_data.get("thumbnail_url"),
            "views": vid_data["views"],
            "likes": vid_data.get("likes", 0),
            "comments": vid_data.get("comments", 0),
            "published_at": vid_data.get("published_at"),
            "fetched_at": now_iso,
            "earnings": round(earnings, 4),
            "manually_added": True,
            "simulated": False,
        }
        try:
            await db.tracked_videos.update_one(
                {"account_id": account_id, "platform_video_id": vid_data["platform_video_id"]},
                {"$set": set_fields,
                 "$setOnInsert": {"video_id": f"vid_{uuid.uuid4().hex[:12]}", "created_at": now_iso}},
                upsert=True,
            )
            saved_count += 1
        except Exception as e:
            logger.warning(f"Failed to upsert manually added video {vid_data['platform_video_id']}: {e}")

    if saved_count == 0:
        # No campaign assigned — save linked to account only
        fallback_fields = {
            "platform_video_id": vid_data["platform_video_id"],
            "account_id": account_id,
            "user_id": user["user_id"],
            "campaign_id": None,
            "platform": platform,
            "url": vid_data["url"],
            "title": vid_data.get("title"),
            "thumbnail_url": vid_data.get("thumbnail_url"),
            "views": vid_data["views"],
            "likes": vid_data.get("likes", 0),
            "comments": vid_data.get("comments", 0),
            "published_at": vid_data.get("published_at"),
            "fetched_at": now_iso,
            "earnings": 0,
            "manually_added": True,
            "simulated": False,
        }
        await db.tracked_videos.update_one(
            {"account_id": account_id, "platform_video_id": vid_data["platform_video_id"]},
            {"$set": fallback_fields,
             "$setOnInsert": {"video_id": f"vid_{uuid.uuid4().hex[:12]}", "created_at": now_iso}},
            upsert=True,
        )

    if vid_data["views"] > 0:
        views_str = f"{vid_data['views']:,}"
        msg = f"Vidéo ajoutée ✓ ({views_str} vues)"
    elif stats_partial:
        msg = "Vidéo ajoutée ✓ — stats non disponibles pour l'instant (seront mises à jour au prochain tracking)"
    else:
        msg = "Vidéo ajoutée ✓ (0 vues — mise à jour au prochain tracking)"
    return {
        "message": msg,
        "video": {
            "url": vid_data["url"],
            "title": vid_data.get("title"),
            "views": vid_data["views"],
            "likes": vid_data.get("likes", 0),
            "thumbnail_url": vid_data.get("thumbnail_url"),
        }
    }


# Endpoint /monthly-earnings retire (calcul estimatif par distribution lineaire,
# donc supprime conformement a la regle 'jamais de donnees inventees').
# Le frontend qui l'utilisait a ete retire dans le commit 899bb96.

@api_router.get("/campaigns/{campaign_id}/period-stats")
async def get_campaign_period_stats(
    campaign_id: str,
    period: str = "30d",
    offset: int = 0,
    user: dict = Depends(get_current_user)
):
    """Aggregate views + earnings + clicks for a campaign over a time window.

    period : "24h" | "7d" | "30d" | "year" | "all"
    offset : 0 = current period, 1 = previous period of same length, etc.
    Returns: views/earnings/clicks for the window, plus period bounds for UI.
    """
    from datetime import timedelta

    PERIOD_DAYS = {"24h": 1, "7d": 7, "30d": 30, "year": 365}
    if period not in PERIOD_DAYS and period != "all":
        raise HTTPException(status_code=400, detail="period invalide (24h|7d|30d|year|all)")

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    end = datetime.now(timezone.utc)
    if period == "all":
        start = datetime(2020, 1, 1, tzinfo=timezone.utc)
        period_label = "Depuis toujours"
    else:
        days = PERIOD_DAYS[period]
        # offset shifts window backwards (offset=1 = previous period)
        end = end - timedelta(days=days * offset)
        start = end - timedelta(days=days)
        period_label = {"24h": "24 dernières heures", "7d": "7 derniers jours",
                        "30d": "30 derniers jours", "year": "Cette année"}[period]

    # ── Views = vues GAGNEES dans la periode (delta snapshots) ──
    # Calcul HONNETE : views_in_period = total_au_jour_end - total_au_jour_start
    # Si pas de snapshots, on retourne 0 (pas d'invention).
    if period == "all":
        # Total cumule (toutes les vues actuelles de la campagne)
        agg_total = await db.tracked_videos.aggregate([
            {"$match": {"campaign_id": campaign_id}},
            {"$group": {"_id": None, "views": {"$sum": "$views"}, "videos": {"$sum": 1}}},
        ]).to_list(1)
        views_in_period = int(agg_total[0]["views"]) if agg_total else 0
        videos_in_period = int(agg_total[0]["videos"]) if agg_total else 0
    else:
        # Snapshots quotidiens — delta entre debut et fin de periode
        start_date_str = start.strftime("%Y-%m-%d")
        end_date_str = end.strftime("%Y-%m-%d")
        # Snapshot le plus recent <= end
        snap_end_doc = await db.views_snapshots.find_one(
            {"campaign_id": campaign_id, "date": {"$lte": end_date_str}},
            sort=[("date", -1)]
        )
        # Snapshot le plus recent < start (ie. juste avant le debut)
        snap_start_doc = await db.views_snapshots.find_one(
            {"campaign_id": campaign_id, "date": {"$lt": start_date_str}},
            sort=[("date", -1)]
        )
        end_total = int((snap_end_doc or {}).get("total_views") or 0)
        start_total = int((snap_start_doc or {}).get("total_views") or 0)
        views_in_period = max(0, end_total - start_total)

        # Videos publiees dans la periode (count reel)
        videos_in_period = await db.tracked_videos.count_documents({
            "campaign_id": campaign_id,
            "published_at": {"$ne": None},
        })

    # ── Earnings (depends on payment model) ──
    payment_model = campaign.get("payment_model", "views")
    rpm = campaign.get("rpm", 0) or 0
    rate_per_click = campaign.get("rate_per_click", 0) or 0

    earnings_in_period = 0.0
    clicks_in_period = 0
    unique_clicks_in_period = 0

    if payment_model in ("views", "both"):
        earnings_in_period += round((views_in_period / 1000) * rpm, 2)
    if payment_model in ("clicks", "both"):
        click_match = {
            "campaign_id": campaign_id,
            "clicked_at": {"$gte": start.isoformat(), "$lte": end.isoformat()},
        }
        clicks_in_period = await db.click_events.count_documents(click_match)
        unique_clicks_in_period = await db.click_events.count_documents({**click_match, "is_unique": True})
        billing_mode = campaign.get("click_billing_mode", "all")
        billable = unique_clicks_in_period if billing_mode != "all" else clicks_in_period
        earnings_in_period += round((billable / 1000) * rate_per_click, 2)
    earnings_in_period = round(earnings_in_period, 2)

    return {
        "period": period,
        "period_label": period_label,
        "offset": offset,
        "period_start": start.isoformat(),
        "period_end": end.isoformat(),
        "views": views_in_period,
        "videos": videos_in_period,
        "earnings": earnings_in_period,
        "clicks": clicks_in_period,
        "unique_clicks": unique_clicks_in_period,
        "payment_model": payment_model,
        "rpm": rpm,
        "rate_per_click": rate_per_click,
        "budget_unlimited": campaign.get("budget_unlimited", False),
    }


@api_router.get("/campaigns/{campaign_id}/my-period-stats")
async def get_my_period_stats(
    campaign_id: str,
    period: str = "30d",
    offset: int = 0,
    user: dict = Depends(get_current_user)
):
    """Per-clipper aggregate views + earnings + clicks over a time window.
    Same shape as /period-stats but filtered to the current authenticated user.
    """
    from datetime import timedelta

    PERIOD_DAYS = {"24h": 1, "7d": 7, "30d": 30, "year": 365}
    if period not in PERIOD_DAYS and period != "all":
        raise HTTPException(status_code=400, detail="period invalide (24h|7d|30d|year|all)")

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    user_id = user["user_id"]
    end = datetime.now(timezone.utc)
    if period == "all":
        start = datetime(2020, 1, 1, tzinfo=timezone.utc)
        period_label = "Depuis toujours"
    else:
        days = PERIOD_DAYS[period]
        end = end - timedelta(days=days * offset)
        start = end - timedelta(days=days)
        period_label = {"24h": "24 dernières heures", "7d": "7 derniers jours",
                        "30d": "30 derniers jours", "year": "Cette année"}[period]

    # ── Views = somme des vues actuelles des vidéos PUBLIEES par ce clipper dans la période ──
    views_match = {
        "campaign_id": campaign_id,
        "user_id": user_id,
        "published_at": {"$ne": None},
    }
    pipeline = [
        {"$match": views_match},
        {"$addFields": {
            "_pub_dt": {"$cond": [
                {"$eq": [{"$type": "$published_at"}, "string"]},
                {"$dateFromString": {"dateString": "$published_at", "onError": None}},
                "$published_at",
            ]}
        }},
        {"$match": {"_pub_dt": {"$gte": start, "$lte": end}}} if period != "all" else {"$match": {}},
        {"$group": {"_id": None, "views": {"$sum": "$views"}, "videos": {"$sum": 1}}},
    ]
    agg_res = await db.tracked_videos.aggregate(pipeline).to_list(1)
    views_in_period = int(agg_res[0]["views"]) if agg_res else 0
    videos_in_period = int(agg_res[0]["videos"]) if agg_res else 0

    payment_model = campaign.get("payment_model", "views")
    rpm = campaign.get("rpm", 0) or 0
    rate_per_click = campaign.get("rate_per_click", 0) or 0

    earnings_in_period = 0.0
    clicks_in_period = 0
    unique_clicks_in_period = 0

    if payment_model in ("views", "both"):
        earnings_in_period += round((views_in_period / 1000) * rpm, 2)
    if payment_model in ("clicks", "both"):
        my_links = await db.click_links.find(
            {"campaign_id": campaign_id, "clipper_id": user_id},
            {"_id": 0, "link_id": 1}
        ).to_list(50)
        link_ids = [l["link_id"] for l in my_links]
        if link_ids:
            click_match = {
                "link_id": {"$in": link_ids},
                "clicked_at": {"$gte": start.isoformat(), "$lte": end.isoformat()},
            }
            clicks_in_period = await db.click_events.count_documents(click_match)
            unique_clicks_in_period = await db.click_events.count_documents({**click_match, "is_unique": True})
        billing_mode = campaign.get("click_billing_mode", "all")
        billable = unique_clicks_in_period if billing_mode != "all" else clicks_in_period
        earnings_in_period += round((billable / 1000) * rate_per_click, 2)
    earnings_in_period = round(earnings_in_period, 2)

    return {
        "period": period,
        "period_label": period_label,
        "offset": offset,
        "period_start": start.isoformat(),
        "period_end": end.isoformat(),
        "views": views_in_period,
        "earnings": earnings_in_period,
        "clicks": clicks_in_period,
        "unique_clicks": unique_clicks_in_period,
        "payment_model": payment_model,
        "rpm": rpm,
        "rate_per_click": rate_per_click,
        "budget_unlimited": campaign.get("budget_unlimited", False),
    }


def _compute_chart_window(days: int, offset: int = 0):
    """Calcule (start, end) pour une fenetre de `days` jours, decalee de `offset` periodes en arriere.
    offset=0 = periode courante, offset=1 = periode precedente, etc."""
    from datetime import timedelta
    end = datetime.now(timezone.utc) - timedelta(days=days * offset)
    start = end - timedelta(days=days)
    return start, end


def _hourly_chart_from_snapshots(snapshots, start, end, prev_total):
    """Construit la timeline horaire a partir des snapshots tries chronologiquement.
    Retourne liste de points avec label HH:MM (Paris) ou jour si on dépasse 1j."""
    span_days = (end - start).total_seconds() / 86400
    timeline = []
    running = prev_total
    for s in snapshots:
        cur = s["total_views"]
        delta = max(0, cur - running)
        # Label : si on est sur 1 jour -> "HH:MM", sinon "JJ/MM HH:MM"
        if span_days <= 1.5:
            label = f"{s.get('hour', 0):02d}:{s.get('minute', 0):02d}"
        else:
            try:
                dt_paris = datetime.fromisoformat(s["scraped_at_paris"].replace("Z", "+00:00")) if s.get("scraped_at_paris") else None
                if dt_paris:
                    label = dt_paris.strftime("%d/%m %Hh")
                else:
                    label = f"{s.get('hour', 0):02d}h"
            except Exception:
                label = f"{s.get('hour', 0):02d}h"
        timeline.append({
            "date": s["scraped_at"],
            "label": label,
            "views": delta,
            "total_views": cur,
        })
        running = cur
    return timeline


@api_router.get("/campaigns/{campaign_id}/kpi-stats")
async def get_campaign_kpi_stats(
    campaign_id: str,
    days: int = 7,
    offset: int = 0,
    user: dict = Depends(get_current_user)
):
    """🎯 KPI stats SYNCHRONISEES avec la courbe + ANTI-FANTOMES.

    Calcule les 6 KPI sur la periode :
    - views : delta total_views (vues GAGNEES sur la periode)
    - likes / comments : delta sur la periode
    - engagement_pct : (likes + comments) / views x 100
    - active_videos_count : nb videos VRAIMENT trackees (account assigne + apres tracking_start)
    - avg_views_per_video : views / active_videos_count
    - earnings : views / 1000 x rpm

    Calcul LIVE (pas via snapshots historiques potentiellement gonfles) :
    - total END = aggregate live sur tracked_videos AVEC filtres :
      * account_id encore assigne (anti-fantomes)
      * published_at >= tracking_start_date (anti-vieilles-videos)
    - total START = snapshot le plus ancien dispo, MAIS borne par total END (max=END)
      pour eviter delta negatif quand les snapshots passes etaient gonfles.
    - Si pas de snapshot avant : assume 0 -> delta = total live (campagne neuve).
    """
    from datetime import timedelta
    start, end = _compute_chart_window(days, offset)

    # 1. Lookup campagne + filtres anti-fantomes/anti-vieilles
    campaign = await db.campaigns.find_one(
        {"campaign_id": campaign_id},
        {"_id": 0, "rpm": 1, "tracking_start_date": 1, "created_at": 1}
    )
    if not campaign:
        return {
            "period_start": start.isoformat(), "period_end": end.isoformat(),
            "days": days, "offset": offset,
            "views": 0, "likes": 0, "comments": 0, "engagement_pct": 0.0,
            "active_videos_count": 0, "avg_views_per_video": 0, "earnings": 0.0,
            "note": "Campagne introuvable",
        }
    rpm = float(campaign.get("rpm") or 0)
    tracking_start = campaign.get("tracking_start_date") or campaign.get("created_at")

    # 2. Recupere les account_ids ENCORE assignes (anti-fantomes)
    active_assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0, "account_id": 1}
    ).to_list(2000)
    active_account_ids = [a["account_id"] for a in active_assignments if a.get("account_id")]

    if not active_account_ids:
        return {
            "period_start": start.isoformat(), "period_end": end.isoformat(),
            "days": days, "offset": offset,
            "views": 0, "likes": 0, "comments": 0, "engagement_pct": 0.0,
            "active_videos_count": 0, "avg_views_per_video": 0, "earnings": 0.0,
            "note": "Aucun compte assigne a la campagne",
        }

    # 3. Calcul LIVE du total END (= valeurs actuelles filtrees correctement)
    live_match: dict = {
        "campaign_id": campaign_id,
        "account_id": {"$in": active_account_ids},
    }
    if tracking_start:
        live_match["published_at"] = {"$gte": tracking_start}

    live_agg = await db.tracked_videos.aggregate([
        {"$match": live_match},
        {"$group": {
            "_id": None,
            "total_views": {"$sum": "$views"},
            "total_likes": {"$sum": "$likes"},
            "total_comments": {"$sum": "$comments"},
            "video_count": {"$sum": 1},
        }}
    ]).to_list(1)
    end_views = int(live_agg[0]["total_views"]) if live_agg else 0
    end_likes = int(live_agg[0]["total_likes"]) if live_agg else 0
    end_comments = int(live_agg[0]["total_comments"]) if live_agg else 0
    total_videos = int(live_agg[0]["video_count"]) if live_agg else 0

    # 4. Calcul START via snapshot (le plus recent AVANT start de la fenetre)
    # Borne : start_views ne peut pas etre superieur a end_views (anti-snapshot-gonfle)
    start_views = 0
    start_likes = 0
    start_comments = 0

    start_date_str = start.strftime("%Y-%m-%d")
    start_snap = await db.views_snapshots.find_one(
        {"campaign_id": campaign_id, "date": {"$lt": start_date_str}},
        {"_id": 0, "total_views": 1, "total_likes": 1, "total_comments": 1},
        sort=[("date", -1)]
    )
    if start_snap:
        # Borne par END pour eviter delta negatif (anti-snapshot-historique-gonfle)
        start_views = min(int(start_snap.get("total_views") or 0), end_views)
        start_likes = min(int(start_snap.get("total_likes") or 0), end_likes)
        start_comments = min(int(start_snap.get("total_comments") or 0), end_comments)

    period_views = max(0, end_views - start_views)
    period_likes = max(0, end_likes - start_likes)
    period_comments = max(0, end_comments - start_comments)

    # 5. Compte videos actives (non archivees) pour la moyenne
    active_videos_count = await db.tracked_videos.count_documents({
        **live_match,
        "tracking_active": {"$ne": False},
    })

    engagement_pct = round(((period_likes + period_comments) / period_views * 100), 1) if period_views > 0 else 0.0
    avg_views = int(period_views / active_videos_count) if active_videos_count > 0 else 0
    earnings = round((period_views / 1000) * rpm, 2)

    return {
        "period_start": start.isoformat(),
        "period_end": end.isoformat(),
        "days": days,
        "offset": offset,
        "views": period_views,
        "likes": period_likes,
        "comments": period_comments,
        "engagement_pct": engagement_pct,
        "active_videos_count": active_videos_count,
        "total_videos_in_period": total_videos,
        "avg_views_per_video": avg_views,
        "earnings": earnings,
        "source": "live_aggregate_filtered",
        "note": "Calcul live avec filtres anti-fantomes (compte assigne + published_at >= tracking_start). Synchronise avec /tracked-videos.",
    }


@api_router.post("/campaigns/{campaign_id}/recompute-stats")
async def recompute_campaign_stats(campaign_id: str, user: dict = Depends(get_current_user)):
    """Recalcule les snapshots quotidiens de la campagne a partir de
    video_views_snapshots (source de verite par video par jour).

    Corrige les chiffres historiques incoherents (ex: 'hier' qui change
    d'un jour a l'autre apres deletions de comptes).

    Reserve a l'agence proprietaire ou au manager de la campagne.
    Pas d'admin code requis, c'est une action sur SES donnees.
    """
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    role = user.get("role")
    if role not in ("agency", "manager"):
        raise HTTPException(status_code=403, detail="Agence ou manager uniquement")
    if role == "agency" and campaign.get("agency_id") != user.get("user_id"):
        raise HTTPException(status_code=403, detail="Cette campagne n'est pas la votre")

    # Agrege video_views_snapshots par date pour cette campagne
    agg = await db.video_views_snapshots.aggregate([
        {"$match": {"campaign_id": campaign_id}},
        {"$group": {
            "_id": "$date",
            "total_views": {"$sum": "$views"},
            "total_likes": {"$sum": "$likes"},
            "total_comments": {"$sum": "$comments"},
            "n_videos": {"$sum": 1},
        }},
        {"$sort": {"_id": 1}},
    ]).to_list(2000)

    now_iso = datetime.now(timezone.utc).isoformat()
    recomputed = 0
    unchanged = 0
    changes = []

    for daily in agg:
        date_str = daily["_id"]
        if not date_str:
            continue
        new_total = int(daily.get("total_views") or 0)
        new_likes = int(daily.get("total_likes") or 0)
        new_comments = int(daily.get("total_comments") or 0)
        new_videos = int(daily.get("n_videos") or 0)

        existing = await db.views_snapshots.find_one(
            {"campaign_id": campaign_id, "date": date_str},
            {"_id": 0, "total_views": 1}
        )
        old_total = int((existing or {}).get("total_views") or 0)

        if old_total == new_total:
            unchanged += 1
            continue

        recomputed += 1
        changes.append({
            "date": date_str,
            "old_views": old_total,
            "new_views": new_total,
            "diff": new_total - old_total,
        })
        await db.views_snapshots.update_one(
            {"campaign_id": campaign_id, "date": date_str},
            {"$set": {
                "campaign_id": campaign_id,
                "date": date_str,
                "total_views": new_total,
                "total_likes": new_likes,
                "total_comments": new_comments,
                "total_videos": new_videos,
                "recomputed_at": now_iso,
                "recomputed_source": "video_views_snapshots",
            }},
            upsert=True,
        )

    logger.info(f"Recompute campaign {campaign_id} by {user.get('user_id')}: {recomputed} dates updated, {unchanged} unchanged")
    return {
        "ok": True,
        "campaign_id": campaign_id,
        "dates_recomputed": recomputed,
        "dates_unchanged": unchanged,
        "changes": changes[:30],
        "message": (
            f"{recomputed} snapshot(s) recalcule(s), {unchanged} inchange(s). "
            f"La courbe affiche maintenant les vraies valeurs historiques."
            if recomputed > 0 else
            "Aucun changement : les snapshots etaient deja a jour."
        ),
    }


@api_router.get("/campaigns/{campaign_id}/views-chart")
async def get_campaign_views_chart(
    campaign_id: str,
    days: int = 30,
    offset: int = 0,
    user: dict = Depends(get_current_user)
):
    """
    Graphique des vues GAGNEES par jour, base UNIQUEMENT sur les snapshots quotidiens
    reels (views_snapshots). Pas d'invention : si pas de snapshot pour un jour, la
    valeur est 0 (donc avant que le tracking soit en place, courbe a plat = honnete).

    GRANULARITE HORAIRE (plan Business 2 scrapes/jour) :
    Si days=1 ET la campagne a 2 scrapes/jour -> on retourne les snapshots
    HORAIRES (8h00 + 20h00 Paris) au lieu de daily. Comme ca la courbe 24h
    montre 2 points reels = ce qui a ete collecte a chaque scrape de la journee.
    """
    from datetime import timedelta
    start, end = _compute_chart_window(days, offset)
    start_str = start.strftime("%Y-%m-%d")
    end_str = end.strftime("%Y-%m-%d")

    # ── GRANULARITE HORAIRE pour Business 24h ──
    # Si days=1 et la campagne a >= 2 scrapes/jour, on retourne les snapshots horaires.
    if days == 1:
        # Lookup le plan agence pour savoir si elle a 2 scrapes/jour
        campaign_doc_chk = await db.campaigns.find_one(
            {"campaign_id": campaign_id},
            {"_id": 0, "agency_id": 1, "_scrape_interval_h": 1, "tracking_start_date": 1, "created_at": 1}
        )
        if campaign_doc_chk:
            interval_h = int((campaign_doc_chk or {}).get("_scrape_interval_h") or 24)
            # Business plan = 2 scrapes/jour = interval 12h. Si interval <= 12h on est en mode multi-scrape
            if interval_h <= 12:
                # Retourne les snapshots horaires des dernieres 24h
                hourly_snaps = await db.views_snapshots_hourly.find(
                    {"campaign_id": campaign_id, "scraped_at": {"$gte": start.isoformat(), "$lte": end.isoformat()}},
                    {"_id": 0}
                ).sort("scraped_at", 1).to_list(50)
                if hourly_snaps:
                    # Recupere le snapshot HORAIRE le plus recent AVANT start (pour le 1er delta)
                    prev_snap = await db.views_snapshots_hourly.find_one(
                        {"campaign_id": campaign_id, "scraped_at": {"$lt": start.isoformat()}},
                        {"_id": 0, "total_views": 1},
                        sort=[("scraped_at", -1)]
                    )
                    prev_total = int((prev_snap or {}).get("total_views") or 0)
                    # ── SNAPSHOTS IMMUTABLES ──
                    # On garde les valeurs ENREGISTREES a l'epoque (immuables).
                    # Seul le DERNIER snapshot (le plus recent) est replace par le live actuel
                    # pour refleter la valeur exacte au moment de la lecture.
                    tracking_start_h = campaign_doc_chk.get("tracking_start_date") or campaign_doc_chk.get("created_at")
                    active_assignments_h = await db.campaign_social_accounts.find(
                        {"campaign_id": campaign_id}, {"_id": 0, "account_id": 1}
                    ).to_list(2000)
                    active_account_ids_h = [a["account_id"] for a in active_assignments_h if a.get("account_id")]
                    live_total_h = 0
                    if active_account_ids_h:
                        live_match_h: dict = {"campaign_id": campaign_id, "account_id": {"$in": active_account_ids_h}}
                        if tracking_start_h:
                            live_match_h["published_at"] = {"$gte": tracking_start_h}
                        live_agg_h = await db.tracked_videos.aggregate([
                            {"$match": live_match_h},
                            {"$group": {"_id": None, "total_views": {"$sum": "$views"}}}
                        ]).to_list(1)
                        live_total_h = int(live_agg_h[0]["total_views"]) if live_agg_h else 0
                    # SEUL le dernier snapshot (= le plus recent = maintenant) est replace par live.
                    # Les anciens snapshots restent intacts (pas de plafonnement retroactif).
                    if live_total_h > 0 and hourly_snaps:
                        last_raw = int(hourly_snaps[-1].get("total_views") or 0)
                        hourly_snaps[-1]["total_views"] = max(live_total_h, last_raw)
                    timeline = _hourly_chart_from_snapshots(hourly_snaps, start, end, prev_total)
                    return {
                        "timeline": timeline,
                        "source": "hourly_snapshots_delta_immutable",
                        "granularity": "hourly",
                        "period_start": start.isoformat(),
                        "period_end": end.isoformat(),
                        "offset": offset,
                        "days": days,
                        "note": "Plan Business : 3 scrapes/jour. Snapshots horaires passes immutables.",
                    }

    # ── CALCUL LIVE du total_views ACTUEL (filtre anti-fantomes + anti-vieilles) ──
    # Sert de BORNE pour les snapshots passes potentiellement gonfles.
    # Si un snapshot ancien = 3M vues mais le total live filtre = 10k, on plafonne
    # le snapshot a 10k (-> delta correct au lieu de chiffres aberrants).
    campaign_doc = await db.campaigns.find_one(
        {"campaign_id": campaign_id},
        {"_id": 0, "tracking_start_date": 1, "created_at": 1}
    )
    tracking_start = (campaign_doc or {}).get("tracking_start_date") or (campaign_doc or {}).get("created_at")

    active_assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0, "account_id": 1}
    ).to_list(2000)
    active_account_ids = [a["account_id"] for a in active_assignments if a.get("account_id")]

    live_total_views = 0
    if active_account_ids:
        live_match: dict = {"campaign_id": campaign_id, "account_id": {"$in": active_account_ids}}
        if tracking_start:
            live_match["published_at"] = {"$gte": tracking_start}
        live_agg = await db.tracked_videos.aggregate([
            {"$match": live_match},
            {"$group": {"_id": None, "total_views": {"$sum": "$views"}}}
        ]).to_list(1)
        live_total_views = int(live_agg[0]["total_views"]) if live_agg else 0

    # Recupere TOUS les snapshots quotidiens (pour avoir le J-1 du 1er jour)
    snapshots = await db.views_snapshots.find(
        {"campaign_id": campaign_id},
        {"_id": 0, "date": 1, "total_views": 1}
    ).sort("date", 1).to_list(2000)

    # Construit map date -> total_views.
    # PRINCIPE (apres bug 2026-05-13) : snapshots historiques = IMMUTABLES.
    # On ne les plafonne PAS par live_total_views car ca fait varier les chiffres
    # passes quand des comptes sont deletes (ex: la valeur d'hier change aujourd'hui).
    # Seul le snapshot d'AUJOURD'HUI est remplace par live_total_views (= valeur
    # la plus precise au moment de la lecture).
    snap_by_date = {}
    today_str = _today_paris_str()
    for s in snapshots:
        if not s.get("date"):
            continue
        raw_total = int(s.get("total_views") or 0)
        if s["date"] == today_str:
            # Snapshot du jour : utilise live_total_views (precise) mais au minimum le snapshot
            # ecrit dans la journee (sinon on serait < a la valeur enregistree, ce qui ferait
            # des deltas negatifs / clip a 0 incorrects).
            snap_by_date[s["date"]] = max(live_total_views, raw_total)
        else:
            # Snapshots passes : INTOUCHABLES. Valeur exacte ecrite a l'epoque.
            snap_by_date[s["date"]] = raw_total

    # Si aucun snapshot aujourd'hui mais on a un total live > 0 : on l'ajoute
    if today_str not in snap_by_date and live_total_views > 0:
        snap_by_date[today_str] = live_total_views

    sorted_snap_dates = sorted(snap_by_date.keys())

    # Pour chaque jour : delta = today_total - prev_total. Si pas de prev -> 1er scrape, delta = total.
    timeline = []
    current = start
    while current <= end:
        day = current.strftime("%Y-%m-%d")
        if day in snap_by_date:
            today_total = snap_by_date[day]
            prev_total = 0
            for d in reversed(sorted_snap_dates):
                if d < day:
                    prev_total = snap_by_date[d]
                    break
            delta = max(0, today_total - prev_total)
        else:
            delta = 0
        timeline.append({"date": day, "views": int(delta)})
        current += timedelta(days=1)

    return {
        "timeline": timeline,
        "source": "daily_snapshots_delta_immutable",
        "granularity": "daily",
        "period_start": start.isoformat(),
        "period_end": end.isoformat(),
        "offset": offset,
        "days": days,
        "note": "Vues GAGNEES par jour. Snapshots passes immutables (ne bougent jamais). Aujourd'hui = live actuel.",
    }


@api_router.get("/campaigns/{campaign_id}/my-views-chart")
async def get_my_views_chart(
    campaign_id: str,
    days: int = 30,
    offset: int = 0,
    user: dict = Depends(get_current_user)
):
    """
    Vues du clippeur connecté avec meme logique que campaign chart (horaire 24h/7j/30j, daily 90j/1an).
    Vues GAGNEES par jour pour ce clippeur, basees UNIQUEMENT sur user_views_snapshots
    (delta total_views entre J et J-1). Pas d'invention : 0 si pas de snapshot.
    """
    from datetime import timedelta
    uid = user["user_id"]
    start, end = _compute_chart_window(days, offset)

    snapshots = await db.user_views_snapshots.find(
        {"campaign_id": campaign_id, "user_id": uid},
        {"_id": 0, "date": 1, "total_views": 1}
    ).sort("date", 1).to_list(2000)

    snap_by_date = {s["date"]: int(s.get("total_views") or 0) for s in snapshots if s.get("date")}
    sorted_snap_dates = sorted(snap_by_date.keys())

    timeline = []
    current = start
    while current <= end:
        day = current.strftime("%Y-%m-%d")
        if day in snap_by_date:
            today_total = snap_by_date[day]
            # Snapshot precedent le plus proche
            prev_total = 0
            for d in reversed(sorted_snap_dates):
                if d < day:
                    prev_total = snap_by_date[d]
                    break
            delta = max(0, today_total - prev_total)
        else:
            delta = 0
        timeline.append({"date": day, "views": int(delta)})
        current += timedelta(days=1)

    return {
        "timeline": timeline,
        "granularity": "daily",
        "source": "user_daily_snapshots_delta",
        "period_start": start.isoformat(),
        "period_end": end.isoformat(),
        "offset": offset,
        "days": days,
        "note": "Vues GAGNEES par jour (delta snapshots). 0 si pas de snapshot pour cette date.",
    }

@api_router.get("/campaigns/{campaign_id}/my-videos")
async def get_my_campaign_videos(campaign_id: str, user: dict = Depends(get_current_user)):
    """Clipper's own tracked videos for a specific campaign, sorted by views desc.
    ANTI-FANTOMES : filtre par account_id encore assigne (cas compte clippeur retire)
    ANTI-VIEILLES : filtre published_at >= tracking_start_date (vieilles videos avant campagne)
    """
    uid = user["user_id"]
    # Comptes assignes a cette campagne pour CE clippeur
    active_assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id, "user_id": uid},
        {"_id": 0, "account_id": 1}
    ).to_list(200)
    active_account_ids = [a["account_id"] for a in active_assignments if a.get("account_id")]
    if not active_account_ids:
        return {"videos": []}
    # tracking_start_date
    campaign = await db.campaigns.find_one(
        {"campaign_id": campaign_id},
        {"_id": 0, "tracking_start_date": 1, "created_at": 1}
    )
    tracking_start = (campaign or {}).get("tracking_start_date") or (campaign or {}).get("created_at")
    query: dict = {"campaign_id": campaign_id, "user_id": uid, "account_id": {"$in": active_account_ids}}
    if tracking_start:
        query["published_at"] = {"$gte": tracking_start}
    videos = await db.tracked_videos.find(query, {"_id": 0}).sort("views", -1).to_list(200)
    return {"videos": videos}

@api_router.get("/campaigns/{campaign_id}/top-clips")
async def get_campaign_top_clips(
    campaign_id: str,
    limit: int = 10,
    period: str = "all",   # "24h" | "7d" | "30d" | "all"
    user: dict = Depends(get_current_user)
):
    """Top N videos by views for this campaign — visible to all roles.
    period: filtre les vidéos par date de publication (depuis quand publiées).

    ANTI-FANTOMES : on ne retourne QUE les videos dont le compte est ENCORE assigne
    a la campagne. Sinon on affichait des videos orphelines (compte retire mais
    videos restees en DB avec le campaign_id), ce qui donnait l'impression de
    fausses donnees dans Clip Winner.

    ANTI-VIEILLES-VIDEOS : on ne retourne QUE les videos publiees APRES
    tracking_start_date (= date de creation de la campagne par defaut). Sinon
    une nouvelle campagne affichait les vieilles videos historiques du compte.
    """
    from datetime import timedelta
    PERIOD_DAYS = {"24h": 1, "7d": 7, "30d": 30}

    # ── ANTI-FANTOMES : recupere les account_ids ENCORE assignes a cette campagne
    active_assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0, "account_id": 1}
    ).to_list(2000)
    active_account_ids = [a["account_id"] for a in active_assignments if a.get("account_id")]
    if not active_account_ids:
        # Aucun compte assigne -> aucun clip a montrer (meme s'il reste des videos en DB)
        return {"clips": []}

    # ── ANTI-VIEILLES-VIDEOS : recupere tracking_start_date pour filtrer published_at
    campaign = await db.campaigns.find_one(
        {"campaign_id": campaign_id},
        {"_id": 0, "tracking_start_date": 1, "created_at": 1}
    )
    tracking_start = (campaign or {}).get("tracking_start_date") or (campaign or {}).get("created_at")

    query: dict = {
        "campaign_id": campaign_id,
        "views": {"$gt": 0},
        "account_id": {"$in": active_account_ids},
    }

    # Determine la borne basse de published_at : max(tracking_start, period cutoff)
    pub_cutoffs: list = []
    if tracking_start:
        pub_cutoffs.append(tracking_start)
    if period in PERIOD_DAYS:
        period_cutoff = (datetime.now(timezone.utc) - timedelta(days=PERIOD_DAYS[period])).isoformat()
        pub_cutoffs.append(period_cutoff)
    if pub_cutoffs:
        query["published_at"] = {"$gte": max(pub_cutoffs)}
    raw = await db.tracked_videos.find(
        query,
        {"_id": 0}
    ).sort("views", -1).to_list(limit)

    # Enrich with clipper info
    user_ids = list({v.get("user_id") for v in raw if v.get("user_id")})
    users_map: dict = {}
    if user_ids:
        clipper_docs = await db.users.find(
            {"user_id": {"$in": user_ids}},
            {"_id": 0, "user_id": 1, "display_name": 1, "name": 1, "picture": 1}
        ).to_list(len(user_ids))
        users_map = {u["user_id"]: u for u in clipper_docs}

    clips = []
    for i, vid in enumerate(raw):
        uid = vid.get("user_id")
        clipper = users_map.get(uid, {})
        clips.append({
            "rank": i + 1,
            "video_id": vid.get("video_id"),
            "url": vid.get("url"),
            "platform": vid.get("platform"),
            "title": vid.get("title"),
            "thumbnail_url": vid.get("thumbnail_url"),
            "views": vid.get("views", 0),
            "likes": vid.get("likes", 0),
            "comments": vid.get("comments", 0),
            "published_at": vid.get("published_at"),
            "earnings": vid.get("earnings", 0),
            "clipper_name": clipper.get("display_name") or clipper.get("name") or "Clippeur",
            "clipper_picture": clipper.get("picture"),
            "user_id": uid,
        })
    return {"clips": clips}

@api_router.get("/campaigns/{campaign_id}/tracked-videos")
async def get_campaign_tracked_videos(campaign_id: str, user: dict = Depends(get_current_user)):
    """All tracked videos for a campaign (agency view).
    ANTI-FANTOMES : ne retourne que les videos des comptes ENCORE assignes a la campagne.
    ANTI-VIEILLES-VIDEOS : ne retourne que les videos publiees APRES tracking_start_date.
    """
    active_assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0, "account_id": 1}
    ).to_list(2000)
    active_account_ids = [a["account_id"] for a in active_assignments if a.get("account_id")]
    if not active_account_ids:
        return {"videos": []}

    # Recupere tracking_start_date pour filtrer les vieilles videos
    campaign = await db.campaigns.find_one(
        {"campaign_id": campaign_id},
        {"_id": 0, "tracking_start_date": 1, "created_at": 1}
    )
    tracking_start = (campaign or {}).get("tracking_start_date") or (campaign or {}).get("created_at")

    query: dict = {"campaign_id": campaign_id, "account_id": {"$in": active_account_ids}}
    if tracking_start:
        query["published_at"] = {"$gte": tracking_start}

    videos = await db.tracked_videos.find(query, {"_id": 0}).sort("published_at", -1).to_list(500)
    return {"videos": videos}

@api_router.post("/campaigns/{campaign_id}/refresh-tracking")
async def force_campaign_tracking(campaign_id: str, user: dict = Depends(get_current_user)):
    """Force immediate tracking for a campaign"""
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager only")
    asyncio.create_task(run_video_tracking())
    return {"message": "Tracking lancé en arrière-plan"}

@api_router.post("/campaigns/{campaign_id}/import-link")
@api_router.post("/campaigns/{campaign_id}/list-account-videos")
async def list_account_videos(campaign_id: str, body: dict, user: dict = Depends(get_current_user)):
    """Scrape un compte (username + platform) avec la cascade COMPLETE (ClipScraper -> TikWm -> ...)
    et retourne ses dernieres videos pour que l'agence selectionne celles a tracker.
    """
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    raw_username = (body.get("username") or "").strip()
    platform = (body.get("platform") or "").lower().strip()

    if platform not in ("tiktok", "instagram", "youtube"):
        raise HTTPException(status_code=400, detail="platform invalide (tiktok/instagram/youtube)")

    # Nettoie le username (gere URL collee)
    if _looks_like_url_or_dirty(raw_username):
        username = extract_handle_from_url(raw_username, platform)
    else:
        username = raw_username
    username = (username or "").lstrip("@").strip("/")
    if not username:
        raise HTTPException(status_code=400, detail="username requis (sans @)")

    # Utilise la cascade complete via fetch_videos
    # Pour youtube, on a besoin d'un channel_id : on essaie de le verifier d'abord
    try:
        if platform == "youtube":
            # YouTube : besoin du channel_id pour fetch_videos
            yt_info = await _verify_youtube(username)
            channel_id = yt_info.get("platform_channel_id")
            if not channel_id:
                raise HTTPException(status_code=404, detail=f"Compte YouTube @{username} introuvable")
            account_doc = {"platform": "youtube", "username": username, "platform_channel_id": channel_id, "status": "verified"}
        else:
            # TikTok / Instagram : besoin du compte verifie pour avoir potentiellement le channel_id
            account_doc = {"platform": platform, "username": username, "status": "verified"}

        # Cascade complete
        videos = await fetch_videos(platform, username, account_doc, since_days=180)

        if not videos:
            # Construit message d'erreur AVEC diagnostic config (env vars manquantes)
            missing_config = []
            if platform == "instagram":
                if not BACKEND_PROXY_URL:
                    missing_config.append("BACKEND_PROXY_URL (proxy webshare)")
                if not CLIP_SCRAPER_URL or not CLIP_SCRAPER_KEY:
                    missing_config.append("CLIP_SCRAPER_URL+KEY (VPS Hostinger)")
                if not INSTAGRAM_SESSIONS:
                    missing_config.append("INSTAGRAM_SESSIONS (cookie session)")
            elif platform == "tiktok":
                if not CLIP_SCRAPER_URL or not CLIP_SCRAPER_KEY:
                    missing_config.append("CLIP_SCRAPER_URL+KEY (VPS)")
                if not TIKWM_API_KEY:
                    missing_config.append("TIKWM_API_KEY (tikwm.com)")
            elif platform == "youtube":
                if not YOUTUBE_API_KEY:
                    missing_config.append("YOUTUBE_API_KEY (Google Cloud, gratuit)")

            if missing_config:
                detail = (
                    f"Aucune vidéo trouvée pour @{username} sur {platform}. "
                    f"⚠️ Config Railway manquante : {', '.join(missing_config)}. "
                    f"Lance /api/admin/test-free-path/{platform}/{username} pour le diagnostic complet."
                )
            else:
                detail = (
                    f"Aucune vidéo trouvée pour @{username} sur {platform}. "
                    f"Toutes les sources gratuites ont échoué (proxy/VPS configurés mais bloqués par la plateforme). "
                    f"Lance /api/admin/test-free-path/{platform}/{username} pour voir laquelle pète exactement."
                )
            raise HTTPException(status_code=404, detail=detail)

        # Limite a 30 videos pour l'UI
        videos = videos[:30]

        return {
            "username": username,
            "platform": platform,
            "profile": {"username": username, "platform": platform},
            "videos": videos,
            "count": len(videos),
        }
    except HTTPException:
        raise
    except Exception as e:
        logger.warning(f"list_account_videos error for {platform}/@{username}: {type(e).__name__}: {e}")
        raise HTTPException(status_code=502, detail=f"Erreur scraping : {str(e)[:200]}")


@api_router.post("/campaigns/{campaign_id}/add-video")
@api_router.post("/campaigns/{campaign_id}/track-video")
async def track_video_by_url(campaign_id: str, body: dict, user: dict = Depends(get_current_user)):
    """
    Agency adds a video URL to track automatically.
    - Auto-fetches current stats from the platform
    - Stored as manually_added=True (bypasses joined_at filter)
    - target: specific user_id | "all" (all active clippers) | "" (no clipper)
    """
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    url = (body.get("url") or "").strip()
    platform = (body.get("platform") or "").lower().strip()
    target = (body.get("target") or "").strip()  # user_id | "all" | ""

    if not url:
        raise HTTPException(status_code=400, detail="URL requise")
    if platform not in ("tiktok", "youtube", "instagram"):
        raise HTTPException(status_code=400, detail="Plateforme invalide")
    # Vérifie que la plateforme est autorisée par la campagne
    allowed_platforms = campaign.get("platforms") or []
    if allowed_platforms and platform not in allowed_platforms:
        platforms_label = ", ".join(allowed_platforms) or "aucune"
        raise HTTPException(
            status_code=400,
            detail=f"Cette campagne n'accepte que : {platforms_label}. "
                   f"Modifie les plateformes dans l'onglet ⚙️ Paramètres pour ajouter {platform}."
        )

    # SAFETY : valider que l'URL pointe bien vers une video specifique, pas un profil
    expected_vid_id = _expected_video_id_from_url(url, platform)
    # Si l'URL ne matche pas mais qu'on a un platform_video_id explicite (modal voir-videos),
    # on reconstruit une URL canonique pour Instagram et on continue
    body_pvid = (body.get("platform_video_id") or "").strip()
    if not expected_vid_id and body_pvid and platform == "instagram":
        url = f"https://www.instagram.com/p/{body_pvid}/"
        expected_vid_id = body_pvid
        logger.info(f"add-video : URL reconstruite depuis platform_video_id={body_pvid}")
    if not expected_vid_id and body_pvid and platform == "tiktok" and body_pvid.isdigit():
        # Pour TikTok il faut aussi le username dans l'URL — essaye de l'extraire de l'URL d'origine
        m_uname = re.search(r'@([\w.-]+)/', url) if url else None
        uname_for_url = m_uname.group(1) if m_uname else (body.get("account_username") or "").strip().lstrip("@")
        if uname_for_url:
            url = f"https://www.tiktok.com/@{uname_for_url}/video/{body_pvid}"
            expected_vid_id = body_pvid
            logger.info(f"add-video : URL TikTok reconstruite depuis platform_video_id={body_pvid}")
    if not expected_vid_id:
        raise HTTPException(
            status_code=400,
            detail=f"URL invalide pour {platform}. Doit pointer vers une vidéo spécifique "
                   f"(ex TikTok: /video/123..., Instagram: /reel/ABC..., YouTube: ?v=...)"
        )

    # account_username optionnel : si l'utilisateur ajoute la video depuis le modal "Voir les videos d'un compte",
    # on connait le username -> permet le VPS account-scrape gratuit pour Instagram (qui n'a pas le @ dans l'URL video)
    account_username = (body.get("account_username") or body.get("username") or "").strip().lstrip("@") or None

    # APIFY DEBRANCHE pour Insta (Paul a configure proxy webshare = scraping gratuit suffit)
    prefer_apify_for_add = False

    # Fetch video stats — each platform function is self-contained with its own timeout and never raises
    scraping_failed = False
    try:
        vid_info = await fetch_single_video_by_url(url, platform, account_username=account_username, prefer_apify=prefer_apify_for_add)
    except Exception as e:
        logger.warning(f"track-video: could not fetch stats for {url} ({platform}): {type(e).__name__}: {e}")
        scraping_failed = True
        vid_info = {
            "platform_video_id": expected_vid_id,
            "url": url, "title": None, "thumbnail_url": None,
            "views": 0, "likes": 0, "comments": 0, "published_at": None,
        }

    rpm = campaign.get("rpm", 0)
    now_iso = datetime.now(timezone.utc).isoformat()

    # Determine target users
    if target == "all":
        members = await db.campaign_members.find(
            {"campaign_id": campaign_id, "status": "active", "role": "clipper"},
            {"_id": 0, "user_id": 1}
        ).to_list(100)
        target_users = [m["user_id"] for m in members]
        if not target_users:
            raise HTTPException(status_code=400, detail="Aucun clippeur actif dans cette campagne")
    elif target:
        # Verify clipper is in campaign
        member = await db.campaign_members.find_one(
            {"campaign_id": campaign_id, "user_id": target, "role": "clipper"}
        )
        if not member:
            raise HTTPException(status_code=400, detail="Ce clippeur ne fait pas partie de cette campagne")
        target_users = [target]
    else:
        target_users = [None]  # No clipper association

    saved = []
    for uid in target_users:
        earnings = round((vid_info["views"] / 1000) * rpm, 2) if uid else 0
        video_id = f"vid_{uuid.uuid4().hex[:12]}"
        # Fields updated every time (on insert OR update)
        set_fields = {
            "platform_video_id": vid_info["platform_video_id"],
            "account_id": None,
            "user_id": uid,
            "campaign_id": campaign_id,
            "platform": platform,
            "url": url,
            "title": vid_info.get("title"),
            "thumbnail_url": vid_info.get("thumbnail_url"),
            "views": vid_info["views"],
            "likes": vid_info.get("likes", 0),
            "comments": vid_info.get("comments", 0),
            "published_at": vid_info.get("published_at"),
            "fetched_at": now_iso,
            "earnings": earnings,
            "manually_added": True,
            "added_by": user["user_id"],
        }
        # Fields only set on first insert (video_id + created_at must NOT be in $set to avoid conflict)
        insert_only = {"video_id": video_id, "created_at": now_iso}
        upsert_key = {"campaign_id": campaign_id, "platform_video_id": vid_info["platform_video_id"]}
        if uid:
            upsert_key["user_id"] = uid
        try:
            await db.tracked_videos.update_one(
                upsert_key,
                {"$set": set_fields, "$setOnInsert": insert_only},
                upsert=True
            )
            saved.append({**set_fields, **insert_only})
        except Exception as e:
            err_str = str(e)
            if "duplicate key" in err_str.lower() or "E11000" in err_str:
                # Unique index conflict — just update the existing doc
                try:
                    await db.tracked_videos.update_one(upsert_key, {"$set": set_fields})
                    saved.append({**set_fields, **insert_only})
                except Exception as e2:
                    logger.warning(f"track_video fallback update error: {e2}")
            else:
                logger.warning(f"track_video upsert error: {e}")
                raise HTTPException(status_code=500, detail=f"Erreur d'enregistrement en base: {e}")

    views = int(vid_info.get("views") or 0)
    likes = int(vid_info.get("likes") or 0)
    if views > 0:
        msg = f"Vidéo trackée — {views:,} vues officielles récupérées"
        scraping_status = "ok"
    elif likes > 0:
        msg = f"Vidéo trackée — {likes:,} likes officiels (vues non publiques pour cette vidéo)"
        scraping_status = "partial"
    elif platform == "youtube" and not YOUTUBE_API_KEY:
        msg = "Vidéo enregistrée — clé YOUTUBE_API_KEY manquante côté serveur, stats indisponibles"
        scraping_status = "config_missing"
    elif scraping_failed:
        msg = "Vidéo enregistrée mais le scraping a échoué — les stats seront récupérées au prochain tracking automatique (toutes les 6h)"
        scraping_status = "retry_later"
    else:
        msg = "Vidéo enregistrée — aucune stat publique trouvée. Réessai automatique au prochain cycle (toutes les 6h)"
        scraping_status = "retry_later"

    return {
        "message": msg,
        "scraping_status": scraping_status,
        "video": {
            "url": url,
            "title": vid_info.get("title"),
            "thumbnail_url": vid_info.get("thumbnail_url"),
            "views": views,
            "likes": likes,
            "comments": int(vid_info.get("comments") or 0),
            "platform_video_id": vid_info.get("platform_video_id"),
            "platform": platform,
            "target_count": len([u for u in target_users if u]),
        }
    }

@api_router.post("/campaigns/{campaign_id}/manual-video")
async def add_manual_video(campaign_id: str, body: dict, user: dict = Depends(get_current_user)):
    """
    Agency adds a video manually for a clipper.
    Used for videos posted outside the campaign (exception/dérogation).
    These videos bypass the joined_at date filter and are always counted.
    """
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")
    if campaign.get("agency_id") != user["user_id"] and campaign.get("manager_id") != user["user_id"]:
        # Allow if user is a manager of this campaign
        member = await db.campaign_members.find_one({"campaign_id": campaign_id, "user_id": user["user_id"], "role": "manager"})
        if not member:
            raise HTTPException(status_code=403, detail="Non autorisé")

    clipper_id = body.get("user_id", "").strip()
    url = body.get("url", "").strip()
    try:
        views = max(0, int(body.get("views", 0)))
    except (TypeError, ValueError):
        views = 0
    platform = (body.get("platform") or "tiktok").lower()
    title = (body.get("title") or "Vidéo ajoutée manuellement").strip()

    if not clipper_id or not url:
        raise HTTPException(status_code=400, detail="user_id et url sont requis")

    # Verify clipper is in this campaign
    member = await db.campaign_members.find_one({"campaign_id": campaign_id, "user_id": clipper_id, "role": "clipper"})
    if not member:
        raise HTTPException(status_code=400, detail="Ce clippeur ne fait pas partie de cette campagne")

    rpm = campaign.get("rpm", 0)
    video_id = f"vid_{uuid.uuid4().hex[:12]}"
    video = {
        "video_id": video_id,
        "platform_video_id": f"manual_{video_id}",
        "campaign_id": campaign_id,
        "user_id": clipper_id,
        "account_id": None,
        "platform": platform,
        "url": url,
        "title": title,
        "views": views,
        "likes": 0,
        "comments": 0,
        "manually_added": True,
        "added_by": user["user_id"],
        "published_at": None,
        "fetched_at": datetime.now(timezone.utc).isoformat(),
        "created_at": datetime.now(timezone.utc).isoformat(),
        "earnings": round((views / 1000) * rpm, 2),
    }
    await db.tracked_videos.insert_one(video)
    video.pop("_id", None)

    # Notify clipper
    clipper = await db.users.find_one({"user_id": clipper_id}, {"_id": 0, "display_name": 1, "name": 1})
    clipper_name = (clipper or {}).get("display_name") or (clipper or {}).get("name", "")
    await notify_user(clipper_id, {
        "type": "manual_video_added",
        "message": f"L'agence a ajouté une vidéo à votre compte dans la campagne « {campaign.get('name', '')} ».",
        "campaign_id": campaign_id,
        "video_id": video_id,
    })

    return {"video": video, "earnings": video["earnings"]}

@api_router.delete("/campaigns/{campaign_id}/manual-video/{video_id}")
async def delete_manual_video(campaign_id: str, video_id: str, user: dict = Depends(get_current_user)):
    """Agency removes a manually added video."""
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    result = await db.tracked_videos.delete_one({
        "video_id": video_id,
        "campaign_id": campaign_id,
        "manually_added": True,
    })
    if result.deleted_count == 0:
        raise HTTPException(status_code=404, detail="Vidéo introuvable ou non supprimable")
    return {"message": "Vidéo supprimée"}

# ================= MESSAGES & CHAT =================

@api_router.get("/campaigns/{campaign_id}/messages")
async def get_messages(campaign_id: str, user: dict = Depends(get_current_user)):
    # Le canal "manager" est privé entre agence et manager.
    # On le cache aux clippeurs et clients pour qu'il n'apparaisse meme pas dans le reseau.
    role = user.get("role")
    query = {"campaign_id": campaign_id}
    if role not in ("agency", "manager"):
        query["message_type"] = {"$ne": "manager"}
    messages = await db.messages.find(
        query,
        {"_id": 0}
    ).sort("created_at", -1).to_list(200)
    result = list(reversed(messages))
    # Ensure all messages expose a reactions dict
    for m in result:
        if "reactions" not in m:
            m["reactions"] = {}
    return {"messages": result}

@api_router.get("/messages/unread-counts")
async def get_unread_counts(user: dict = Depends(get_current_user)):
    """Retourne le nombre de messages non lus par campagne — 2 requêtes DB (batch)."""
    uid = user["user_id"]

    # 1 query: all memberships
    memberships = await db.campaign_members.find(
        {"user_id": uid}, {"_id": 0, "campaign_id": 1}
    ).to_list(200)
    campaign_ids = list(set(m["campaign_id"] for m in memberships))

    # For agencies add their own campaigns (1 query)
    if user.get("role") == "agency":
        own = await db.campaigns.find({"agency_id": uid}, {"_id": 0, "campaign_id": 1}).to_list(200)
        campaign_ids = list(set(campaign_ids + [c["campaign_id"] for c in own]))

    if not campaign_ids:
        support_unread = await db.support_messages.count_documents(
            {"user_id": uid, "from_admin": True, "read_by_user": False}
        )
        return {"unread": {}, "support_unread": support_unread}

    # 1 query: all last_seen timestamps for this user
    seen_docs = await db.message_reads.find(
        {"user_id": uid, "campaign_id": {"$in": campaign_ids}},
        {"_id": 0, "campaign_id": 1, "last_seen_at": 1}
    ).to_list(500)
    seen_map = {d["campaign_id"]: d.get("last_seen_at") for d in seen_docs}

    # 1 aggregation: count unread per campaign
    # Cache les messages du canal "manager" aux clippeurs/clients
    match_filter = {
        "campaign_id": {"$in": campaign_ids},
        "sender_id": {"$ne": uid},
    }
    if user.get("role") not in ("agency", "manager"):
        match_filter["message_type"] = {"$ne": "manager"}
    pipeline = [
        {"$match": match_filter},
        {"$group": {
            "_id": "$campaign_id",
            "latest": {"$max": "$created_at"},
            "count": {"$sum": 1},
            "msgs": {"$push": {"created_at": "$created_at"}}
        }},
    ]
    raw = await db.messages.aggregate(pipeline).to_list(500)

    counts = {}
    for row in raw:
        cid = row["_id"]
        last_seen = seen_map.get(cid)
        if last_seen:
            unread = sum(1 for m in row["msgs"] if m["created_at"] > last_seen)
        else:
            unread = row["count"]
        if unread > 0:
            counts[cid] = unread

    support_unread = await db.support_messages.count_documents(
        {"user_id": uid, "from_admin": True, "read_by_user": False}
    )
    return {"unread": counts, "support_unread": support_unread}

@api_router.post("/campaigns/{campaign_id}/mark-read")
async def mark_campaign_read(campaign_id: str, user: dict = Depends(get_current_user)):
    """Marque tous les messages d'une campagne comme lus pour cet utilisateur."""
    uid = user["user_id"]
    now = datetime.now(timezone.utc).isoformat()
    await db.message_reads.update_one(
        {"user_id": uid, "campaign_id": campaign_id},
        {"$set": {"last_seen_at": now, "user_id": uid, "campaign_id": campaign_id}},
        upsert=True
    )
    return {"ok": True}

@api_router.post("/messages")
async def send_message(message_data: MessageCreate, user: dict = Depends(get_current_user)):
    # Bloquer les clippers en attente de validation
    if user.get("role") == "clipper" and message_data.campaign_id:
        member = await db.campaign_members.find_one({
            "campaign_id": message_data.campaign_id,
            "user_id": user["user_id"],
            "role": "clipper",
        })
        if member and member.get("status") == "pending":
            raise HTTPException(status_code=403, detail="Ta candidature est en attente de validation. Tu pourras écrire dans le chat une fois accepté.")

    # Canal "manager" privé : reservé à agence + manager
    if message_data.message_type == "manager" and user.get("role") not in ("agency", "manager"):
        raise HTTPException(status_code=403, detail="Canal réservé à l'agence et au manager.")

    message = {
        "message_id": f"msg_{uuid.uuid4().hex[:12]}",
        "campaign_id": message_data.campaign_id,
        "sender_id": user["user_id"],
        "sender_name": user.get("display_name") or user.get("name"),
        "sender_role": user.get("role"),
        "recipient_id": message_data.recipient_id,
        "content": message_data.content,
        "message_type": message_data.message_type,
        "image_data": message_data.image_data,
        "created_at": datetime.now(timezone.utc).isoformat()
    }

    await db.messages.insert_one(message)
    message.pop("_id", None)

    # Broadcast restreint pour le canal manager : seulement agence + managers
    if message_data.message_type == "manager":
        # Recupere agence + managers de la campagne
        camp = await db.campaigns.find_one({"campaign_id": message_data.campaign_id}, {"_id": 0, "agency_id": 1})
        recipient_ids = set()
        if camp and camp.get("agency_id"):
            recipient_ids.add(camp["agency_id"])
        manager_members = await db.campaign_members.find(
            {"campaign_id": message_data.campaign_id, "role": "manager"},
            {"_id": 0, "user_id": 1}
        ).to_list(50)
        for m in manager_members:
            if m.get("user_id"):
                recipient_ids.add(m["user_id"])
        await asyncio.gather(*[
            manager.send_to_user(uid, {"type": "new_message", "message": message})
            for uid in recipient_ids
        ], return_exceptions=True)
    else:
        await manager.broadcast_to_campaign(message_data.campaign_id, {
            "type": "new_message",
            "message": message
        })

    return message

@api_router.post("/messages/{message_id}/react")
async def react_to_message(message_id: str, body: dict, user: dict = Depends(get_current_user)):
    """Toggle an emoji reaction on a message. All roles can react (including clippers on announcements)."""
    ALLOWED_EMOJIS = ["❤️", "🔥", "😂", "👍", "👎", "😮", "🎉"]
    emoji = (body.get("emoji") or "").strip()
    if not emoji or emoji not in ALLOWED_EMOJIS:
        raise HTTPException(status_code=400, detail="Emoji non autorisé")

    msg = await db.messages.find_one({"message_id": message_id}, {"_id": 0})
    if not msg:
        raise HTTPException(status_code=404, detail="Message introuvable")

    reactions = dict(msg.get("reactions") or {})
    user_id = user["user_id"]

    current_users = list(reactions.get(emoji, []))
    if user_id in current_users:
        current_users.remove(user_id)
    else:
        current_users.append(user_id)

    if current_users:
        reactions[emoji] = current_users
    else:
        reactions.pop(emoji, None)

    await db.messages.update_one({"message_id": message_id}, {"$set": {"reactions": reactions}})

    # Broadcast to campaign so all connected users see the update in real-time
    try:
        await manager.broadcast_to_campaign(msg["campaign_id"], {
            "type": "message_reaction",
            "message_id": message_id,
            "reactions": reactions,
        })
    except Exception:
        pass

    return {"reactions": reactions}


@api_router.get("/messages/{message_id}/comments")
async def get_message_comments(message_id: str, user: dict = Depends(get_current_user)):
    """Get text comments on an annonce message."""
    comments = await db.message_comments.find(
        {"message_id": message_id}, {"_id": 0}
    ).sort("created_at", 1).to_list(200)
    # Enrich with author info
    author_ids = list({c["user_id"] for c in comments})
    if author_ids:
        authors = await db.users.find(
            {"user_id": {"$in": author_ids}},
            {"_id": 0, "user_id": 1, "display_name": 1, "name": 1, "picture": 1, "role": 1}
        ).to_list(len(author_ids))
        authors_map = {a["user_id"]: a for a in authors}
    else:
        authors_map = {}
    for c in comments:
        a = authors_map.get(c["user_id"], {})
        c["author_name"] = a.get("display_name") or a.get("name") or "?"
        c["author_picture"] = a.get("picture")
        c["author_role"] = a.get("role")
    return {"comments": comments}


@api_router.post("/messages/{message_id}/comments")
async def post_message_comment(message_id: str, body: dict, user: dict = Depends(get_current_user)):
    """Post a text comment on an annonce message."""
    content = (body.get("content") or "").strip()
    if not content:
        raise HTTPException(status_code=400, detail="Contenu vide")
    if len(content) > 500:
        raise HTTPException(status_code=400, detail="Commentaire trop long (500 caractères max)")

    msg = await db.messages.find_one({"message_id": message_id}, {"_id": 0, "campaign_id": 1, "message_type": 1})
    if not msg:
        raise HTTPException(status_code=404, detail="Message introuvable")

    comment_id = f"cmt_{uuid.uuid4().hex[:12]}"
    comment = {
        "comment_id": comment_id,
        "message_id": message_id,
        "campaign_id": msg.get("campaign_id"),
        "user_id": user["user_id"],
        "content": content,
        "created_at": datetime.now(timezone.utc).isoformat(),
    }
    await db.message_comments.insert_one(comment)
    comment.pop("_id", None)
    comment["author_name"] = user.get("display_name") or user.get("name") or "?"
    comment["author_picture"] = user.get("picture")
    comment["author_role"] = user.get("role")

    # Broadcast to campaign
    try:
        await manager.broadcast_to_campaign(msg["campaign_id"], {
            "type": "message_comment",
            "message_id": message_id,
            "comment": comment,
        })
    except Exception:
        pass

    # Update comment count on message
    await db.messages.update_one(
        {"message_id": message_id},
        {"$inc": {"comment_count": 1}}
    )

    return comment


@api_router.get("/campaigns/{campaign_id}/participants")
async def get_campaign_participants(campaign_id: str, user: dict = Depends(get_current_user)):
    """Get all participants (active + pending members + agency/manager) of a campaign."""
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    # All members (any status)
    members = await db.campaign_members.find(
        {"campaign_id": campaign_id},
        {"_id": 0, "user_id": 1, "role": 1, "status": 1, "joined_at": 1}
    ).to_list(500)

    member_ids = [m["user_id"] for m in members]
    agency_id = campaign.get("agency_id")
    campaign_manager_id = campaign.get("manager_id")

    # All user IDs we need to fetch (deduplicated)
    all_ids = list({uid for uid in member_ids + [agency_id, campaign_manager_id] if uid})

    user_docs = await db.users.find(
        {"user_id": {"$in": all_ids}},
        {"_id": 0, "user_id": 1, "display_name": 1, "name": 1, "picture": 1, "role": 1}
    ).to_list(500)
    users_map = {u["user_id"]: u for u in user_docs}

    participants = []
    seen_ids = set()

    # Agency owner first (not in campaign_members)
    for uid, lbl_role in [(agency_id, "agency"), (campaign_manager_id, "manager")]:
        if uid and uid not in seen_ids and uid not in member_ids:
            u = users_map.get(uid, {})
            participants.append({
                "user_id": uid,
                "role": u.get("role", lbl_role),
                "status": "owner",
                "display_name": u.get("display_name") or u.get("name", "Agence"),
                "picture": u.get("picture"),
                "joined_at": campaign.get("created_at"),
            })
            seen_ids.add(uid)

    # All members
    for m in members:
        uid = m["user_id"]
        if uid in seen_ids:
            continue
        u = users_map.get(uid, {})
        participants.append({
            "user_id": uid,
            "role": m.get("role", "clipper"),
            "status": m.get("status", "active"),
            "display_name": u.get("display_name") or u.get("name", "?"),
            "picture": u.get("picture"),
            "joined_at": m.get("joined_at"),
        })
        seen_ids.add(uid)

    return {"participants": participants, "total": len(participants)}

