@api_router.put("/profile")
async def update_profile(profile_data: dict, user: dict = Depends(get_current_user)):
    update_fields = {}
    if "display_name" in profile_data:
        update_fields["display_name"] = profile_data["display_name"]
    if "picture" in profile_data:
        update_fields["picture"] = profile_data["picture"]
    if "payment_info" in profile_data:
        update_fields["payment_info"] = profile_data["payment_info"]

    if update_fields:
        await db.users.update_one(
            {"user_id": user["user_id"]},
            {"$set": update_fields}
        )
    updated = await db.users.find_one({"user_id": user["user_id"]}, {"_id": 0, "password_hash": 0})
    return updated or {}

# ================= WEBSOCKET =================

@app.websocket("/ws/{user_id}")
async def websocket_endpoint(websocket: WebSocket, user_id: str):
    """WebSocket avec authentification : verifie que le session_token correspond bien au user_id.
    Le client doit envoyer le cookie session_token (auto par le navigateur).
    """
    # Authentification : verification que le user_id correspond a la session
    session_token = websocket.cookies.get("session_token", "")
    if not session_token:
        # Tente aussi via query param (pour les clients qui ne supportent pas cookies)
        session_token = websocket.query_params.get("session", "")

    if not session_token:
        await websocket.close(code=4401, reason="Authentication required")
        return

    session = await db.user_sessions.find_one({"session_token": session_token}, {"_id": 0, "user_id": 1, "expires_at": 1})
    if not session:
        await websocket.close(code=4401, reason="Invalid session")
        return

    # Verifie que la session n'a pas expire
    expires_at = session.get("expires_at")
    if expires_at:
        try:
            exp_dt = datetime.fromisoformat(expires_at.replace("Z", "+00:00")) if isinstance(expires_at, str) else expires_at
            if exp_dt.tzinfo is None:
                exp_dt = exp_dt.replace(tzinfo=timezone.utc)
            if datetime.now(timezone.utc) > exp_dt:
                await websocket.close(code=4401, reason="Session expired")
                return
        except Exception:
            pass

    # CRITIQUE : verifier que le user_id de l'URL correspond bien a celui de la session
    if session.get("user_id") != user_id:
        await websocket.close(code=4403, reason="Forbidden : user_id mismatch")
        logger.warning(f"WebSocket auth bypass attempt: session={session.get('user_id')} tried to subscribe as {user_id}")
        return

    await manager.connect(websocket, user_id)
    try:
        while True:
            data = await websocket.receive_text()
            try:
                message = json.loads(data)
            except (json.JSONDecodeError, ValueError):
                continue
            if message.get("type") == "ping":
                await websocket.send_json({"type": "pong"})
    except WebSocketDisconnect:
        manager.disconnect(websocket, user_id)
    except Exception:
        manager.disconnect(websocket, user_id)

# ================= ADMIN ROUTES =================

async def verify_admin_code(request: Request):
    """Dependency: verify X-Admin-Code header OR ?code= query param against env var.
    Permet tests rapides depuis navigateur via ?code=ADMIN_CODE.
    """
    if not ADMIN_SECRET_CODE:
        raise HTTPException(status_code=503, detail="ADMIN_SECRET_CODE non configuré sur le serveur")
    code = request.headers.get("X-Admin-Code", "") or request.query_params.get("code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    return True

@api_router.get("/admin/diag-instagram")
async def admin_diag_instagram(request: Request, url: str = "https://www.instagram.com/p/DVju4UNCle9/"):
    """DIAGNOSTIC : test direct du scraping Insta + tous les checks de configuration."""
    # Auth simple
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")

    diag = {"url_tested": url, "_step": "init"}
    try:
        diag["_step"] = "config"
        try:
            apify_token_global = APIFY_TOKEN
        except NameError:
            apify_token_global = ""
        try:
            apify_disabled_global = APIFY_DISABLED
        except NameError:
            apify_disabled_global = None
        try:
            apify_budget_global = APIFY_INSTA_DAILY_BUDGET
        except NameError:
            apify_budget_global = "NOT_DEFINED"
        try:
            ig_sessions_count = len(INSTAGRAM_SESSIONS)
        except NameError:
            ig_sessions_count = "NOT_DEFINED"
        try:
            ig_biz = bool(IG_BUSINESS_ACCOUNT_ID)
        except NameError:
            ig_biz = "NOT_DEFINED"
        try:
            ig_token = bool(IG_LONG_LIVED_TOKEN)
        except NameError:
            ig_token = "NOT_DEFINED"
        try:
            cs_url = CLIP_SCRAPER_URL or "(vide)"
        except NameError:
            cs_url = "NOT_DEFINED"
        try:
            cs_key = bool(CLIP_SCRAPER_KEY)
        except NameError:
            cs_key = "NOT_DEFINED"
        try:
            proxy_global = BACKEND_PROXY_URL
        except NameError:
            proxy_global = None
        diag["config"] = {
            "APIFY_TOKEN_configured": bool(apify_token_global),
            "APIFY_TOKEN_prefix": (apify_token_global[:10] + "...") if apify_token_global else None,
            "APIFY_DISABLED": apify_disabled_global,
            "APIFY_INSTA_DAILY_BUDGET": apify_budget_global,
            "INSTAGRAM_SESSIONS_count": ig_sessions_count,
            "CLIP_SCRAPER_URL": cs_url,
            "CLIP_SCRAPER_KEY_configured": cs_key,
            "IG_BUSINESS_ACCOUNT_ID_configured": ig_biz,
            "IG_LONG_LIVED_TOKEN_configured": ig_token,
            "BACKEND_PROXY_URL_configured": bool(proxy_global),
            "BACKEND_PROXY_URL_prefix": (proxy_global[:25] + "...") if proxy_global else None,
        }

        # Budget
        diag["_step"] = "budget"
        try:
            budget_ok = await _apify_budget_ok("instagram")
            today_iso = datetime.now(timezone.utc).strftime("%Y-%m-%dT00:00:00+00:00")
            today_count = await db.scraping_history.count_documents({
                "source": "apify", "platform": "instagram", "timestamp": {"$gte": today_iso}
            })
            diag["apify_budget"] = {"ok": budget_ok, "used_today": today_count, "max_per_day": apify_budget_global}
        except Exception as e:
            diag["apify_budget"] = {"error": f"{type(e).__name__}: {e}"}

        # Delete old cascade log first pour garantir donnees fraiches
        diag["_step"] = "clear_old_log"
        try:
            import re as _re_for_id
            m_id = _re_for_id.search(r'/(?:p|reel|reels)/([A-Za-z0-9_-]+)', url)
            shortcode_id = m_id.group(1) if m_id else None
            if shortcode_id:
                await db.cascade_debug_log.delete_one({"_id": f"ig_{shortcode_id}"})
        except Exception:
            shortcode_id = None

        # Cascade complete UNIQUEMENT (1 seul appel Apify pour eviter rate limit)
        diag["_step"] = "full_cascade"
        try:
            full_result = await asyncio.wait_for(_fetch_single_instagram_video(url), timeout=200)
            diag["full_cascade_result"] = full_result
            diag["apify_reel_scraper_result"] = "SKIPPED (test direct removed - voir full_cascade)"
        except asyncio.TimeoutError:
            diag["full_cascade_result"] = {"error": "TIMEOUT 200s"}
            diag["apify_reel_scraper_result"] = "TIMEOUT cascade"
        except Exception as e:
            diag["full_cascade_result"] = {"error": f"{type(e).__name__}: {e}"}
            diag["apify_reel_scraper_result"] = f"error cascade: {e}"

        # Recupere le cascade log fraichement stocke
        diag["_step"] = "cascade_log"
        try:
            if shortcode_id:
                cascade_doc = await db.cascade_debug_log.find_one({"_id": f"ig_{shortcode_id}"}, {"_id": 0})
                diag["cascade_log"] = cascade_doc if cascade_doc else "NO LOG STORED - cascade fonction n'a meme pas tente de stocker"
        except Exception as e:
            diag["cascade_log"] = f"error reading log: {e}"

        diag["_step"] = "DONE"
        return diag
    except Exception as e:
        diag["_FATAL_ERROR"] = f"{type(e).__name__}: {e} (at step={diag.get('_step')})"
        return diag


