@api_router.get("/admin/proxy-stats")
async def admin_proxy_stats(request: Request):
    """Stats d'utilisation des pools de proxies + etat des bad-list."""
    await verify_admin_code(request)
    now_ts = time.time()
    static_bad = sum(1 for p in BACKEND_PROXY_STATIC if _PROXY_BAD_UNTIL.get(p, 0) > now_ts)
    rotating_bad = sum(1 for p in BACKEND_PROXY_ROTATING if _PROXY_BAD_UNTIL.get(p, 0) > now_ts)
    total_calls = _PROXY_USAGE_COUNT["static"] + _PROXY_USAGE_COUNT["rotating"]
    return {
        "pools": {
            "static": {
                "total": len(BACKEND_PROXY_STATIC),
                "available": len(BACKEND_PROXY_STATIC) - static_bad,
                "bad_quarantined": static_bad,
                "bandwidth": "illimite (Static Residential)",
            },
            "rotating": {
                "total": len(BACKEND_PROXY_ROTATING),
                "available": len(BACKEND_PROXY_ROTATING) - rotating_bad,
                "bad_quarantined": rotating_bad,
                "bandwidth": "quota partage 1 GB/mois (Rotating Residential)",
            },
        },
        "usage_counts_since_boot": {
            "static_picks": _PROXY_USAGE_COUNT["static"],
            "rotating_picks": _PROXY_USAGE_COUNT["rotating"],
            "static_ratio": f"{(_PROXY_USAGE_COUNT['static'] / total_calls * 100):.1f}%" if total_calls else "n/a",
        },
        "policy": "Static prioritaire (illimite). Rotating en fallback uniquement si tous Static rate-limited.",
    }


@api_router.post("/admin/social-accounts/{account_id}/verify-existence")
async def admin_verify_account_existence(account_id: str, request: Request):
    """Verifie ACTIVEMENT si un compte existe encore sur sa plateforme.
    Si False -> marque status=deleted. Si True -> reset le compteur d'echecs."""
    await verify_admin_code(request)
    acc = await db.social_accounts.find_one({"account_id": account_id}, {"_id": 0})
    if not acc:
        raise HTTPException(status_code=404, detail="Compte introuvable")
    platform = acc.get("platform")
    username = acc.get("username")
    check_target = acc.get("platform_channel_id") if platform == "youtube" else username
    exists = await _verify_account_still_exists(platform, check_target or username)
    now_iso = datetime.now(timezone.utc).isoformat()
    update_fields = {
        "last_existence_check_at": now_iso,
        "last_existence_check_result": "exists" if exists is True else "deleted" if exists is False else "uncertain",
    }
    if exists is False:
        account_was_verified = bool(acc.get("verified_at")) or bool(acc.get("last_tracked_at"))
        update_fields.update({
            "status": "deleted",
            "deleted_at": now_iso,
            "deleted_type": "deleted_by_user" if account_was_verified else "never_existed",
            "deleted_reason": f"Verification manuelle admin : compte {platform} confirme supprime",
            "not_found_count": 99,
        })
    elif exists is True:
        update_fields.update({
            "consecutive_failures": 0,
            "tracking_paused_until": None,
            "not_found_count": 0,
        })
    await db.social_accounts.update_one({"account_id": account_id}, {"$set": update_fields})
    return {
        "ok": True,
        "platform": platform,
        "username": username,
        "exists": exists,
        "result": update_fields.get("last_existence_check_result"),
        "action_taken": (
            "Marque comme supprime" if exists is False
            else "Compteurs d'echec reset" if exists is True
            else "Aucune action (resultat incertain)"
        ),
    }

@api_router.get("/admin/suspect-accounts")
async def admin_suspect_accounts(request: Request):
    """Liste les comptes 'suspects' :
    - Usernames corrompus (contiennent ?, =, &, %, etc.)
    - Comptes en echec persistant (consecutive_failures >= 3) jamais verifies
    - Comptes en pause auto depuis > 24h sans verif d'existence
    """
    await verify_admin_code(request)
    import re as _re_susp
    suspect_pattern = _re_susp.compile(r'[^a-zA-Z0-9._-]')

    cursor = db.social_accounts.find(
        {"status": {"$ne": "deleted"}},
        {
            "_id": 0,
            "account_id": 1,
            "platform": 1,
            "username": 1,
            "status": 1,
            "consecutive_failures": 1,
            "tracking_paused_until": 1,
            "last_tracked_at": 1,
            "last_existence_check_at": 1,
            "last_existence_check_result": 1,
            "user_id": 1,
            "created_at": 1,
        }
    )
    corrupted = []
    persistent_failures = []
    never_verified = []
    async for acc in cursor:
        username = (acc.get("username") or "").strip()
        if not username:
            continue
        # Detection username corrompu
        if suspect_pattern.search(username):
            corrupted.append({**acc, "reason": "username contient caracteres invalides"})
            continue
        # Echecs persistants jamais verifies
        consec = int(acc.get("consecutive_failures") or 0)
        last_check = acc.get("last_existence_check_at")
        if consec >= 3 and not last_check:
            persistent_failures.append({**acc, "reason": f"{consec} echecs consecutifs sans verif d'existence"})
        elif consec >= 1 and not last_check:
            never_verified.append({**acc, "reason": f"{consec} echec(s) jamais verifies"})

    return {
        "corrupted_usernames": corrupted,
        "persistent_failures": persistent_failures,
        "never_verified": never_verified,
        "totals": {
            "corrupted": len(corrupted),
            "persistent_failures": len(persistent_failures),
            "never_verified": len(never_verified),
        },
    }


@api_router.post("/admin/social-accounts/bulk-verify-pending")
async def admin_bulk_verify_pending(request: Request, max_accounts: int = 100):
    """Verifie ACTIVEMENT l'existence de tous les comptes en echec
    qui n'ont JAMAIS ete verifies (last_existence_check_at = null) OU
    dont la derniere verif date de > 24h.
    Limite max_accounts pour eviter de saturer (default 100).
    Marque automatiquement les comptes confirmes supprimes."""
    await verify_admin_code(request)
    cutoff_24h = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
    query = {
        "status": {"$ne": "deleted"},
        "consecutive_failures": {"$gte": 1},
        "$or": [
            {"last_existence_check_at": {"$exists": False}},
            {"last_existence_check_at": None},
            {"last_existence_check_at": {"$lt": cutoff_24h}},
        ],
    }
    cursor = db.social_accounts.find(query, {"_id": 0}).limit(max_accounts)
    accounts = [a async for a in cursor]
    logger.info(f"Bulk verify pending : {len(accounts)} comptes a verifier (max={max_accounts})")

    results = {"exists": 0, "deleted": 0, "uncertain": 0, "errors": 0, "details": []}
    for acc in accounts:
        platform = acc.get("platform")
        username = acc.get("username") or ""
        account_id = acc.get("account_id")
        check_target = acc.get("platform_channel_id") if platform == "youtube" else username
        now_iso = datetime.now(timezone.utc).isoformat()
        try:
            exists = await asyncio.wait_for(
                _verify_account_still_exists(platform, check_target or username),
                timeout=30
            )
            update_fields = {
                "last_existence_check_at": now_iso,
                "last_existence_check_result": (
                    "exists" if exists is True
                    else "deleted" if exists is False
                    else "uncertain"
                ),
            }
            if exists is False:
                account_was_verified = bool(acc.get("verified_at")) or bool(acc.get("last_tracked_at"))
                update_fields.update({
                    "status": "deleted",
                    "deleted_at": now_iso,
                    "deleted_type": "deleted_by_user" if account_was_verified else "never_existed",
                    "deleted_reason": f"Bulk verify : compte {platform} confirme supprime ({acc.get('consecutive_failures', 0)} echecs)",
                    "not_found_count": 99,
                })
                results["deleted"] += 1
            elif exists is True:
                update_fields.update({
                    "consecutive_failures": 0,
                    "tracking_paused_until": None,
                    "not_found_count": 0,
                })
                results["exists"] += 1
            else:
                results["uncertain"] += 1
            await db.social_accounts.update_one({"account_id": account_id}, {"$set": update_fields})
            results["details"].append({
                "account_id": account_id,
                "platform": platform,
                "username": username,
                "result": update_fields["last_existence_check_result"],
            })
        except Exception as ex:
            results["errors"] += 1
            results["details"].append({
                "account_id": account_id,
                "platform": platform,
                "username": username,
                "result": "error",
                "error": f"{type(ex).__name__}: {ex}",
            })
        # Petit delay pour ne pas spam les plateformes (1s entre chaque verif)
        await asyncio.sleep(1)

    return {
        "ok": True,
        "checked": len(accounts),
        "results": {k: v for k, v in results.items() if k != "details"},
        "details": results["details"][:50],  # cap pour la response
    }


@api_router.get("/admin/scrape-diagnostic")
async def admin_scrape_diagnostic(request: Request, hours: int = 24):
    """Diagnostic complet du systeme de scraping.
    Pour Paul : comprendre rapidement si le scrape automatique a tourne,
    combien de comptes sont actifs vs deleted, etat des campagnes, etc.
    """
    await verify_admin_code(request)
    now = datetime.now(timezone.utc)
    cutoff = (now - timedelta(hours=hours)).isoformat()

    # ── Stats comptes globales ─────────────────────────────────────
    total_accounts = await db.social_accounts.count_documents({})
    verified = await db.social_accounts.count_documents({"status": "verified"})
    deleted = await db.social_accounts.count_documents({"status": "deleted"})
    pending = await db.social_accounts.count_documents({"status": "pending"})
    error_status = await db.social_accounts.count_documents({"status": "error"})

    # Comptes en pause auto (tracking_paused_until > now)
    paused_now = await db.social_accounts.count_documents({
        "tracking_paused_until": {"$gt": now.isoformat()},
        "status": "verified",
    })

    # Comptes en echec persistant (consecutive_failures >= 3) mais pas deleted
    persistent_failing = await db.social_accounts.count_documents({
        "status": "verified",
        "consecutive_failures": {"$gte": 3},
    })

    # Comptes scrapes recemment (last_tracked_at >= cutoff)
    scraped_recently = await db.social_accounts.count_documents({
        "last_tracked_at": {"$gte": cutoff},
        "status": "verified",
    })

    # Comptes deleted recemment (par mon code de verif active probablement)
    recent_deleted_cursor = db.social_accounts.find(
        {"status": "deleted", "deleted_at": {"$gte": cutoff}},
        {"_id": 0, "account_id": 1, "platform": 1, "username": 1, "deleted_at": 1, "deleted_reason": 1, "deleted_type": 1, "consecutive_failures": 1}
    ).sort("deleted_at", -1).limit(100)
    recent_deleted = [a async for a in recent_deleted_cursor]

    # ── Stats campagnes ─────────────────────────────────────────────
    total_campaigns = await db.campaigns.count_documents({})
    active_campaigns = await db.campaigns.count_documents({"status": "active"})
    # Campagnes scrapees recemment
    campaigns_scraped_recently = await db.campaigns.count_documents({
        "status": "active",
        "last_scraped_at": {"$gte": cutoff},
    })
    # Campagnes dues maintenant (next_scrape_at <= now)
    campaigns_due_now = await db.campaigns.count_documents({
        "status": "active",
        "next_scrape_at": {"$lte": now.isoformat()},
    })

    # Detail par campagne (top 20 actives)
    campaigns_cursor = db.campaigns.find(
        {"status": "active"},
        {"_id": 0, "campaign_id": 1, "name": 1, "last_scraped_at": 1, "next_scrape_at": 1, "tracking_per_day": 1, "scrape_interval_hours": 1}
    ).sort("last_scraped_at", -1).limit(20)
    campaigns_detail = []
    async for c in campaigns_cursor:
        cid = c["campaign_id"]
        # Compte les comptes assignes (via campaign_social_accounts)
        n_assigned = await db.campaign_social_accounts.count_documents({"campaign_id": cid})
        # Combien de comptes scrapes recemment
        assignments = await db.campaign_social_accounts.find(
            {"campaign_id": cid}, {"_id": 0, "account_id": 1}
        ).to_list(500)
        acc_ids = [a["account_id"] for a in assignments]
        n_scraped_recent = await db.social_accounts.count_documents({
            "account_id": {"$in": acc_ids},
            "last_tracked_at": {"$gte": cutoff},
            "status": "verified",
        }) if acc_ids else 0
        campaigns_detail.append({
            **c,
            "accounts_assigned": n_assigned,
            "accounts_scraped_recently": n_scraped_recent,
        })

    # ── Etat scheduler ────────────────────────────────────────────
    next_scrape_utc = _next_scrape_time_utc()
    scheduler_state = {
        "scheduler_lock_locked": _TRACKING_RUN_LOCK.locked(),
        "next_global_scrape_utc": next_scrape_utc.isoformat(),
        "next_global_scrape_paris": next_scrape_utc.astimezone(PARIS_TZ).strftime("%Y-%m-%d %H:%M"),
        "schedule_paris": [f"{h:02d}:{m:02d}" for h, m in SCRAPE_SCHEDULE_PARIS],
    }

    # ── Watchdog state ────────────────────────────────────────────
    watchdog_state = _WATCHDOG_LAST_CHECK

    return {
        "now_utc": now.isoformat(),
        "now_paris": now.astimezone(PARIS_TZ).strftime("%Y-%m-%d %H:%M"),
        "window_hours": hours,
        "accounts": {
            "total": total_accounts,
            "verified": verified,
            "deleted": deleted,
            "pending": pending,
            "error": error_status,
            "paused_now": paused_now,
            "persistent_failing": persistent_failing,
            "scraped_recently": scraped_recently,
            "deleted_in_window": len(recent_deleted),
        },
        "campaigns": {
            "total": total_campaigns,
            "active": active_campaigns,
            "scraped_in_window": campaigns_scraped_recently,
            "due_now": campaigns_due_now,
        },
        "scheduler": scheduler_state,
        "watchdog": watchdog_state,
        "campaigns_detail": campaigns_detail,
        "recently_deleted_accounts": recent_deleted,
        "proxy_pools": {
            "static_count": len(BACKEND_PROXY_STATIC),
            "rotating_count": len(BACKEND_PROXY_ROTATING),
            "usage": _PROXY_USAGE_COUNT,
        },
    }


@api_router.post("/admin/restore-recently-deleted")
async def admin_restore_recently_deleted(request: Request, hours: int = 24, dry_run: bool = True):
    """Restaure les comptes marques 'deleted' dans les dernieres N heures.
    Utile si la verif active a marque a tort des comptes valides.

    dry_run=True (default) : ne fait QUE retourner la liste sans modifier.
    dry_run=false : effectue la restauration (status -> verified, reset counters).
    """
    await verify_admin_code(request)
    cutoff = (datetime.now(timezone.utc) - timedelta(hours=hours)).isoformat()
    query = {
        "status": "deleted",
        "deleted_at": {"$gte": cutoff},
    }
    cursor = db.social_accounts.find(query, {"_id": 0})
    accounts = [a async for a in cursor]

    if dry_run:
        return {
            "ok": True,
            "dry_run": True,
            "count": len(accounts),
            "accounts": [
                {
                    "account_id": a.get("account_id"),
                    "platform": a.get("platform"),
                    "username": a.get("username"),
                    "deleted_at": a.get("deleted_at"),
                    "deleted_reason": a.get("deleted_reason"),
                    "deleted_type": a.get("deleted_type"),
                }
                for a in accounts
            ],
            "note": "Aucune modification. Relancer avec dry_run=false pour appliquer.",
        }

    # Restauration effective
    restored_ids = [a["account_id"] for a in accounts]
    if restored_ids:
        await db.social_accounts.update_many(
            {"account_id": {"$in": restored_ids}},
            {"$set": {
                "status": "verified",
                "consecutive_failures": 0,
                "tracking_paused_until": None,
                "not_found_count": 0,
                "last_existence_check_at": None,  # force re-verif au prochain scrape
                "last_existence_check_result": None,
                "deleted_at": None,
                "deleted_reason": None,
                "deleted_type": None,
                "restored_at": datetime.now(timezone.utc).isoformat(),
                "restored_reason": f"Restauration manuelle admin (deleted depuis < {hours}h)",
            }}
        )
        logger.warning(f"🔄 RESTORE : {len(restored_ids)} comptes restaures (status=verified) par admin")

    return {
        "ok": True,
        "dry_run": False,
        "restored_count": len(restored_ids),
        "restored_accounts": [
            {"account_id": a.get("account_id"), "platform": a.get("platform"), "username": a.get("username")}
            for a in accounts
        ],
    }


@api_router.post("/admin/purge-dead-accounts")
async def admin_purge_dead_accounts(
    request: Request,
    min_failures: int = 5,
    dry_run: bool = True,
    max_to_check: int = 200,
):
    """Audit AGRESSIF des comptes morts.
    Pour chaque compte avec consecutive_failures >= min_failures,
    lance une verif active (2 sources par plateforme). Si la verif dit
    'deleted' OU si toutes les sources echouent silencieusement,
    marque le compte 'deleted'.

    dry_run=true (default) : retourne juste la liste sans modifier.
    dry_run=false : applique.
    """
    await verify_admin_code(request)
    query = {
        "status": "verified",
        "consecutive_failures": {"$gte": min_failures},
    }
    cursor = db.social_accounts.find(query, {"_id": 0}).limit(max_to_check)
    accounts = [a async for a in cursor]
    logger.info(f"Purge dead accounts: {len(accounts)} candidats (min_failures={min_failures}, dry_run={dry_run})")

    results = {"exists": 0, "deleted": 0, "uncertain": 0, "errors": 0, "actions": []}
    for acc in accounts:
        platform = acc.get("platform")
        username = acc.get("username") or ""
        account_id = acc.get("account_id")
        consec = int(acc.get("consecutive_failures") or 0)
        check_target = acc.get("platform_channel_id") if platform == "youtube" else username
        now_iso = datetime.now(timezone.utc).isoformat()
        try:
            exists = await asyncio.wait_for(
                _verify_account_still_exists(platform, check_target or username),
                timeout=30
            )
        except Exception as ex:
            results["errors"] += 1
            results["actions"].append({
                "account_id": account_id,
                "platform": platform,
                "username": username,
                "consecutive_failures": consec,
                "action": "error",
                "error": f"{type(ex).__name__}: {ex}",
            })
            continue

        if exists is True:
            results["exists"] += 1
            action = "kept_alive"
            if not dry_run:
                await db.social_accounts.update_one(
                    {"account_id": account_id},
                    {"$set": {
                        "last_existence_check_at": now_iso,
                        "last_existence_check_result": "exists",
                        "consecutive_failures": 0,
                        "tracking_paused_until": None,
                    }}
                )
        elif exists is False:
            results["deleted"] += 1
            action = "marked_deleted"
            if not dry_run:
                await db.social_accounts.update_one(
                    {"account_id": account_id},
                    {"$set": {
                        "status": "deleted",
                        "deleted_at": now_iso,
                        "deleted_type": "purge_admin",
                        "deleted_reason": f"Purge admin : compte {platform} confirme supprime apres {consec} echecs",
                        "last_existence_check_at": now_iso,
                        "last_existence_check_result": "deleted",
                        "not_found_count": 99,
                    }}
                )
        else:
            results["uncertain"] += 1
            # Si min_failures >= 7 et la verif est uncertain, on marque deleted force
            # (regle de l'auto-pause : 7 echecs sans confirmation = mort)
            if consec >= 7:
                action = "force_deleted_uncertain"
                results["deleted"] += 1
                results["uncertain"] -= 1
                if not dry_run:
                    await db.social_accounts.update_one(
                        {"account_id": account_id},
                        {"$set": {
                            "status": "deleted",
                            "deleted_at": now_iso,
                            "deleted_type": "purge_admin_force",
                            "deleted_reason": f"Purge admin force : {consec} echecs + verif uncertain = mort probable",
                            "last_existence_check_at": now_iso,
                            "last_existence_check_result": "uncertain",
                            "not_found_count": 99,
                        }}
                    )
            else:
                action = "kept_uncertain"
                if not dry_run:
                    await db.social_accounts.update_one(
                        {"account_id": account_id},
                        {"$set": {
                            "last_existence_check_at": now_iso,
                            "last_existence_check_result": "uncertain",
                        }}
                    )
        results["actions"].append({
            "account_id": account_id,
            "platform": platform,
            "username": username,
            "consecutive_failures": consec,
            "verif_result": str(exists),
            "action": action,
        })
        # Petit delay pour ne pas spam les plateformes
        await asyncio.sleep(0.5)

    return {
        "ok": True,
        "dry_run": dry_run,
        "min_failures": min_failures,
        "checked": len(accounts),
        "summary": {k: v for k, v in results.items() if k != "actions"},
        "actions": results["actions"],
    }


@api_router.post("/admin/reset-scrape-schedule")
async def admin_reset_scrape_schedule(request: Request, body: dict = None):
    """Reset next_scrape_at de toutes les campagnes pour appliquer immediatement
    le plan actuel de l'agence (utile apres changement de plan, trial activation, etc).

    body (optional) = {
      agency_id: '...',       # ne reset que les campagnes de cette agence
      campaign_id: '...',     # ne reset qu'une campagne specifique
      dry_run: bool (default true)
    }
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    body = body or {}
    dry_run = bool(body.get("dry_run", True))

    # Filtre campagnes
    q: dict = {"status": "active"}
    if body.get("agency_id"):
        q["agency_id"] = body["agency_id"]
    if body.get("campaign_id"):
        q["campaign_id"] = body["campaign_id"]
    campaigns = await db.campaigns.find(q, {"_id": 0}).to_list(500)
    if not campaigns:
        return {"ok": True, "checked": 0, "message": "Aucune campagne active trouvee"}

    # Pre-fetch les plans
    agency_ids = list({c.get("agency_id") for c in campaigns if c.get("agency_id")})
    agencies = await db.users.find(
        {"user_id": {"$in": agency_ids}},
        {"_id": 0}
    ).to_list(len(agency_ids)) if agency_ids else []
    agency_map = {a["user_id"]: a for a in agencies}

    now = datetime.now(timezone.utc)
    changes = []
    applied = 0
    for camp in campaigns:
        cid = camp["campaign_id"]
        agency = agency_map.get(camp.get("agency_id"))
        if not agency:
            continue
        limits = _get_plan_limits(agency)
        new_tpd = limits.get("tracking_per_day", 1)
        if camp.get("payment_model") == "clicks":
            new_interval_h = 24
        else:
            new_interval_h = _scrape_interval_hours(new_tpd)
        old_tpd = int(camp.get("tracking_per_day") or 0)
        old_next = camp.get("next_scrape_at")
        last_scrape = _parse_utc(camp.get("last_scraped_at"))
        new_next = _compute_next_scrape_at(cid, new_interval_h, last_scrape, new_tpd)

        if old_tpd != new_tpd or not old_next:
            changes.append({
                "campaign_id": cid,
                "campaign_name": camp.get("name"),
                "agency_id": camp.get("agency_id"),
                "old_tracking_per_day": old_tpd,
                "new_tracking_per_day": new_tpd,
                "old_next_scrape_at": old_next,
                "new_next_scrape_at": new_next.isoformat(),
            })
            if not dry_run:
                await db.campaigns.update_one(
                    {"campaign_id": cid},
                    {"$set": {
                        "next_scrape_at": new_next.isoformat(),
                        "tracking_per_day": new_tpd,
                        "scrape_interval_hours": new_interval_h,
                        "plan_reset_at": now.isoformat(),
                    }}
                )
                applied += 1

    return {
        "ok": True,
        "dry_run": dry_run,
        "campaigns_checked": len(campaigns),
        "changes_needed": len(changes),
        "applied": applied,
        "changes": changes[:50],
    }


@api_router.get("/admin/campaigns/{campaign_id}/accounts-debug")
async def admin_accounts_debug(campaign_id: str, request: Request):
    """Detail par compte d'une campagne (admin, pas de session user).
    Retourne pour chaque compte : status, last_scrape_error, consecutive_failures,
    last_existence_check_result, tracking_paused_until, n_videos, last_tracked_at.
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).to_list(2000)
    account_ids = [a["account_id"] for a in assignments]
    accounts = await db.social_accounts.find(
        {"account_id": {"$in": account_ids}},
        {"_id": 0}
    ).to_list(2000)

    # Videos par compte
    pipeline = [
        {"$match": {"campaign_id": campaign_id, "account_id": {"$in": account_ids}}},
        {"$group": {"_id": "$account_id", "n": {"$sum": 1}, "total_views": {"$sum": "$views"}}},
    ]
    video_stats = await db.tracked_videos.aggregate(pipeline).to_list(2000)
    vmap = {s["_id"]: s for s in video_stats}

    by_status: dict = {}
    by_display_status: dict = {}
    details = []
    now_iso = datetime.now(timezone.utc).isoformat()
    for a in accounts:
        st = a.get("status", "unknown")
        by_status[st] = by_status.get(st, 0) + 1
        vstat = vmap.get(a["account_id"], {"n": 0, "total_views": 0})

        # Calcul du status d'affichage (meme logique que last-scrape-details)
        platform = a.get("platform")
        username = a.get("username")
        last_tracked = a.get("last_tracked_at")
        paused_until = a.get("tracking_paused_until")
        status_acc = a.get("status", "verified")
        channel_id = a.get("platform_channel_id")
        # BUG FIX YouTube : lookup par username OU channel_id
        if platform == "youtube" and channel_id:
            last_scrape = await db.scraping_history.find_one(
                {"platform": platform, "username": {"$in": [username, channel_id]}},
                {"_id": 0, "success": 1, "video_count": 1, "source": 1, "error": 1, "timestamp": 1},
                sort=[("timestamp", -1)]
            )
        else:
            last_scrape = await db.scraping_history.find_one(
                {"platform": platform, "username": username},
                {"_id": 0, "success": 1, "video_count": 1, "source": 1, "error": 1, "timestamp": 1},
                sort=[("timestamp", -1)]
            )
        # PRIORITE verif active recente
        last_check_result = a.get("last_existence_check_result")
        last_check_at = a.get("last_existence_check_at")
        verif_says_exists_recent = False
        if last_check_result in ("exists", "exists_or_uncertain_recheck"):
            try:
                cdt = _parse_utc(last_check_at) if last_check_at else None
                if cdt and (datetime.now(timezone.utc) - cdt).total_seconds() < 24 * 3600:
                    verif_says_exists_recent = True
            except Exception:
                pass

        if status_acc == "deleted":
            disp = "deleted"
        elif paused_until and paused_until > now_iso:
            disp = "skipped_paused"
        elif not last_tracked:
            disp = "never_tried"
        elif last_scrape and last_scrape.get("success"):
            try:
                ts_dt = _parse_utc(last_scrape.get("timestamp"))
                if ts_dt and (datetime.now(timezone.utc) - ts_dt).total_seconds() < 36 * 3600:
                    disp = "ok"
                else:
                    disp = "skipped_cold"
            except Exception:
                disp = "ok"
        elif verif_says_exists_recent:
            disp = "ok"
        else:
            disp = "ko"
        by_display_status[disp] = by_display_status.get(disp, 0) + 1

        details.append({
            "account_id": a["account_id"],
            "platform": platform,
            "username": username,
            "db_status": status_acc,
            "display_status": disp,
            "last_tracked_at": last_tracked,
            "last_scrape_error": (a.get("last_scrape_error") or "")[:200],
            "error_message": (a.get("error_message") or "")[:200],
            "consecutive_failures": a.get("consecutive_failures") or 0,
            "tracking_paused_until": paused_until,
            "last_existence_check_at": a.get("last_existence_check_at"),
            "last_existence_check_result": a.get("last_existence_check_result"),
            "deleted_type": a.get("deleted_type"),
            "deleted_reason": (a.get("deleted_reason") or "")[:200],
            "verified_at": a.get("verified_at"),
            "last_scrape_success": (last_scrape or {}).get("success"),
            "last_scrape_source": (last_scrape or {}).get("source"),
            "last_scrape_error_msg": ((last_scrape or {}).get("error") or "")[:200],
            "last_scrape_video_count": (last_scrape or {}).get("video_count") or 0,
            "last_scrape_timestamp": (last_scrape or {}).get("timestamp"),
            "n_videos_in_db": vstat["n"],
            "total_views_in_db": vstat["total_views"],
        })

    return {
        "campaign_id": campaign_id,
        "campaign_name": campaign.get("name"),
        "total_accounts": len(accounts),
        "by_db_status": by_status,
        "by_display_status": by_display_status,
        "tracking_per_day": campaign.get("tracking_per_day"),
        "details": details,
    }


@api_router.get("/admin/campaigns/{campaign_id}/snapshots-debug")
async def admin_snapshots_debug(campaign_id: str, request: Request):
    """Debug : retourne les snapshots views_snapshots ET les aggregats video_views_snapshots
    pour cette campagne, par date. Permet de comprendre les ecarts."""
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")

    # 1. Daily snapshots (views_snapshots)
    daily_snaps = await db.views_snapshots.find(
        {"campaign_id": campaign_id},
        {"_id": 0, "date": 1, "total_views": 1, "total_videos": 1, "updated_at": 1, "recomputed_at": 1}
    ).sort("date", 1).to_list(100)

    # 2. Hourly snapshots
    hourly_snaps = await db.views_snapshots_hourly.find(
        {"campaign_id": campaign_id},
        {"_id": 0, "hour_key": 1, "total_views": 1, "scraped_at_paris": 1, "hour": 1, "minute": 1}
    ).sort("hour_key", -1).limit(20).to_list(20)

    # 3. Video views snapshots agreges par date
    video_agg = await db.video_views_snapshots.aggregate([
        {"$match": {"campaign_id": campaign_id}},
        {"$group": {
            "_id": "$date",
            "total_views": {"$sum": "$views"},
            "n_videos": {"$sum": 1},
        }},
        {"$sort": {"_id": 1}},
    ]).to_list(100)

    # 4. Live total
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if campaign:
        tracking_start = campaign.get("tracking_start_date") or campaign.get("created_at")
        assignments = await db.campaign_social_accounts.find(
            {"campaign_id": campaign_id}, {"_id": 0, "account_id": 1}
        ).to_list(2000)
        active_account_ids = [a["account_id"] for a in assignments if a.get("account_id")]
        live_total = 0
        if active_account_ids:
            match: dict = {"campaign_id": campaign_id, "account_id": {"$in": active_account_ids}}
            if tracking_start:
                match["published_at"] = {"$gte": tracking_start}
            agg = await db.tracked_videos.aggregate([
                {"$match": match},
                {"$group": {"_id": None, "total_views": {"$sum": "$views"}}}
            ]).to_list(1)
            live_total = int(agg[0]["total_views"]) if agg else 0
    else:
        live_total = 0
        tracking_start = None

    return {
        "campaign_id": campaign_id,
        "campaign_name": (campaign or {}).get("name"),
        "tracking_start_date": tracking_start,
        "live_total_views_now": live_total,
        "now_paris": datetime.now(timezone.utc).astimezone(PARIS_TZ).strftime("%Y-%m-%d %H:%M"),
        "today_paris": _today_paris_str(),
        "daily_snapshots": daily_snaps,
        "hourly_snapshots_recent": hourly_snaps,
        "video_aggregates_by_date": video_agg,
    }


@api_router.post("/admin/campaigns/{campaign_id}/reset-stats-history")
async def admin_reset_stats_history(campaign_id: str, request: Request, body: dict = None):
    """Wipe TOTAL de l'historique stats d'une campagne :
    - views_snapshots (daily)
    - views_snapshots_hourly
    - video_views_snapshots
    Puis cree 1 nouveau snapshot du jour avec live_total_views_now.

    Utile quand l'historique est corrompu (ex: bug de scraping qui a stocké
    des valeurs aberrantes une fois, et qui contamine la courbe pour toujours).

    body = { dry_run: bool (default true) }
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    body = body or {}
    dry_run = bool(body.get("dry_run", True))

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    # Calcule live_total_views_now (vraie valeur actuelle)
    tracking_start = campaign.get("tracking_start_date") or campaign.get("created_at")
    assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0, "account_id": 1}
    ).to_list(2000)
    active_account_ids = [a["account_id"] for a in assignments if a.get("account_id")]
    live_total = 0
    live_videos = 0
    if active_account_ids:
        match: dict = {"campaign_id": campaign_id, "account_id": {"$in": active_account_ids}}
        if tracking_start:
            match["published_at"] = {"$gte": tracking_start}
        agg = await db.tracked_videos.aggregate([
            {"$match": match},
            {"$group": {"_id": None, "total_views": {"$sum": "$views"}, "n_videos": {"$sum": 1}}}
        ]).to_list(1)
        if agg:
            live_total = int(agg[0]["total_views"])
            live_videos = int(agg[0]["n_videos"])

    # Comptage de ce qu'on va wiper (preview)
    n_daily = await db.views_snapshots.count_documents({"campaign_id": campaign_id})
    n_hourly = await db.views_snapshots_hourly.count_documents({"campaign_id": campaign_id})
    n_video = await db.video_views_snapshots.count_documents({"campaign_id": campaign_id})

    if dry_run:
        return {
            "ok": True,
            "dry_run": True,
            "campaign_id": campaign_id,
            "campaign_name": campaign.get("name"),
            "live_total_views_now": live_total,
            "live_videos_count": live_videos,
            "will_delete": {
                "daily_snapshots": n_daily,
                "hourly_snapshots": n_hourly,
                "video_views_snapshots": n_video,
            },
            "after_reset": {
                "new_snap_today": {
                    "date": _today_paris_str(),
                    "total_views": live_total,
                },
                "courbe_apres_reset": "Vues d'aujourd'hui = total live (215K dans le cas de Check Marcus). Demain, delta = nouveau total - 215K.",
            },
            "note": "DRY RUN. Relancer avec dry_run=false pour wiper.",
        }

    # Apply : delete tout + cree snap[today] avec live
    now_iso = datetime.now(timezone.utc).isoformat()
    today_str = _today_paris_str()
    res_daily = await db.views_snapshots.delete_many({"campaign_id": campaign_id})
    res_hourly = await db.views_snapshots_hourly.delete_many({"campaign_id": campaign_id})
    res_video = await db.video_views_snapshots.delete_many({"campaign_id": campaign_id})
    await db.views_snapshots.insert_one({
        "campaign_id": campaign_id,
        "date": today_str,
        "total_views": live_total,
        "total_videos": live_videos,
        "updated_at": now_iso,
        "reset_at": now_iso,
        "reset_source": "admin_reset_stats_history",
    })
    logger.warning(f"🗑️ RESET STATS HISTORY : {campaign_id} ({campaign.get('name')}) — wiped {res_daily.deleted_count} daily + {res_hourly.deleted_count} hourly + {res_video.deleted_count} video snapshots. New snap[{today_str}]={live_total}")
    return {
        "ok": True,
        "dry_run": False,
        "campaign_id": campaign_id,
        "campaign_name": campaign.get("name"),
        "deleted": {
            "daily_snapshots": res_daily.deleted_count,
            "hourly_snapshots": res_hourly.deleted_count,
            "video_views_snapshots": res_video.deleted_count,
        },
        "new_snap_today": {
            "date": today_str,
            "total_views": live_total,
            "total_videos": live_videos,
        },
        "message": f"Historique wipé. Aujourd'hui = {live_total:,} vues. Demain, le delta sera correct.",
    }


@api_router.post("/admin/recheck-failing-accounts")
async def admin_recheck_failing(request: Request, body: dict = None):
    """Re-verifie ACTIVEMENT les comptes status=verified mais qui ECHOUENT au scrape
    (consecutive_failures >= 1 OU tracking_paused_until set). Pour chacun :
    - Si verif active confirme 'deleted' (2+ sources) -> passe en status='deleted'
    - Si verif dit 'exists' -> reset consecutive_failures + tracking_paused_until
    - Si verif uncertain -> reset pause seulement (laisse verified)

    Aussi : pour les comptes status='error', meme logique.

    body = { campaign_id?, dry_run (default true) }
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    body = body or {}
    dry_run = bool(body.get("dry_run", True))
    cid_filter = body.get("campaign_id")

    # Filtre : comptes en echec mais pas encore deleted.
    # Inclut TOUS les status=error (meme sans consec) ET les verified avec failures.
    query: dict = {
        "$or": [
            {"status": "error"},
            {"$and": [
                {"status": "verified"},
                {"$or": [
                    {"consecutive_failures": {"$gte": 1}},
                    {"tracking_paused_until": {"$exists": True, "$ne": None}},
                ]}
            ]}
        ]
    }
    if cid_filter:
        assignments = await db.campaign_social_accounts.find(
            {"campaign_id": cid_filter}, {"_id": 0, "account_id": 1}
        ).to_list(2000)
        ids = [a["account_id"] for a in assignments if a.get("account_id")]
        query["account_id"] = {"$in": ids}

    accounts = await db.social_accounts.find(query, {"_id": 0}).limit(300).to_list(300)

    results = {"marked_deleted": [], "restored_alive": [], "reset_pause_only": [], "errors": []}
    now_iso = datetime.now(timezone.utc).isoformat()

    for acc in accounts:
        platform = acc.get("platform")
        username = acc.get("username") or ""
        account_id = acc.get("account_id")
        check_target = acc.get("platform_channel_id") if platform == "youtube" else username
        try:
            exists = await asyncio.wait_for(
                _verify_account_still_exists(platform, check_target or username), timeout=30
            )
        except Exception as ex:
            results["errors"].append({"username": username, "platform": platform, "error": str(ex)[:100]})
            continue

        entry = {"account_id": account_id, "platform": platform, "username": username,
                 "old_status": acc.get("status"), "old_consec": acc.get("consecutive_failures") or 0,
                 "verif": "exists" if exists is True else "deleted" if exists is False else "uncertain"}

        # Cas 1 : verif confirme deleted (2 sources)
        if exists is False:
            # Securite : si videos en DB, on ne marque pas deleted (faux positif possible)
            n_videos = await db.tracked_videos.count_documents({"account_id": account_id})
            if n_videos > 0:
                entry["note"] = f"verif=deleted MAIS {n_videos} videos en DB -> on garde verified"
                results["reset_pause_only"].append(entry)
                if not dry_run:
                    await db.social_accounts.update_one(
                        {"account_id": account_id},
                        {"$set": {
                            "consecutive_failures": 0,
                            "tracking_paused_until": None,
                            "last_existence_check_at": now_iso,
                            "last_existence_check_result": "uncertain_has_videos",
                        }}
                    )
            else:
                entry["note"] = "verif=deleted (2 sources) + 0 video DB -> marque deleted"
                results["marked_deleted"].append(entry)
                if not dry_run:
                    await db.social_accounts.update_one(
                        {"account_id": account_id},
                        {"$set": {
                            "status": "deleted",
                            "deleted_at": now_iso,
                            "deleted_type": "confirmed_after_failures",
                            "deleted_reason": "Verif active (2 sources) confirme introuvable + 0 video historique",
                            "last_existence_check_at": now_iso,
                            "last_existence_check_result": "deleted",
                            "not_found_count": 99,
                        }}
                    )
        elif exists is True:
            entry["note"] = "verif=exists -> reset failures + pause"
            results["restored_alive"].append(entry)
            if not dry_run:
                await db.social_accounts.update_one(
                    {"account_id": account_id},
                    {"$set": {
                        "status": "verified",
                        "consecutive_failures": 0,
                        "tracking_paused_until": None,
                        "last_existence_check_at": now_iso,
                        "last_existence_check_result": "exists",
                        "error_message": None,
                    }}
                )
        else:
            entry["note"] = "verif=uncertain -> reset pause uniquement"
            results["reset_pause_only"].append(entry)
            if not dry_run:
                await db.social_accounts.update_one(
                    {"account_id": account_id},
                    {"$set": {
                        "tracking_paused_until": None,
                        "last_existence_check_at": now_iso,
                        "last_existence_check_result": "uncertain",
                    }}
                )
        await asyncio.sleep(0.4)

    return {
        "ok": True,
        "dry_run": dry_run,
        "checked": len(accounts),
        "summary": {
            "marked_deleted": len(results["marked_deleted"]),
            "restored_alive": len(results["restored_alive"]),
            "reset_pause_only": len(results["reset_pause_only"]),
            "errors": len(results["errors"]),
        },
        "details": results,
    }


@api_router.post("/admin/recheck-deleted-accounts")
async def admin_recheck_deleted(request: Request, body: dict = None):
    """Re-verifie ACTIVEMENT (2 sources) tous les comptes marques deleted/error
    et restore en 'verified' tous ceux dont la verif renvoie 'exists' OU 'uncertain'.
    Seuls les comptes confirmes deleted (2+ sources disent 404) restent deleted.

    body = {
      campaign_id: str (optional, filtre),
      dry_run: bool (default true),
      max_to_check: int (default 200, anti-overload)
    }
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    body = body or {}
    dry_run = bool(body.get("dry_run", True))
    max_to_check = int(body.get("max_to_check", 200))
    cid_filter = body.get("campaign_id")

    # Liste les comptes deleted/error a re-verifier
    query: dict = {"status": {"$in": ["deleted", "error"]}}
    if cid_filter:
        # Filtre via campaign_social_accounts
        assignments = await db.campaign_social_accounts.find(
            {"campaign_id": cid_filter}, {"_id": 0, "account_id": 1}
        ).to_list(2000)
        ids = [a["account_id"] for a in assignments if a.get("account_id")]
        query["account_id"] = {"$in": ids}
    accounts = await db.social_accounts.find(query, {"_id": 0}).limit(max_to_check).to_list(max_to_check)

    results = {"exists": [], "uncertain": [], "confirmed_deleted": [], "errors": []}
    for acc in accounts:
        platform = acc.get("platform")
        username = acc.get("username") or ""
        account_id = acc.get("account_id")
        check_target = acc.get("platform_channel_id") if platform == "youtube" else username
        try:
            exists = await asyncio.wait_for(
                _verify_account_still_exists(platform, check_target or username), timeout=30
            )
        except Exception as ex:
            results["errors"].append({"account_id": account_id, "username": username, "error": str(ex)[:100]})
            continue

        entry = {
            "account_id": account_id,
            "platform": platform,
            "username": username,
            "old_status": acc.get("status"),
            "verif_result": "exists" if exists is True else "deleted" if exists is False else "uncertain",
        }
        if exists is True:
            results["exists"].append(entry)
        elif exists is False:
            results["confirmed_deleted"].append(entry)
        else:
            results["uncertain"].append(entry)
        await asyncio.sleep(0.5)  # anti-spam plateformes

    if dry_run:
        return {
            "ok": True,
            "dry_run": True,
            "checked": len(accounts),
            "summary": {
                "would_restore_exists": len(results["exists"]),
                "would_restore_uncertain": len(results["uncertain"]),
                "stay_deleted_confirmed": len(results["confirmed_deleted"]),
                "errors": len(results["errors"]),
            },
            "samples": {
                "exists": results["exists"][:10],
                "uncertain": results["uncertain"][:10],
                "confirmed_deleted": results["confirmed_deleted"][:10],
            },
        }

    # Apply : restore exists + uncertain
    now_iso = datetime.now(timezone.utc).isoformat()
    to_restore = [r["account_id"] for r in results["exists"] + results["uncertain"]]
    if to_restore:
        await db.social_accounts.update_many(
            {"account_id": {"$in": to_restore}},
            {"$set": {
                "status": "verified",
                "consecutive_failures": 0,
                "tracking_paused_until": None,
                "not_found_count": 0,
                "last_existence_check_at": now_iso,
                "last_existence_check_result": "exists_or_uncertain_recheck",
                "deleted_at": None,
                "deleted_reason": None,
                "deleted_type": None,
                "error_message": None,
                "restored_at": now_iso,
                "restored_reason": "admin_recheck_deleted_returned_exists_or_uncertain",
            }}
        )
        logger.warning(f"🔄 RECHECK : {len(to_restore)} comptes restaures (verif active a confirme existence ou uncertain)")
    return {
        "ok": True,
        "dry_run": False,
        "checked": len(accounts),
        "restored_count": len(to_restore),
        "summary": {
            "restored_exists": len(results["exists"]),
            "restored_uncertain": len(results["uncertain"]),
            "stay_deleted_confirmed": len(results["confirmed_deleted"]),
            "errors": len(results["errors"]),
        },
    }


@api_router.get("/admin/health-summary")
async def admin_health_summary(request: Request):
    """Dashboard sante du systeme de scraping.
    Vue d'ensemble en 1 endpoint : que se passe-t-il MAINTENANT ?
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")

    now = datetime.now(timezone.utc)
    now_paris = now.astimezone(PARIS_TZ)
    h24_ago = (now - timedelta(hours=24)).isoformat()
    h1_ago = (now - timedelta(hours=1)).isoformat()

    # Campagnes actives
    campaigns = await db.campaigns.find({"status": "active"}, {"_id": 0}).to_list(500)
    n_camps = len(campaigns)
    # Prochain scrape global
    next_at_list = [c.get("next_scrape_at") for c in campaigns if c.get("next_scrape_at")]
    next_at_global = min(next_at_list) if next_at_list else None
    # Dernier scrape global
    last_scraped_list = [c.get("last_scraped_at") for c in campaigns if c.get("last_scraped_at")]
    last_scraped_global = max(last_scraped_list) if last_scraped_list else None

    # Comptes
    n_total = await db.social_accounts.count_documents({})
    n_verified = await db.social_accounts.count_documents({"status": "verified"})
    n_deleted = await db.social_accounts.count_documents({"status": "deleted"})
    n_error = await db.social_accounts.count_documents({"status": "error"})
    n_pending = await db.social_accounts.count_documents({"status": "pending"})
    n_paused = await db.social_accounts.count_documents({
        "status": "verified",
        "tracking_paused_until": {"$gt": now.isoformat()}
    })
    n_with_failures = await db.social_accounts.count_documents({
        "status": "verified",
        "consecutive_failures": {"$gte": 1}
    })

    # Scrapes derniere 24h
    n_scrapes_24h = await db.scraping_history.count_documents({"timestamp": {"$gte": h24_ago}})
    n_scrapes_24h_ok = await db.scraping_history.count_documents({"timestamp": {"$gte": h24_ago}, "success": True})
    n_scrapes_24h_ko = n_scrapes_24h - n_scrapes_24h_ok
    success_rate_24h = round(100 * n_scrapes_24h_ok / n_scrapes_24h, 1) if n_scrapes_24h else 0

    # Sources utilisees derniere 24h
    sources_agg = await db.scraping_history.aggregate([
        {"$match": {"timestamp": {"$gte": h24_ago}}},
        {"$group": {"_id": {"source": "$source", "success": "$success"}, "count": {"$sum": 1}}},
        {"$sort": {"count": -1}},
    ]).to_list(50)
    by_source = {}
    for s in sources_agg:
        src = s["_id"]["source"]
        ok = s["_id"]["success"]
        by_source.setdefault(src, {"ok": 0, "ko": 0})
        by_source[src]["ok" if ok else "ko"] += s["count"]

    # Tracked videos
    n_videos = await db.tracked_videos.count_documents({})
    agg_total = await db.tracked_videos.aggregate([
        {"$group": {"_id": None, "total_views": {"$sum": "$views"}}}
    ]).to_list(1)
    total_views = agg_total[0]["total_views"] if agg_total else 0

    # Diagnostic
    issues = []
    if n_camps == 0:
        issues.append("CRITIQUE : aucune campagne active")
    if not last_scraped_global:
        issues.append("CRITIQUE : aucun scrape jamais effectue")
    elif last_scraped_global < h24_ago:
        issues.append(f"WARNING : dernier scrape > 24h ({last_scraped_global})")
    if success_rate_24h < 50 and n_scrapes_24h > 10:
        issues.append(f"WARNING : taux reussite faible ({success_rate_24h}%) sur 24h")
    if n_paused > n_verified * 0.3:
        issues.append(f"WARNING : >30% des comptes sont en pause ({n_paused}/{n_verified})")

    return {
        "now_utc": now.isoformat(),
        "now_paris": now_paris.strftime("%Y-%m-%d %H:%M:%S"),
        "campaigns": {
            "active": n_camps,
            "last_scraped_global": last_scraped_global,
            "next_scrape_global": next_at_global,
        },
        "accounts": {
            "total": n_total,
            "verified": n_verified,
            "with_failures": n_with_failures,
            "paused_auto": n_paused,
            "deleted": n_deleted,
            "error": n_error,
            "pending": n_pending,
        },
        "tracked_videos": {
            "count": n_videos,
            "total_views_all_campaigns": total_views,
        },
        "scraping_24h": {
            "total_attempts": n_scrapes_24h,
            "success": n_scrapes_24h_ok,
            "failed": n_scrapes_24h_ko,
            "success_rate_pct": success_rate_24h,
            "by_source": by_source,
        },
        "issues": issues if issues else ["OK"],
    }


@api_router.post("/admin/restore-false-positives")
async def admin_restore_false_positives(request: Request, body: dict = None):
    """Restaure les comptes marques 'deleted' ou 'error' alors qu'ils ont
    deja des videos en DB (preuve qu'ils existent/existaient).

    body = {
      dry_run: bool (default true),
      campaign_id: str (optional, filtre par campagne)
    }
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    body = body or {}
    dry_run = bool(body.get("dry_run", True))
    cid_filter = body.get("campaign_id")

    # 1. Trouve tous les comptes deleted ou error
    query: dict = {"status": {"$in": ["deleted", "error"]}}
    accounts = await db.social_accounts.find(query, {"_id": 0}).to_list(5000)

    to_restore = []
    for acc in accounts:
        # Si le compte a des videos en DB, c'est forcement un faux positif
        video_filter = {"account_id": acc["account_id"]}
        if cid_filter:
            video_filter["campaign_id"] = cid_filter
        n_videos = await db.tracked_videos.count_documents(video_filter)
        if n_videos > 0:
            to_restore.append({
                "account_id": acc["account_id"],
                "platform": acc.get("platform"),
                "username": acc.get("username"),
                "old_status": acc.get("status"),
                "deleted_reason": acc.get("deleted_reason"),
                "videos_count": n_videos,
            })

    if dry_run:
        return {
            "ok": True,
            "dry_run": True,
            "count": len(to_restore),
            "to_restore": to_restore[:50],
            "note": f"{len(to_restore)} comptes vont etre restaures (ils ont des videos historiques). Relancer avec dry_run=false pour appliquer.",
        }

    # Apply
    now_iso = datetime.now(timezone.utc).isoformat()
    restored_ids = [a["account_id"] for a in to_restore]
    if restored_ids:
        await db.social_accounts.update_many(
            {"account_id": {"$in": restored_ids}},
            {"$set": {
                "status": "verified",
                "consecutive_failures": 0,
                "tracking_paused_until": None,
                "not_found_count": 0,
                "last_existence_check_at": None,
                "last_existence_check_result": None,
                "deleted_at": None,
                "deleted_reason": None,
                "deleted_type": None,
                "error_message": None,
                "restored_at": now_iso,
                "restored_reason": "false_positive_had_videos_in_db",
            }}
        )
        logger.warning(f"🔄 RESTORE FALSE POSITIVES : {len(restored_ids)} comptes restaures (avaient des videos en DB)")
    return {
        "ok": True,
        "dry_run": False,
        "restored_count": len(restored_ids),
        "restored_accounts": to_restore,
    }


@api_router.post("/admin/recompute-snapshots")
async def admin_recompute_snapshots(request: Request, body: dict = None):
    """Recalcule TOUS les snapshots quotidiens des campagnes a partir de la source
    de verite : video_views_snapshots (qui stocke les vues par video par jour).

    Corrige les chiffres historiques incoherents (ex: "hier" qui change d'un
    jour a l'autre) en repartant du detail par video.

    body (optional) = {
      campaign_id: '...',   # si fourni, ne recalcule que cette campagne
      dry_run: true/false   # default true (preview uniquement)
    }
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    body = body or {}
    campaign_filter = body.get("campaign_id")
    dry_run = bool(body.get("dry_run", True))

    # Liste les campagnes a traiter
    if campaign_filter:
        campaigns = await db.campaigns.find({"campaign_id": campaign_filter}, {"_id": 0, "campaign_id": 1, "name": 1}).to_list(5)
    else:
        campaigns = await db.campaigns.find({}, {"_id": 0, "campaign_id": 1, "name": 1}).to_list(500)

    summary = {"campaigns_processed": 0, "snapshots_recomputed": 0, "snapshots_unchanged": 0, "details": []}
    for camp in campaigns:
        cid = camp["campaign_id"]
        # Pour chaque date distincte dans video_views_snapshots, calcule la somme des vues
        # par video pour cette campagne, ce jour-la.
        agg = await db.video_views_snapshots.aggregate([
            {"$match": {"campaign_id": cid}},
            {"$group": {
                "_id": "$date",
                "total_views": {"$sum": "$views"},
                "total_likes": {"$sum": "$likes"},
                "total_comments": {"$sum": "$comments"},
                "n_videos": {"$sum": 1},
            }},
            {"$sort": {"_id": 1}},
        ]).to_list(1000)

        if not agg:
            continue

        campaign_changes = 0
        for daily in agg:
            date_str = daily["_id"]
            if not date_str:
                continue
            new_total = int(daily.get("total_views") or 0)
            new_likes = int(daily.get("total_likes") or 0)
            new_comments = int(daily.get("total_comments") or 0)
            new_videos = int(daily.get("n_videos") or 0)

            # Compare avec l'existant
            existing = await db.views_snapshots.find_one(
                {"campaign_id": cid, "date": date_str},
                {"_id": 0, "total_views": 1}
            )
            old_total = int((existing or {}).get("total_views") or 0)

            if old_total == new_total:
                summary["snapshots_unchanged"] += 1
                continue

            campaign_changes += 1
            summary["snapshots_recomputed"] += 1
            summary["details"].append({
                "campaign_id": cid,
                "campaign_name": camp.get("name"),
                "date": date_str,
                "old_total_views": old_total,
                "new_total_views": new_total,
                "diff": new_total - old_total,
            })

            if not dry_run:
                await db.views_snapshots.update_one(
                    {"campaign_id": cid, "date": date_str},
                    {"$set": {
                        "campaign_id": cid,
                        "date": date_str,
                        "total_views": new_total,
                        "total_likes": new_likes,
                        "total_comments": new_comments,
                        "total_videos": new_videos,
                        "recomputed_at": datetime.now(timezone.utc).isoformat(),
                        "recomputed_source": "video_views_snapshots",
                    }},
                    upsert=True,
                )

        if campaign_changes > 0:
            summary["campaigns_processed"] += 1
            if not dry_run:
                logger.warning(f"📊 RECOMPUTE snapshots : {campaign_changes} changements pour campagne {cid}")

    return {
        "ok": True,
        "dry_run": dry_run,
        "summary": {
            "campaigns_processed": summary["campaigns_processed"],
            "snapshots_recomputed": summary["snapshots_recomputed"],
            "snapshots_unchanged": summary["snapshots_unchanged"],
        },
        "sample_changes": summary["details"][:30],
        "note": (
            "DRY RUN : aucune modification. Relancer avec dry_run=false pour appliquer."
            if dry_run else
            f"{summary['snapshots_recomputed']} snapshots recomputed."
        ),
    }


@api_router.get("/admin/click-fraud-report")
async def admin_click_fraud_report(request: Request, hours: int = 24):
    """Rapport anti-fraude des clics sur les dernieres N heures.
    Liste : clicks suspects, top IPs suspects, top CIDR /24 suspects, top user agents bots.
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    cutoff = (datetime.now(timezone.utc) - timedelta(hours=hours)).isoformat()

    # Stats globales clics dans la fenetre
    total_clicks = await db.click_events.count_documents({"clicked_at": {"$gte": cutoff}})
    suspect_clicks = await db.click_events.count_documents({"clicked_at": {"$gte": cutoff}, "is_suspect": True})
    billable_clicks = await db.click_events.count_documents({"clicked_at": {"$gte": cutoff}, "billable": True})

    # Top IPs suspectes
    top_suspect_ips = await db.click_events.aggregate([
        {"$match": {"clicked_at": {"$gte": cutoff}, "is_suspect": True}},
        {"$group": {
            "_id": "$ip_hash",
            "count": {"$sum": 1},
            "reasons": {"$addToSet": "$suspect_reasons"},
            "campaigns": {"$addToSet": "$campaign_id"},
            "clippers": {"$addToSet": "$clipper_id"},
        }},
        {"$sort": {"count": -1}},
        {"$limit": 20},
    ]).to_list(20)

    # Top CIDR /24 (bursts reseau)
    top_cidr_bursts = await db.click_events.aggregate([
        {"$match": {"clicked_at": {"$gte": cutoff}, "cidr24_hash": {"$exists": True, "$ne": ""}}},
        {"$group": {
            "_id": "$cidr24_hash",
            "total_clicks": {"$sum": 1},
            "suspect_clicks": {"$sum": {"$cond": ["$is_suspect", 1, 0]}},
            "unique_links": {"$addToSet": "$link_id"},
            "campaigns": {"$addToSet": "$campaign_id"},
        }},
        {"$match": {"total_clicks": {"$gte": 10}}},
        {"$sort": {"total_clicks": -1}},
        {"$limit": 20},
    ]).to_list(20)

    # Top user agents bots
    top_bot_uas = await db.click_events.aggregate([
        {"$match": {
            "clicked_at": {"$gte": cutoff},
            "is_suspect": True,
            "suspect_reasons": {"$regex": "bot:"},
        }},
        {"$group": {
            "_id": "$user_agent",
            "count": {"$sum": 1},
        }},
        {"$sort": {"count": -1}},
        {"$limit": 15},
    ]).to_list(15)

    # Top clippers avec ratio suspect eleve
    clippers_stats = await db.click_events.aggregate([
        {"$match": {"clicked_at": {"$gte": cutoff}}},
        {"$group": {
            "_id": "$clipper_id",
            "total": {"$sum": 1},
            "suspect": {"$sum": {"$cond": ["$is_suspect", 1, 0]}},
        }},
        {"$match": {"total": {"$gte": 5}}},
        {"$addFields": {"suspect_ratio": {"$divide": ["$suspect", "$total"]}}},
        {"$sort": {"suspect_ratio": -1}},
        {"$limit": 20},
    ]).to_list(20)

    return {
        "window_hours": hours,
        "totals": {
            "total_clicks": total_clicks,
            "suspect_clicks": suspect_clicks,
            "billable_clicks": billable_clicks,
            "suspect_ratio": round(suspect_clicks / total_clicks, 3) if total_clicks else 0,
        },
        "top_suspect_ips": [
            {"ip_hash_prefix": (x["_id"] or "")[:16], "count": x["count"], "reasons": x["reasons"][:5], "campaigns": x["campaigns"], "clippers": x["clippers"]}
            for x in top_suspect_ips
        ],
        "top_cidr_bursts": [
            {
                "cidr24_prefix": (x["_id"] or "")[:16],
                "total_clicks": x["total_clicks"],
                "suspect_clicks": x["suspect_clicks"],
                "unique_links_targeted": len(x["unique_links"]),
                "campaigns": x["campaigns"],
            }
            for x in top_cidr_bursts
        ],
        "top_bot_user_agents": [
            {"user_agent": (x["_id"] or "")[:100], "count": x["count"]}
            for x in top_bot_uas
        ],
        "suspect_clippers": [
            {"clipper_id": x["_id"], "total_clicks": x["total"], "suspect_clicks": x["suspect"], "suspect_ratio": round(x["suspect_ratio"], 3)}
            for x in clippers_stats
        ],
    }


@api_router.post("/admin/click-events/invalidate-by-pattern")
async def admin_invalidate_clicks_by_pattern(request: Request, body: dict):
    """Invalide retroactivement des clicks selon un pattern, recalcule les earnings.
    body = {
      campaign_id?: str,
      clipper_id?: str,
      ip_hash?: str,
      cidr24_hash?: str,
      since?: iso datetime,
      dry_run: bool (default true)
    }
    Filtres se combinent en AND. Marque is_suspect=True, billable=False.
    Decrement les compteurs unique_click_count sur click_links + recalc earnings.
    """
    code = request.query_params.get("code") or request.headers.get("X-Admin-Code", "")
    if not code or not hmac.compare_digest(code, ADMIN_SECRET_CODE):
        raise HTTPException(status_code=403, detail="Code admin invalide")
    dry_run = bool(body.get("dry_run", True))

    # Build filter
    q: dict = {"is_suspect": {"$ne": True}}  # ne touche pas aux deja-suspect
    for k in ("campaign_id", "clipper_id", "ip_hash", "cidr24_hash", "link_id"):
        if body.get(k):
            q[k] = body[k]
    if body.get("since"):
        q["clicked_at"] = {"$gte": body["since"]}
    if len([k for k in q.keys() if k not in ("is_suspect", "clicked_at")]) == 0:
        raise HTTPException(status_code=400, detail="Au moins un filtre requis (campaign_id, clipper_id, ip_hash, cidr24_hash, ou link_id)")

    # Trouve les events impactes
    events = await db.click_events.find(q, {"_id": 0, "event_id": 1, "link_id": 1, "is_unique": 1, "campaign_id": 1}).to_list(10000)

    if dry_run:
        # Compte par link les unique a decrementer
        unique_per_link = {}
        for e in events:
            if e.get("is_unique"):
                unique_per_link[e["link_id"]] = unique_per_link.get(e["link_id"], 0) + 1
        return {
            "ok": True,
            "dry_run": True,
            "would_invalidate": len(events),
            "unique_per_link": unique_per_link,
            "filter": {k: v for k, v in q.items() if k != "is_suspect"},
        }

    # Apply : marque suspect + recompte les compteurs
    now_iso = datetime.now(timezone.utc).isoformat()
    await db.click_events.update_many(
        q,
        {"$set": {
            "is_suspect": True,
            "billable": False,
            "suspect_reasons": ["admin_invalidated"],
            "invalidated_at": now_iso,
        }}
    )

    # Recompte les counters par link
    affected_link_ids = list({e["link_id"] for e in events if e.get("link_id")})
    for lid in affected_link_ids:
        # Recompte depuis les events (source de verite)
        billable_count = await db.click_events.count_documents({"link_id": lid, "billable": True})
        all_count = await db.click_events.count_documents({"link_id": lid})
        suspect_count = await db.click_events.count_documents({"link_id": lid, "is_suspect": True})
        link = await db.click_links.find_one({"link_id": lid}, {"_id": 0})
        if link:
            campaign = await db.campaigns.find_one({"campaign_id": link["campaign_id"]}, {"_id": 0})
            rate = (campaign or {}).get("rate_per_click", 0)
            earnings = round((billable_count / 1000) * rate, 4)
            await db.click_links.update_one(
                {"link_id": lid},
                {"$set": {
                    "unique_click_count": billable_count,
                    "click_count": all_count,
                    "suspect_count": suspect_count,
                    "earnings": earnings,
                    "last_recompute_at": now_iso,
                }}
            )

    logger.warning(f"🔒 ADMIN INVALIDATE : {len(events)} clics marques suspect, {len(affected_link_ids)} liens recalcules")
    return {
        "ok": True,
        "dry_run": False,
        "invalidated_count": len(events),
        "affected_links": affected_link_ids,
    }


@api_router.post("/admin/force-scrape-all")
async def admin_force_scrape_all(request: Request):
    """Force IMMEDIATEMENT un scrape de TOUTES les campagnes actives.
    Ignore les next_scrape_at. A utiliser pour rattraper un scrape rate.
    """
    await verify_admin_code(request)
    if _TRACKING_RUN_LOCK.locked():
        return {
            "ok": False,
            "error": "Un scrape est deja en cours, attendre la fin (ou re-essayer dans 5 min).",
        }
    # Lance en background, ne bloque pas la response
    async def _do_force():
        async with _TRACKING_RUN_LOCK:
            try:
                await run_video_tracking(force_all=True)
            except Exception as e:
                logger.error(f"force-scrape-all error: {type(e).__name__}: {e}", exc_info=True)
    asyncio.create_task(_do_force())
    return {
        "ok": True,
        "message": "Scrape force lance en arriere-plan (toutes campagnes actives). Voir logs Railway pour suivre.",
    }


@api_router.get("/debug/tikwm/{username}")
async def debug_tikwm(username: str):
    """Debug endpoint: tests all TikWm strategies for a TikTok username. No auth required."""
    username = username.lstrip("@")
    result = {"tikwm_api_key_configured": bool(TIKWM_API_KEY)}

    HEADERS = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36",
        "Accept": "application/json, text/plain, */*",
        "Origin": "https://www.tikwm.com",
        "Referer": "https://www.tikwm.com/",
    }

    def _trim_body(body):
        if isinstance(body, dict) and isinstance(body.get("data"), dict):
            vids = body["data"].get("videos") or []
            body["data"]["videos_sample"] = vids[:2]
            body["data"]["videos_count"] = len(vids)
            body["data"].pop("videos", None)
        return body

    async with httpx.AsyncClient(timeout=20, follow_redirects=True) as c:
        # Test 1: user info
        try:
            r = await c.get("https://www.tikwm.com/api/user/info",
                params={"unique_id": username}, headers=HEADERS)
            result["user_info"] = {"http_status": r.status_code,
                "body": r.json() if r.status_code == 200 else r.text[:300]}
        except Exception as e:
            result["user_info"] = {"error": str(e)}

        # Test 2: GET no-key
        try:
            r = await c.get("https://www.tikwm.com/api/user/posts",
                params={"unique_id": username, "count": 10, "cursor": 0}, headers=HEADERS)
            body = r.json() if r.status_code == 200 else r.text[:300]
            result["posts_get_nokey"] = {"http_status": r.status_code, "body": _trim_body(body) if r.status_code == 200 else body}
        except Exception as e:
            result["posts_get_nokey"] = {"error": str(e)}

        # Test 3: GET with API key (if configured)
        if TIKWM_API_KEY:
            try:
                r = await c.get("https://www.tikwm.com/api/user/posts",
                    params={"unique_id": username, "count": 10, "cursor": 0, "key": TIKWM_API_KEY}, headers=HEADERS)
                body = r.json() if r.status_code == 200 else r.text[:300]
                result["posts_get_key"] = {"http_status": r.status_code, "body": _trim_body(body) if r.status_code == 200 else body}
            except Exception as e:
                result["posts_get_key"] = {"error": str(e)}

        # Test 4: POST form-encoded
        try:
            post_data = {"unique_id": username, "count": "10", "cursor": "0"}
            if TIKWM_API_KEY:
                post_data["key"] = TIKWM_API_KEY
            r = await c.post("https://www.tikwm.com/api/user/posts",
                data=post_data,
                headers={**HEADERS, "Content-Type": "application/x-www-form-urlencoded"})
            body = r.json() if r.status_code == 200 else r.text[:300]
            result["posts_post_form"] = {"http_status": r.status_code, "body": _trim_body(body) if r.status_code == 200 else body}
        except Exception as e:
            result["posts_post_form"] = {"error": str(e)}

        # Test 5: GET with web=1
        try:
            r = await c.get("https://www.tikwm.com/api/user/posts",
                params={"unique_id": username, "count": 10, "cursor": 0, "web": 1, "hd": 1}, headers=HEADERS)
            body = r.json() if r.status_code == 200 else r.text[:300]
            result["posts_get_web1"] = {"http_status": r.status_code, "body": _trim_body(body) if r.status_code == 200 else body}
        except Exception as e:
            result["posts_get_web1"] = {"error": str(e)}

        # Test 6: feed search type=0 (videos)
        try:
            r = await c.get("https://www.tikwm.com/api/feed/search",
                params={"keywords": username, "count": 20, "cursor": 0, "type": 0}, headers=HEADERS)
            body = r.json() if r.status_code == 200 else r.text[:300]
            if isinstance(body, dict) and isinstance(body.get("data"), dict):
                items = body["data"].get("videos") or body["data"].get("data") or []
                result["feed_search_type0"] = {
                    "http_status": r.status_code,
                    "code": body.get("code"),
                    "data_keys": list(body["data"].keys()),
                    "items_count": len(items),
                    "first_item_author": (items[0].get("author") or {}).get("unique_id") if items else None,
                    "has_more": body["data"].get("hasMore"),
                    "cursor": body["data"].get("cursor"),
                }
            else:
                result["feed_search_type0"] = {"http_status": r.status_code, "body_snippet": str(body)[:300]}
        except Exception as e:
            result["feed_search_type0"] = {"error": str(e)}

        # Test 7: feed search type=1 (user)
        try:
            r = await c.get("https://www.tikwm.com/api/feed/search",
                params={"keywords": username, "count": 20, "cursor": 0, "type": 1}, headers=HEADERS)
            body = r.json() if r.status_code == 200 else r.text[:300]
            if isinstance(body, dict) and isinstance(body.get("data"), dict):
                items = body["data"].get("videos") or body["data"].get("data") or []
                result["feed_search_type1"] = {
                    "http_status": r.status_code,
                    "code": body.get("code"),
                    "data_keys": list(body["data"].keys()),
                    "items_count": len(items),
                    "first_item_author": (items[0].get("author") or {}).get("unique_id") if items else None,
                    "has_more": body["data"].get("hasMore"),
                    "cursor": body["data"].get("cursor"),
                }
            else:
                result["feed_search_type1"] = {"http_status": r.status_code, "body_snippet": str(body)[:300]}
        except Exception as e:
            result["feed_search_type1"] = {"error": str(e)}

    # Also run the full _fetch_tiktok_tikwm function (TikWm strategies only)
    try:
        videos = await _fetch_tiktok_tikwm(username)
        result["_fetch_tiktok_tikwm_result"] = {
            "videos_found": len(videos),
            "sample": videos[:2] if videos else [],
        }
    except Exception as e:
        result["_fetch_tiktok_tikwm_result"] = {"error": str(e)}

    # Test TikTok mobile API (uses numeric user_id from user_info)
    user_id_from_info = None
    try:
        ui = result.get("user_info", {})
        if isinstance(ui.get("body"), dict):
            user_id_from_info = ui["body"].get("data", {}).get("user", {}).get("id")
    except Exception:
        pass
    if user_id_from_info:
        try:
            mobile_videos = await _fetch_tiktok_mobile_api(user_id_from_info, username)
            result["mobile_api_result"] = {
                "user_id_used": user_id_from_info,
                "videos_found": len(mobile_videos),
                "sample": mobile_videos[:2] if mobile_videos else [],
            }
        except Exception as e:
            result["mobile_api_result"] = {"user_id_used": user_id_from_info, "error": str(e)}
    else:
        result["mobile_api_result"] = {"skipped": "user_id not available from user_info"}

    # Full pipeline test (TikWm + Mobile API + Playwright + yt-dlp)
    try:
        all_videos = await _fetch_tiktok_videos_async(username, since_days=30, user_id=user_id_from_info)
        result["full_pipeline_result"] = {
            "videos_found": len(all_videos),
            "sample": all_videos[:2] if all_videos else [],
        }
    except Exception as e:
        result["full_pipeline_result"] = {"error": str(e)}

    # Test Playwright directly
    result["playwright_available"] = PLAYWRIGHT_AVAILABLE
    if PLAYWRIGHT_AVAILABLE:
        try:
            scraped = await _scrape_tiktok_playwright(username)
            parsed_vids = _parse_tiktok_videos(scraped)
            result["playwright_result"] = {
                "videos_found": len(parsed_vids),
                "sample": parsed_vids[:2] if parsed_vids else [],
                "raw_keys": list(scraped.keys()) if isinstance(scraped, dict) else type(scraped).__name__,
            }
        except Exception as e:
            result["playwright_result"] = {"error": str(e)[:300]}

    return result


@api_router.get("/debug/instagram/{username}")
async def debug_instagram(username: str):
    """Debug endpoint: tests Instagram verification + video fetching for a public account."""
    username = username.lstrip("@")
    result = {
        "username": username,
        "instaloader_available": INSTALOADER_AVAILABLE,
    }
    # Test 1: Verify account (httpx API + fallbacks)
    try:
        info = await _verify_instagram(username)
        result["verify"] = {
            "status": "success",
            "display_name": info.get("display_name"),
            "follower_count": info.get("follower_count"),
            "avatar_url": info.get("avatar_url"),
        }
    except Exception as e:
        result["verify"] = {"status": "error", "error": str(e)[:200]}
    # Test 2: Fetch videos
    try:
        videos = await _fetch_instagram_videos_async(username, since_days=3650)
        result["videos"] = {
            "count": len(videos),
            "sample": videos[:2] if videos else [],
        }
    except Exception as e:
        result["videos"] = {"error": str(e)[:200]}
    return result


@api_router.get("/debug/youtube/{handle}")
async def debug_youtube(handle: str):
    """Debug endpoint: tests YouTube channel verification + video fetching."""
    result = {
        "handle": handle,
        "youtube_api_key_configured": bool(YOUTUBE_API_KEY),
    }
    if not YOUTUBE_API_KEY:
        result["error"] = "YOUTUBE_API_KEY not configured in Railway env vars. Add it at console.cloud.google.com."
        return result
    # Test 1: Verify channel
    try:
        info = await _verify_youtube(handle)
        result["verify"] = {
            "status": "success",
            "display_name": info.get("display_name"),
            "follower_count": info.get("follower_count"),
            "channel_id": info.get("platform_channel_id"),
        }
        channel_id = info.get("platform_channel_id")
    except Exception as e:
        result["verify"] = {"status": "error", "error": str(e)[:200]}
        channel_id = None
    # Test 2: Fetch videos
    if channel_id:
        try:
            videos = await _fetch_youtube_videos(channel_id, since_days=365)
            result["videos"] = {
                "count": len(videos),
                "sample": videos[:2] if videos else [],
            }
        except Exception as e:
            result["videos"] = {"error": str(e)[:200]}
    return result


@api_router.get("/admin/stats")
async def admin_stats(request: Request, _: bool = Depends(verify_admin_code)):
    users_count = await db.users.count_documents({})
    campaigns_count = await db.campaigns.count_documents({})
    click_campaigns_count = await db.campaigns.count_documents({"payment_model": "clicks"})
    videos_count = await db.tracked_videos.count_documents({})
    accounts_count = await db.social_accounts.count_documents({})
    messages_count = await db.messages.count_documents({})
    members_count = await db.campaign_members.count_documents({})
    # Views earnings
    earnings_agg = await db.earnings.aggregate([{"$group": {"_id": None, "total": {"$sum": "$amount"}}}]).to_list(1)
    total_earnings = earnings_agg[0]["total"] if earnings_agg else 0
    # Click stats (from click_links)
    click_agg = await db.click_links.aggregate([
        {"$group": {"_id": None,
            "total_clicks": {"$sum": "$click_count"},
            "total_unique": {"$sum": "$unique_click_count"},
            "click_earnings": {"$sum": "$earnings"}
        }}
    ]).to_list(1)
    ck = click_agg[0] if click_agg else {}
    # Total views across all tracked_videos
    views_agg = await db.tracked_videos.aggregate([
        {"$group": {"_id": None, "total_views": {"$sum": "$views"}}}
    ]).to_list(1)
    total_views = views_agg[0]["total_views"] if views_agg else 0
    return {
        "users": users_count,
        "campaigns": campaigns_count,
        "click_campaigns": click_campaigns_count,
        "tracked_videos": videos_count,
        "total_views": total_views,
        "social_accounts": accounts_count,
        "messages": messages_count,
        "campaign_members": members_count,
        "total_earnings_eur": round(total_earnings + ck.get("click_earnings", 0), 2),
        "total_clicks": ck.get("total_clicks", 0),
        "total_unique_clicks": ck.get("total_unique", 0),
        "click_earnings_eur": round(ck.get("click_earnings", 0), 2),
    }

@api_router.get("/admin/stats/videos-timeline")
async def admin_videos_timeline(
    request: Request,
    days: int = Query(30, ge=1, le=366),
    _: bool = Depends(verify_admin_code)
):
    """Tracked videos/views timeline. Grouping: hourly (1j), daily (≤90j), monthly (>90j)."""
    from datetime import timedelta
    end = datetime.now(timezone.utc)
    start = end - timedelta(days=days)
    timeline = []

    if days == 1:
        # ── Hourly: last 24h ──────────────────────────────────────────────────
        pipeline = [
            {"$match": {"created_at": {"$gte": start.isoformat()}}},
            {"$group": {
                "_id": {"$substr": ["$created_at", 0, 13]},  # "YYYY-MM-DDTHH"
                "count": {"$sum": 1},
                "views": {"$sum": "$views"}
            }},
            {"$sort": {"_id": 1}}
        ]
        results = await db.tracked_videos.aggregate(pipeline).to_list(25)
        data_map = {r["_id"]: r for r in results}
        current = start.replace(minute=0, second=0, microsecond=0)
        while current <= end:
            key = current.strftime("%Y-%m-%dT%H")
            d = data_map.get(key, {})
            timeline.append({"date": current.strftime("%H:00"), "videos": d.get("count", 0), "views": d.get("views", 0)})
            current += timedelta(hours=1)

    elif days <= 90:
        # ── Daily ─────────────────────────────────────────────────────────────
        pipeline = [
            {"$match": {"created_at": {"$gte": start.isoformat()}}},
            {"$group": {
                "_id": {"$substr": ["$created_at", 0, 10]},
                "count": {"$sum": 1},
                "views": {"$sum": "$views"}
            }},
            {"$sort": {"_id": 1}}
        ]
        results = await db.tracked_videos.aggregate(pipeline).to_list(days + 1)
        data_map = {r["_id"]: r for r in results}
        current = start
        while current <= end:
            day = current.strftime("%Y-%m-%d")
            d = data_map.get(day, {})
            timeline.append({"date": day, "videos": d.get("count", 0), "views": d.get("views", 0)})
            current += timedelta(days=1)

    else:
        # ── Monthly: 1 year ───────────────────────────────────────────────────
        pipeline = [
            {"$match": {"created_at": {"$gte": start.isoformat()}}},
            {"$group": {
                "_id": {"$substr": ["$created_at", 0, 7]},  # "YYYY-MM"
                "count": {"$sum": 1},
                "views": {"$sum": "$views"}
            }},
            {"$sort": {"_id": 1}}
        ]
        results = await db.tracked_videos.aggregate(pipeline).to_list(13)
        data_map = {r["_id"]: r for r in results}
        # Generate all 12 (or 13) monthly buckets
        from calendar import monthrange
        current = start.replace(day=1, hour=0, minute=0, second=0, microsecond=0)
        while current <= end:
            key = current.strftime("%Y-%m")
            d = data_map.get(key, {})
            timeline.append({"date": key, "videos": d.get("count", 0), "views": d.get("views", 0)})
            # Next month
            days_in_month = monthrange(current.year, current.month)[1]
            current = current + timedelta(days=days_in_month)

    return {"timeline": timeline, "period": days}


@api_router.get("/admin/stats/clicks-timeline")
async def admin_clicks_timeline(
    request: Request,
    days: int = Query(30, ge=1, le=366),
    _: bool = Depends(verify_admin_code)
):
    """Click events timeline. Grouping: hourly (1j), daily (≤90j), monthly (>90j)."""
    from datetime import timedelta as _td
    end = datetime.now(timezone.utc)
    start = end - _td(days=days)
    timeline = []

    if days == 1:
        # ── Hourly ────────────────────────────────────────────────────────────
        pipeline = [
            {"$match": {"clicked_at": {"$gte": start.isoformat()}}},
            {"$group": {
                "_id": {"$substr": ["$clicked_at", 0, 13]},
                "clicks": {"$sum": 1},
                "unique_clicks": {"$sum": {"$cond": ["$is_unique", 1, 0]}}
            }},
            {"$sort": {"_id": 1}}
        ]
        results = await db.click_events.aggregate(pipeline).to_list(25)
        data_map = {r["_id"]: r for r in results}
        current = start.replace(minute=0, second=0, microsecond=0)
        while current <= end:
            key = current.strftime("%Y-%m-%dT%H")
            d = data_map.get(key, {})
            timeline.append({"date": current.strftime("%H:00"), "clicks": d.get("clicks", 0), "unique_clicks": d.get("unique_clicks", 0)})
            current += _td(hours=1)

    elif days <= 90:
        # ── Daily ─────────────────────────────────────────────────────────────
        pipeline = [
            {"$match": {"clicked_at": {"$gte": start.isoformat()}}},
            {"$group": {
                "_id": {"$substr": ["$clicked_at", 0, 10]},
                "clicks": {"$sum": 1},
                "unique_clicks": {"$sum": {"$cond": ["$is_unique", 1, 0]}}
            }},
            {"$sort": {"_id": 1}}
        ]
        results = await db.click_events.aggregate(pipeline).to_list(days + 1)
        data_map = {r["_id"]: r for r in results}
        current = start
        while current <= end:
            day = current.strftime("%Y-%m-%d")
            d = data_map.get(day, {})
            timeline.append({"date": day, "clicks": d.get("clicks", 0), "unique_clicks": d.get("unique_clicks", 0)})
            current += _td(days=1)

    else:
        # ── Monthly ───────────────────────────────────────────────────────────
        pipeline = [
            {"$match": {"clicked_at": {"$gte": start.isoformat()}}},
            {"$group": {
                "_id": {"$substr": ["$clicked_at", 0, 7]},
                "clicks": {"$sum": 1},
                "unique_clicks": {"$sum": {"$cond": ["$is_unique", 1, 0]}}
            }},
            {"$sort": {"_id": 1}}
        ]
        results = await db.click_events.aggregate(pipeline).to_list(13)
        data_map = {r["_id"]: r for r in results}
        from calendar import monthrange
        current = start.replace(day=1, hour=0, minute=0, second=0, microsecond=0)
        while current <= end:
            key = current.strftime("%Y-%m")
            d = data_map.get(key, {})
            timeline.append({"date": key, "clicks": d.get("clicks", 0), "unique_clicks": d.get("unique_clicks", 0)})
            days_in_month = monthrange(current.year, current.month)[1]
            current = current + _td(days=days_in_month)

    return {"timeline": timeline, "period": days}

@api_router.get("/admin/campaigns/{campaign_id}/detail")
async def admin_campaign_detail(campaign_id: str, request: Request, _: bool = Depends(verify_admin_code)):
    """Admin: full campaign detail — stats, members, messages."""
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campaign not found")

    # Agency info
    agency = await db.users.find_one({"user_id": campaign.get("agency_id")}, {"_id": 0, "display_name": 1, "name": 1, "email": 1})
    campaign["agency_name"] = (agency or {}).get("display_name") or (agency or {}).get("name", "—")
    campaign["agency_email"] = (agency or {}).get("email", "")

    # Members + user info (batch)
    members = await db.campaign_members.find({"campaign_id": campaign_id}, {"_id": 0}).to_list(200)
    member_ids = [m["user_id"] for m in members]
    user_docs = await db.users.find(
        {"user_id": {"$in": member_ids}},
        {"_id": 0, "user_id": 1, "display_name": 1, "name": 1, "email": 1, "picture": 1, "role": 1}
    ).to_list(200)
    users_map = {u["user_id"]: u for u in user_docs}
    for m in members:
        m["user_info"] = users_map.get(m["user_id"], {})

    # Payment-model–specific stats
    if campaign.get("payment_model") in ("clicks", "both"):
        links = await db.click_links.find({"campaign_id": campaign_id}, {"_id": 0}).to_list(200)
        # Attach clipper info to each link
        link_clipper_ids = [l.get("clipper_id") for l in links if l.get("clipper_id")]
        link_user_docs = await db.users.find(
            {"user_id": {"$in": link_clipper_ids}},
            {"_id": 0, "user_id": 1, "display_name": 1, "name": 1, "picture": 1}
        ).to_list(200)
        link_users_map = {u["user_id"]: u for u in link_user_docs}
        for lnk in links:
            info = link_users_map.get(lnk.get("clipper_id"), {})
            lnk["clipper_display_name"] = info.get("display_name") or info.get("name") or lnk.get("clipper_name", "?")
            lnk["clipper_picture"] = info.get("picture")
        total_clicks = sum(l.get("click_count", 0) for l in links)
        unique_clicks = sum(l.get("unique_click_count", 0) for l in links)
        earnings = round(sum(l.get("earnings", 0) for l in links), 2)
        campaign["click_stats"] = {
            "total_clicks": total_clicks,
            "unique_clicks": unique_clicks,
            "earnings": earnings,
            "links": links,
            "rate_per_click": campaign.get("rate_per_click", 0),
            "unique_clicks_only": campaign.get("unique_clicks_only", True),
        }
    else:
        agg = await db.tracked_videos.aggregate([
            {"$match": {"campaign_id": campaign_id}},
            {"$group": {"_id": None, "total_views": {"$sum": "$views"}, "video_count": {"$sum": 1}}}
        ]).to_list(1)
        s = agg[0] if agg else {}
        campaign["view_stats"] = {
            "total_views": s.get("total_views", 0),
            "video_count": s.get("video_count", 0),
            "budget_used": round((s.get("total_views", 0) / 1000) * campaign.get("rpm", 0), 2),
        }

    # Last 60 messages
    messages = await db.messages.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).sort("created_at", 1).limit(100).to_list(100)
    sender_ids = list({m["sender_id"] for m in messages if m.get("sender_id")})
    sender_docs = await db.users.find(
        {"user_id": {"$in": sender_ids}},
        {"_id": 0, "user_id": 1, "display_name": 1, "name": 1, "picture": 1, "role": 1}
    ).to_list(200)
    senders_map = {u["user_id"]: u for u in sender_docs}
    for msg in messages:
        s = senders_map.get(msg.get("sender_id"), {})
        msg["sender_display_name"] = s.get("display_name") or s.get("name") or msg.get("sender_name", "?")
        msg["sender_picture"] = s.get("picture")
        msg["sender_role_resolved"] = s.get("role") or msg.get("sender_role", "")

    # Tracked videos (top 200 by views)
    tracked_videos = await db.tracked_videos.find(
        {"campaign_id": campaign_id},
        {"_id": 0, "video_id": 1, "url": 1, "title": 1, "platform": 1, "views": 1,
         "likes": 1, "comments": 1, "thumbnail_url": 1, "published_at": 1,
         "earnings": 1, "user_id": 1, "manually_added": 1, "fetched_at": 1}
    ).sort("views", -1).to_list(200)
    vid_user_ids = list({v["user_id"] for v in tracked_videos if v.get("user_id")})
    if vid_user_ids:
        vid_user_docs = await db.users.find(
            {"user_id": {"$in": vid_user_ids}},
            {"_id": 0, "user_id": 1, "display_name": 1, "name": 1}
        ).to_list(200)
        vid_users_map = {u["user_id"]: u for u in vid_user_docs}
        for v in tracked_videos:
            info = vid_users_map.get(v.get("user_id"), {})
            v["clipper_name"] = info.get("display_name") or info.get("name") or "?"
    campaign["tracked_videos"] = tracked_videos

    campaign["members"] = members
    campaign["messages"] = messages
    return campaign

@api_router.post("/admin/campaigns/{campaign_id}/send-message")
async def admin_send_campaign_message(campaign_id: str, request: Request, _: bool = Depends(verify_admin_code)):
    """Admin sends a message into a campaign chat (visible to all members)."""
    body = await request.json()
    content = body.get("content", "").strip()
    if not content:
        raise HTTPException(status_code=400, detail="content requis")
    now = datetime.now(timezone.utc).isoformat()
    msg = {
        "message_id": f"msg_{uuid.uuid4().hex[:12]}",
        "campaign_id": campaign_id,
        "sender_id": "admin",
        "sender_name": "Admin The Clip Deal",
        "sender_role": "admin",
        "content": content,
        "created_at": now,
        "is_admin": True,
    }
    await db.messages.insert_one(msg)
    msg.pop("_id", None)
    # Broadcast to campaign members via WebSocket
    await manager.broadcast_to_campaign(campaign_id, {"type": "new_message", "message": msg})
    return msg

