@api_router.get("/admin/scraping-history")
async def admin_get_scraping_history(
    request: Request,
    limit: int = 200,
    source: Optional[str] = None,
    apify_only: bool = False,
    _: bool = Depends(verify_admin_code)
):
    """Admin : historique des appels de scraping pour traquer l'utilisation des sources."""
    query = {}
    if source:
        query["source"] = source
    if apify_only:
        query["is_apify"] = True

    history = await db.scraping_history.find(query, {"_id": 0}).sort("timestamp", -1).to_list(limit)

    # Stats agregees sur les 24 dernieres heures
    last_24h = (datetime.now(timezone.utc) - timedelta(hours=24)).isoformat()
    pipeline = [
        {"$match": {"timestamp": {"$gte": last_24h}}},
        {"$group": {
            "_id": "$source",
            "count": {"$sum": 1},
            "successes": {"$sum": {"$cond": ["$success", 1, 0]}},
            "videos_total": {"$sum": "$video_count"},
        }},
        {"$sort": {"count": -1}}
    ]
    stats_24h = await db.scraping_history.aggregate(pipeline).to_list(50)

    # Compteur Apify aujourd'hui
    today_start = datetime.now(timezone.utc).replace(hour=0, minute=0, second=0, microsecond=0).isoformat()
    apify_today = await db.scraping_history.count_documents({
        "is_apify": True,
        "success": True,
        "timestamp": {"$gte": today_start}
    })

    # Total apify ce mois
    month_start = datetime.now(timezone.utc).replace(day=1, hour=0, minute=0, second=0, microsecond=0).isoformat()
    apify_month_pipeline = [
        {"$match": {"is_apify": True, "success": True, "timestamp": {"$gte": month_start}}},
        {"$group": {"_id": None, "count": {"$sum": 1}, "videos": {"$sum": "$video_count"}}}
    ]
    apify_month_res = await db.scraping_history.aggregate(apify_month_pipeline).to_list(1)
    apify_month_count = apify_month_res[0]["count"] if apify_month_res else 0
    apify_month_videos = apify_month_res[0]["videos"] if apify_month_res else 0

    return {
        "history": history,
        "stats_24h": stats_24h,
        "apify_today_count": apify_today,
        "apify_month_count": apify_month_count,
        "apify_month_videos": apify_month_videos,
        "total": await db.scraping_history.count_documents(query),
    }


@api_router.post("/admin/campaigns/{campaign_id}/force-scrape")
async def admin_force_scrape_campaign(campaign_id: str, request: Request, _: bool = Depends(verify_admin_code)):
    """Admin : force le scraping immediat de TOUS les comptes d'une campagne.
    Auto-cleanup d'abord les usernames sales (URLs) puis attend 30s pour re-verification."""
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")

    # Auto-cleanup : usernames sales sur les comptes de cette campagne
    pre_assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).to_list(500)
    pre_account_ids = [a["account_id"] for a in pre_assignments]
    cleanup_res = await _cleanup_dirty_usernames({"account_id": {"$in": pre_account_ids}})
    if cleanup_res["fixed"] > 0:
        logger.info(f"admin force-scrape: nettoye {cleanup_res['fixed']} usernames sales avant scrape, attente 30s pour re-verification")
        await asyncio.sleep(30)

    # Calcule cutoff = tracking_start_date sinon assigned_at par compte
    campaign_tracking_start = _parse_utc(campaign.get("tracking_start_date"))
    days_back = 30
    if campaign_tracking_start:
        days_back = max(2, int((datetime.now(timezone.utc) - campaign_tracking_start).total_seconds() / 86400) + 2)
        days_back = min(days_back, 365)

    assignments = await db.campaign_social_accounts.find(
        {"campaign_id": campaign_id}, {"_id": 0}
    ).to_list(500)
    if not assignments:
        return {"ok": True, "message": "Aucun compte assigne a cette campagne", "results": []}

    # Lance les scrapes en parallele (max 5 concurrents)
    semaphore = asyncio.Semaphore(5)

    async def _scrape_with_semaphore(assignment):
        async with semaphore:
            acc_id = assignment.get("account_id")
            account = await db.social_accounts.find_one({"account_id": acc_id}, {"_id": 0})
            if not account:
                return {"ok": False, "error": "compte DB introuvable", "username": "?", "platform": "?"}
            cutoff = campaign_tracking_start or _parse_utc(assignment.get("assigned_at")) or datetime.now(timezone.utc) - timedelta(days=30)
            return await _scrape_one_account_into_campaign(
                account, campaign, cutoff, since_days=days_back, wait_verification=False
            )

    results = await asyncio.gather(*[_scrape_with_semaphore(a) for a in assignments], return_exceptions=True)
    final_results = []
    total_inserted = 0
    total_errors = 0
    for r in results:
        if isinstance(r, Exception):
            final_results.append({"ok": False, "error": str(r), "username": "?", "platform": "?"})
            total_errors += 1
        else:
            final_results.append(r)
            if r.get("ok"):
                total_inserted += r.get("inserted", 0)
            else:
                total_errors += 1

    await db.campaigns.update_one(
        {"campaign_id": campaign_id},
        {"$set": {
            "last_force_scrape_at": datetime.now(timezone.utc).isoformat(),
            "last_force_scrape_by": "admin",
        }}
    )

    return {
        "ok": True,
        "campaign_id": campaign_id,
        "campaign_name": campaign.get("name"),
        "accounts_scraped": len(assignments),
        "total_videos_inserted": total_inserted,
        "total_errors": total_errors,
        "since_days": days_back,
        "results": final_results,
    }


@api_router.delete("/admin/campaigns/{campaign_id}")
async def admin_delete_campaign(campaign_id: str, request: Request, _: bool = Depends(verify_admin_code)):
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")
    # Notify agency
    agency_id = campaign.get("agency_id")
    if agency_id:
        agency_user = await db.users.find_one({"user_id": agency_id}, {"_id": 0})
        if agency_user:
            notif = {
                "message_id": f"msg_{uuid.uuid4().hex[:12]}",
                "campaign_id": campaign_id,
                "sender_id": "admin",
                "sender_name": "The Clip Deal — Modération",
                "sender_role": "admin",
                "recipient_id": agency_id,
                "content": f"Votre campagne « {campaign.get('name', campaign_id)} » a été retirée par la plateforme The Clip Deal car elle ne respecte pas nos conditions d'utilisation.",
                "message_type": "admin_notice",
                "created_at": datetime.now(timezone.utc).isoformat()
            }
            await db.messages.insert_one(notif)
    await db.campaigns.delete_one({"campaign_id": campaign_id})
    await db.campaign_members.delete_many({"campaign_id": campaign_id})
    await db.tracked_videos.delete_many({"campaign_id": campaign_id})
    return {"deleted": campaign_id}

