# ================= CLICK TRACKING =================

def _hash_ip(ip: str) -> str:
    """Hash an IP address with salt — never store raw IPs (GDPR)."""
    return hashlib.sha256(f"{CLICK_SALT}:{ip}".encode()).hexdigest()


def _hash_cidr24(ip: str) -> str:
    """Hash le CIDR /24 de l'IP (premier 3 octets pour ipv4).
    Permet de detecter des bots qui rotatent les IPs sur un meme reseau.
    """
    if not ip or ip == "unknown":
        return _hash_ip(ip)
    if ":" in ip:
        # ipv6 : prefix /64 (premier 4 groupes)
        groups = ip.split(":")[:4]
        return _hash_ip(":".join(groups) + "::/64")
    if "." in ip:
        parts = ip.split(".")
        if len(parts) >= 3:
            return _hash_ip(".".join(parts[:3]) + ".0/24")
    return _hash_ip(ip)


# ── ANTI-FRAUDE CLIC : signatures bots/crawlers/headless ───────────────
# Liste etendue : si le UA contient une de ces strings -> on flag bot, on ne facture pas
_BOT_UA_SIGNATURES = [
    # Crawlers et bots generiques
    "bot", "crawler", "spider", "scraper",
    # Automation tools (browser headless)
    "headless", "puppeteer", "playwright", "selenium", "phantomjs", "nightmare", "cypress",
    # CLI HTTP clients (utilises pour scripts/bots)
    "curl/", "wget/", "python-requests", "python-httpx", "python-urllib", "python/",
    "go-http-client", "java/", "okhttp", "axios/", "node-fetch", "got (",
    "libwww-perl", "ruby/", "powershell", "winhttp", "winhttpapi",
    # Social media crawlers (qui pre-fetchent les liens, pas des vrais clics)
    "facebookexternalhit", "twitterbot", "linkedinbot", "whatsapp", "telegrambot",
    "slackbot", "discordbot", "skypeuripreview", "viber", "instagrambot",
    # Search engine crawlers
    "googlebot", "bingbot", "duckduckbot", "yandexbot", "baiduspider", "applebot",
    "ahrefsbot", "semrushbot", "mj12bot", "dotbot", "petalbot", "blexbot",
    "facebot", "rogerbot", "exabot", "sogou", "uptimerobot", "pingdom",
    # Tools de test/monitoring
    "lighthouse", "chrome-lighthouse", "pagespeed", "monitoring", "newrelic",
    "datadog", "site24x7", "statuscake", "linkchecker",
]


def _is_bot_ua(ua: str) -> tuple[bool, str]:
    """Detecte les UAs de bots/crawlers/CLI/automation.
    Retourne (is_bot, raison)."""
    if not ua or not ua.strip():
        return True, "no_user_agent"
    ua_lower = ua.lower()
    if len(ua_lower) < 20:
        return True, "ua_too_short"  # un vrai UA fait 80+ chars
    for sig in _BOT_UA_SIGNATURES:
        if sig in ua_lower:
            return True, f"bot_signature:{sig}"
    # Heuristique : un vrai navigateur a Mozilla/X.X
    if "mozilla/" not in ua_lower:
        return True, "missing_mozilla"
    return False, ""


# ── Rate limiting clics : max 10 clics par IP / minute ─────────────────
_CLICK_RATE_LIMIT_PER_MIN = 10
_CLICK_RATE_TS: dict = {}  # ip_hash -> [timestamps]


def _check_click_rate_limit(ip_hash: str) -> tuple[bool, int]:
    """Retourne (rate_limited, count_last_minute). True si l'IP a depasse 10 clics/min."""
    now = time.time()
    timestamps = _CLICK_RATE_TS.get(ip_hash) or []
    timestamps = [ts for ts in timestamps if now - ts < 60]
    count = len(timestamps)
    if count >= _CLICK_RATE_LIMIT_PER_MIN:
        _CLICK_RATE_TS[ip_hash] = timestamps  # ne pas ajouter
        return True, count
    timestamps.append(now)
    _CLICK_RATE_TS[ip_hash] = timestamps
    # Cleanup global : si plus de 5000 IPs trackees, purge les anciennes
    if len(_CLICK_RATE_TS) > 5000:
        cutoff = now - 60
        _CLICK_RATE_TS_NEW = {k: [t for t in v if t > cutoff] for k, v in _CLICK_RATE_TS.items()}
        _CLICK_RATE_TS.clear()
        _CLICK_RATE_TS.update({k: v for k, v in _CLICK_RATE_TS_NEW.items() if v})
    return False, count + 1


def _get_real_client_ip(request) -> str:
    """Retourne l'IP reelle du client. Priorite :
    1. X-Forwarded-For (premiere IP = client original quand derriere reverse proxy Railway)
    2. request.client.host (IP directe TCP)
    Note: X-Forwarded-For est trustee car Railway met cet header. Un attaquant qui le forge
    sera vu avec son vrai IP TCP par Railway, qui sera dans X-Forwarded-For (ajoute par Railway).
    """
    forwarded = request.headers.get("x-forwarded-for") or ""
    if forwarded:
        # Premiere IP = celle du client (Railway ajoute son IP a la fin)
        ip = forwarded.split(",")[0].strip()
        if ip:
            return ip
    return request.client.host if request.client else "unknown"


def _gen_short_code() -> str:
    """Generate an 8-char alphanumeric short code."""
    alphabet = "abcdefghijkmnpqrstuvwxyz23456789"
    return "".join(secrets.choice(alphabet) for _ in range(8))

async def _record_click_async(link_id: str, short_code: str, campaign_id: str,
                               clipper_id: str, ip_hash: str, user_agent: str,
                               referrer: str, rate_per_click: float, unique_only: bool,
                               click_billing_mode: str = "unique_24h",
                               cidr24_hash: str = "",
                               is_bot: bool = False, bot_reason: str = "",
                               rate_limited: bool = False, rate_count: int = 0):
    """Fire-and-forget: record click event + update counters + recalc earnings.

    ANTI-FRAUDE :
    - is_bot=True : event enregistre comme bot_flagged, PAS facture
    - rate_limited=True : event enregistre mais PAS facture (clic suspect)
    - Detection /24 CIDR : si > 30 clics dans la meme heure depuis le meme /24,
      on flag tous les nouveaux clics comme suspect_cidr_burst, PAS factures.

    click_billing_mode:
      "all"              = tous les clics non-fraud factures
      "unique_24h"       = 1 unique par IP / 24h (rolling window)
      "unique_lifetime"  = 1 unique par IP pour toute la campagne
    """
    try:
        now = datetime.now(timezone.utc).isoformat()
        one_hour_ago = (datetime.now(timezone.utc) - timedelta(hours=1)).isoformat()

        # ── DETECTION CIDR BURST : >30 clics du meme /24 en 1h = fraude reseau ──
        cidr_burst = False
        cidr_burst_count = 0
        if cidr24_hash:
            cidr_burst_count = await db.click_events.count_documents({
                "campaign_id": campaign_id,
                "cidr24_hash": cidr24_hash,
                "clicked_at": {"$gte": one_hour_ago},
            })
            if cidr_burst_count >= 30:
                cidr_burst = True

        # Determine si le clic est suspect (bot, rate-limited, ou burst CIDR)
        is_suspect = bool(is_bot or rate_limited or cidr_burst)
        suspect_reasons = []
        if is_bot:
            suspect_reasons.append(f"bot:{bot_reason}")
        if rate_limited:
            suspect_reasons.append(f"rate_limit:{rate_count}/min")
        if cidr_burst:
            suspect_reasons.append(f"cidr24_burst:{cidr_burst_count}/h")

        # Deduplication via atomic upsert on click_dedup collection (race-condition safe)
        # Uses unique index on _dedup_key (created at startup)
        # NOTE : les clics suspects ne sont JAMAIS comptes comme unique (donc non factures).
        if is_suspect:
            is_unique = False
        elif click_billing_mode == "all":
            is_unique = True
        else:
            if click_billing_mode == "unique_lifetime":
                bucket = "lifetime"
            else:
                # Bucket UTC explicite (anti-decalage minuit)
                bucket = datetime.now(timezone.utc).strftime("%Y-%m-%d")
            dedup_key = f"{link_id}:{ip_hash}:{bucket}"
            try:
                result = await db.click_dedup.update_one(
                    {"_dedup_key": dedup_key},
                    {"$setOnInsert": {"first_at": now, "link_id": link_id, "bucket": bucket}},
                    upsert=True
                )
                is_unique = result.upserted_id is not None
            except Exception as e:
                logger.warning(f"click_dedup upsert error, fallback to find_one: {e}")
                existing = await db.click_dedup.find_one({"_dedup_key": dedup_key})
                is_unique = existing is None

        # Insert click event with full anti-fraud metadata
        await db.click_events.insert_one({
            "event_id": f"clk_{uuid.uuid4().hex[:12]}",
            "link_id": link_id,
            "short_code": short_code,
            "campaign_id": campaign_id,
            "clipper_id": clipper_id,
            "ip_hash": ip_hash,
            "cidr24_hash": cidr24_hash,
            "user_agent": user_agent[:300] if user_agent else "",
            "referrer": referrer[:500] if referrer else "",
            "is_unique": is_unique,
            "is_suspect": is_suspect,
            "suspect_reasons": suspect_reasons,
            "billable": is_unique and not is_suspect,
            "clicked_at": now,
        })

        # Increment counters on the link (UNIQUEMENT pour les clics non-suspects)
        inc_fields = {"click_count": 1}
        if is_unique and not is_suspect:
            inc_fields["unique_click_count"] = 1
        if is_suspect:
            inc_fields["suspect_count"] = 1
        await db.click_links.update_one(
            {"link_id": link_id},
            {"$inc": inc_fields, "$set": {"last_clicked_at": now}}
        )

        # ── Si nouveau cas de fraude detecte : log alerte admin ──
        if cidr_burst and cidr_burst_count == 30:
            # Premier franchissement du seuil : alerte une seule fois
            try:
                await db.fraud_alerts.insert_one({
                    "alert_id": f"alert_{uuid.uuid4().hex[:12]}",
                    "type": "click_cidr_burst",
                    "severity": "warning",
                    "status": "pending",
                    "campaign_id": campaign_id,
                    "clipper_id": clipper_id,
                    "link_id": link_id,
                    "cidr24_hash": cidr24_hash,
                    "count_last_hour": cidr_burst_count,
                    "reason": f"30+ clics en 1h depuis meme reseau /24 pour {short_code}",
                    "details": f"Clipper {clipper_id} - lien {short_code} - reseau {cidr24_hash[:12]} - {cidr_burst_count} clics/h",
                    "created_at": now,
                    "timestamp": now,
                    "resolved": False,
                })
                logger.warning(f"🚨 FRAUDE CLIC : burst /24 detecte pour {short_code} (lien {link_id}), {cidr_burst_count} clics/h")
            except Exception:
                pass

        # Recalculate earnings on the link (uniquement clics non-suspects)
        link = await db.click_links.find_one({"link_id": link_id}, {"_id": 0})
        if link:
            # billable = clics non-suspects et uniques (ou all si mode "all")
            if unique_only:
                billable = int(link.get("unique_click_count") or 0)
            else:
                # En mode "all" : tous les clics non-suspects
                billable = int(link.get("click_count") or 0) - int(link.get("suspect_count") or 0)
                billable = max(0, billable)
            earnings = round((billable / 1000) * rate_per_click, 4)  # tarif par 1000 clics
            await db.click_links.update_one({"link_id": link_id}, {"$set": {"earnings": earnings}})
    except Exception as e:
        logger.warning(f"Click record error for {link_id}: {e}")

_IN_APP_UA_SIGNATURES = [
    "TikTok", "BytedanceWebview", "musical_ly", "aweme",      # TikTok
    "Instagram",                                                # Instagram
    "FBAN", "FBAV", "FB_IAB", "FB4A",                         # Facebook
    "GSA",                                                      # Google (YouTube app iOS)
    "Line/",                                                    # LINE
    "Snapchat",                                                 # Snapchat
]

def _is_inapp_browser(ua: str) -> bool:
    return any(sig.lower() in ua.lower() for sig in _IN_APP_UA_SIGNATURES)

def _normalize_destination_url(url: str) -> str:
    """Force https:// si manquant, supprime espaces, valide format minimal."""
    if not url:
        return "https://theclipdealtrack.com"
    url = url.strip()
    if not url:
        return "https://theclipdealtrack.com"
    # Si pas de protocole, ajoute https://
    if not url.lower().startswith(("http://", "https://")):
        url = "https://" + url
    return url


def _build_breakout_page(destination: str) -> str:
    """HTML : tente d'ouvrir dans navigateur système ou app native (TikTok/Insta).
    Marche sur tout : in-app webview, browser mobile, desktop.
    """
    destination = _normalize_destination_url(destination)
    dest_safe = destination.replace('"', "&quot;").replace("'", "&#39;").replace("<", "&lt;")
    dest_no_proto = destination.replace("https://", "").replace("http://", "")
    # Détecte la plateforme cible pour deep link app native
    import re as _re
    tiktok_match = _re.search(r'tiktok\.com/@?([\w.\-]+)', destination)
    insta_match = _re.search(r'instagram\.com/([\w.\-]+)', destination)
    youtube_match = _re.search(r'(?:youtube\.com/(?:watch\?v=|@)|youtu\.be/)([\w.\-]+)', destination)
    tiktok_user = tiktok_match.group(1) if tiktok_match else ""
    insta_user = insta_match.group(1) if insta_match else ""
    return f"""<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Redirection…</title>
  <style>
    html,body{{margin:0;padding:0;background:#0d0d0d;color:#fff;height:100%;
      font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;
      display:flex;align-items:center;justify-content:center;flex-direction:column}}
    .spinner{{width:34px;height:34px;border:3px solid rgba(255,255,255,.12);
      border-top-color:#f0c040;border-radius:50%;animation:spin .8s linear infinite}}
    @keyframes spin{{to{{transform:rotate(360deg)}}}}
    p{{margin-top:16px;font-size:13px;color:rgba(255,255,255,.4)}}
    a.fallback{{color:#f0c040;margin-top:24px;font-size:14px;text-decoration:none;border:1px solid rgba(240,192,64,.4);padding:10px 18px;border-radius:8px;display:none}}
  </style>
</head>
<body>
  <div class="spinner"></div>
  <p>Redirection…</p>
  <a id="fb" class="fallback" href="{dest_safe}" target="_blank" rel="noopener">Cliquez ici si la page ne s'ouvre pas</a>
  <script>
    var dest = "{dest_safe}";
    var destNoProto = "{dest_no_proto}";
    var ttUser = "{tiktok_user}";
    var igUser = "{insta_user}";
    var ua = navigator.userAgent || '';

    var isIOS     = /iPhone|iPad|iPod/.test(ua);
    var isAndroid = /Android/.test(ua);
    var isTikTokApp = /TikTok|BytedanceWebview|musical_ly|aweme/i.test(ua);
    var isInstaApp  = /Instagram/i.test(ua);
    var isFacebook  = /FBAN|FBAV|FB_IAB|FB4A/i.test(ua);
    var isLine      = /Line\\//i.test(ua);
    var isSnap      = /Snapchat/i.test(ua);
    var isInApp = isTikTokApp || isInstaApp || isFacebook || isLine || isSnap;

    function showFallback() {{
      var fb = document.getElementById('fb');
      if (fb) fb.style.display = 'inline-block';
    }}

    function tryDeepLink() {{
      // Tente d'ouvrir l'app native si destination = TikTok ou Instagram
      var deepLink = null;
      if (ttUser && ttUser.length > 0) {{
        // TikTok : snssdk schema (iOS) ou intent (Android géré séparément)
        deepLink = isIOS ? ('snssdk1233://user/profile/' + encodeURIComponent(ttUser)) : null;
      }} else if (igUser && igUser.length > 0) {{
        deepLink = isIOS ? ('instagram://user?username=' + encodeURIComponent(igUser)) : null;
      }}
      if (deepLink && (isIOS || isAndroid)) {{
        try {{ window.location.replace(deepLink); }} catch(e) {{}}
        // Fallback web après 800ms si l'app n'a pas ouvert
        setTimeout(function() {{ window.location.replace(dest); }}, 800);
        return true;
      }}
      return false;
    }}

    // Ordre : navigateur normal -> direct ; mobile -> deep link puis web ; in-app -> intent ou direct
    if (isAndroid && isInApp) {{
      // In-app Android : tente intent pour ouvrir Chrome
      var intentUrl = 'intent://' + destNoProto +
        '#Intent;scheme=https;action=android.intent.action.VIEW;' +
        'S.browser_fallback_url=' + encodeURIComponent(dest) + ';end';
      try {{ window.location.replace(intentUrl); }} catch(e) {{}}
      setTimeout(function() {{ window.location.replace(dest); }}, 1200);
      setTimeout(showFallback, 3500);
    }} else if ((isIOS || isAndroid) && (ttUser || igUser)) {{
      // Mobile + destination app sociale : tente deep link app native
      if (!tryDeepLink()) {{
        window.location.replace(dest);
      }}
      setTimeout(showFallback, 3500);
    }} else {{
      // Desktop ou mobile vers URL non-app : redirection directe
      window.location.replace(dest);
      setTimeout(showFallback, 2500);
    }}
  </script>
</body>
</html>"""

@app.get("/track/{short_code}")
async def track_click(short_code: str, request: Request):
    """
    Public redirect endpoint — no auth required.
    Records the click and serves a page that escapes in-app WebViews (TikTok/Instagram/YouTube).
    Normal browsers get an immediate JS redirect. In-app browsers get a breakout page.

    ANTI-FRAUDE :
    - Bot User-Agent : event enregistre mais PAS facture
    - Rate limit IP : >10 clics/min meme IP -> event enregistre mais PAS facture
    - Burst CIDR /24 : >30 clics/h depuis meme reseau -> flag suspect, PAS facture
    Le user voit toujours la page (UX preserved), mais la fraude n'est pas remuneree.
    """
    from starlette.responses import RedirectResponse
    link = await db.click_links.find_one({"short_code": short_code, "is_active": True}, {"_id": 0})
    if not link:
        return RedirectResponse(url="https://theclipdealtrack.com", status_code=302)

    campaign = await db.campaigns.find_one({"campaign_id": link["campaign_id"]}, {"_id": 0})
    # IMPORTANT : la campagne est SOURCE DE VERITE. Si l'agence modifie destination_url dans Parametres,
    # ca s'applique IMMEDIATEMENT a tous les liens existants (sans avoir a regenerer).
    destination = (
        (campaign.get("destination_url") if campaign else None)
        or link.get("destination_url")
        or "https://theclipdealtrack.com"
    )
    rate_per_click = (campaign.get("rate_per_click", 0)) if campaign else 0
    click_billing_mode = (campaign.get("click_billing_mode", "unique_24h")) if campaign else "unique_24h"
    unique_only = click_billing_mode != "all"

    # ── ANTI-FRAUDE : detection bot/rate-limit/cidr en amont ──
    ip = _get_real_client_ip(request)
    ip_hash = _hash_ip(ip)
    cidr24_hash = _hash_cidr24(ip)
    user_agent = request.headers.get("user-agent", "")
    referrer = request.headers.get("referer", "")

    is_bot, bot_reason = _is_bot_ua(user_agent)
    rate_limited, rate_count = _check_click_rate_limit(ip_hash)

    # Record click asynchronously — don't block the response
    asyncio.create_task(_record_click_async(
        link["link_id"], short_code, link["campaign_id"],
        link["clipper_id"], ip_hash, user_agent, referrer,
        rate_per_click, unique_only, click_billing_mode,
        cidr24_hash=cidr24_hash,
        is_bot=is_bot, bot_reason=bot_reason,
        rate_limited=rate_limited, rate_count=rate_count,
    ))

    # Always serve the HTML page — JS handles in-app vs normal browser
    # NOTE : meme si le clic est suspect (bot/spam), on sert la page car l'utilisateur
    # final ne doit pas savoir qu'on a detecte la fraude (sinon ils s'adaptent).
    html = _build_breakout_page(destination)
    return HTMLResponse(content=html, status_code=200)

@api_router.post("/campaigns/{campaign_id}/generate-links")
async def generate_click_links(campaign_id: str, user: dict = Depends(get_current_user)):
    """Agency: generate a unique tracking link for each active clipper (idempotent)."""
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")
    if campaign.get("payment_model") not in ("clicks", "both"):
        raise HTTPException(status_code=400, detail="Cette campagne n'est pas au modèle 'clics'")

    members = await db.campaign_members.find(
        {"campaign_id": campaign_id, "role": "clipper", "status": "active"},
        {"_id": 0, "user_id": 1}
    ).to_list(200)

    generated = []
    for m in members:
        existing = await db.click_links.find_one(
            {"campaign_id": campaign_id, "clipper_id": m["user_id"], "is_active": True},
            {"_id": 0}
        )
        if existing:
            generated.append(existing)
            continue
        clipper = await db.users.find_one({"user_id": m["user_id"]}, {"_id": 0, "display_name": 1, "name": 1})
        # Generate unique short code (retry if collision)
        for _ in range(10):
            short_code = _gen_short_code()
            collision = await db.click_links.find_one({"short_code": short_code})
            if not collision:
                break
        link_id = f"lnk_{uuid.uuid4().hex[:12]}"
        backend_url = os.environ.get("BACKEND_URL", "https://api.theclipdealtrack.com")
        link_doc = {
            "link_id": link_id,
            "short_code": short_code,
            "campaign_id": campaign_id,
            "clipper_id": m["user_id"],
            "clipper_name": (clipper or {}).get("display_name") or (clipper or {}).get("name", "?"),
            "destination_url": campaign.get("destination_url", ""),
            "is_active": True,
            "click_count": 0,
            "unique_click_count": 0,
            "earnings": 0.0,
            "created_at": datetime.now(timezone.utc).isoformat(),
            "last_clicked_at": None,
            "tracking_url": f"{backend_url}/track/{short_code}",
        }
        await db.click_links.insert_one(link_doc)
        link_doc.pop("_id", None)
        generated.append(link_doc)

    return {"links": generated, "count": len(generated)}

@api_router.get("/campaigns/{campaign_id}/click-stats")
async def get_campaign_click_stats(
    campaign_id: str,
    period: str = "30d",            # 1d | 7d | 30d | all | custom
    date_from: Optional[str] = None, # YYYY-MM-DD
    date_to: Optional[str] = None,   # YYYY-MM-DD
    clipper_id: Optional[str] = None,  # filter by clipper (used by clipper's own view)
    user: dict = Depends(get_current_user)
):
    """Return click stats + chart data for a click-based campaign. Accessible by agency, manager, clipper."""
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campaign not found")

    # Access check
    role = user.get("role")
    uid = user["user_id"]
    if role == "clipper":
        # Clippers can only see their own stats
        is_member = await db.campaign_members.find_one({"campaign_id": campaign_id, "user_id": uid, "status": "active"})
        if not is_member:
            raise HTTPException(status_code=403, detail="Not a member")
        clipper_id = uid  # force filter to self
    elif role not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Not authorized")

    # Build date range
    now = datetime.now(timezone.utc)
    if period == "1d":
        from_dt = now - timedelta(days=1)
    elif period == "7d":
        from_dt = now - timedelta(days=7)
    elif period == "30d":
        from_dt = now - timedelta(days=30)
    elif period == "custom" and date_from:
        from_dt = datetime.fromisoformat(date_from).replace(tzinfo=timezone.utc)
    else:  # "all"
        from_dt = datetime(2020, 1, 1, tzinfo=timezone.utc)

    if period == "custom" and date_to:
        to_dt = datetime.fromisoformat(date_to).replace(tzinfo=timezone.utc) + timedelta(days=1)
    else:
        to_dt = now + timedelta(days=1)

    from_str = from_dt.isoformat()
    to_str = to_dt.isoformat()

    # Match filter
    match = {
        "campaign_id": campaign_id,
        "clicked_at": {"$gte": from_str, "$lte": to_str}
    }
    if clipper_id:
        match["clipper_id"] = clipper_id

    # Aggregate by day
    pipeline = [
        {"$match": match},
        {"$addFields": {
            "day": {"$substr": ["$clicked_at", 0, 10]}
        }},
        {"$group": {
            "_id": "$day",
            "clicks": {"$sum": 1},
            "unique_clicks": {"$sum": {"$cond": ["$is_unique", 1, 0]}}
        }},
        {"$sort": {"_id": 1}}
    ]
    daily = await db.click_events.aggregate(pipeline).to_list(1000)

    # Build a complete date range
    days_between = max(1, (to_dt - from_dt).days)
    chart = []
    date_map = {d["_id"]: d for d in daily}
    for i in range(min(days_between, 366)):
        day = (from_dt + timedelta(days=i)).strftime("%Y-%m-%d")
        entry = date_map.get(day, {"_id": day, "clicks": 0, "unique_clicks": 0})
        chart.append({
            "date": day,
            "label": (from_dt + timedelta(days=i)).strftime("%d/%m"),
            "clicks": entry.get("clicks", 0),
            "unique_clicks": entry.get("unique_clicks", 0),
        })

    # Global totals for the period
    totals = await db.click_events.aggregate([
        {"$match": match},
        {"$group": {
            "_id": None,
            "total_clicks": {"$sum": 1},
            "unique_clicks": {"$sum": {"$cond": ["$is_unique", 1, 0]}}
        }}
    ]).to_list(1)
    total_clicks = totals[0]["total_clicks"] if totals else 0
    unique_clicks = totals[0]["unique_clicks"] if totals else 0
    rate_per_click = campaign.get("rate_per_click", 0) or 0
    billable = unique_clicks if campaign.get("unique_clicks_only", True) else total_clicks
    total_earnings = round((billable / 1000) * rate_per_click, 2)

    # Per-clipper breakdown (agency only) — batch user lookup
    clippers_data = []
    if role in ["agency", "manager"] and not clipper_id:
        clipper_pipeline = [
            {"$match": match},
            {"$group": {
                "_id": "$clipper_id",
                "clicks": {"$sum": 1},
                "unique_clicks": {"$sum": {"$cond": ["$is_unique", 1, 0]}}
            }}
        ]
        clipper_stats = await db.click_events.aggregate(clipper_pipeline).to_list(100)
        # Batch fetch all clipper users in one query
        clipper_ids = [cs["_id"] for cs in clipper_stats if cs["_id"]]
        user_docs = await db.users.find(
            {"user_id": {"$in": clipper_ids}},
            {"_id": 0, "user_id": 1, "display_name": 1, "name": 1, "picture": 1}
        ).to_list(len(clipper_ids))
        user_map = {u["user_id"]: u for u in user_docs}
        for cs in clipper_stats:
            cu = user_map.get(cs["_id"], {})
            b = cs["unique_clicks"] if campaign.get("unique_clicks_only", True) else cs["clicks"]
            clippers_data.append({
                "clipper_id": cs["_id"],
                "name": cu.get("display_name") or cu.get("name", "?"),
                "picture": cu.get("picture"),
                "clicks": cs["clicks"],
                "unique_clicks": cs["unique_clicks"],
                "earnings": round((b / 1000) * rate_per_click, 2),
            })
        clippers_data.sort(key=lambda x: x["unique_clicks"], reverse=True)

    return {
        "period": period,
        "date_from": from_str[:10],
        "date_to": to_str[:10],
        "total_clicks": total_clicks,
        "unique_clicks": unique_clicks,
        "total_earnings": total_earnings,
        "rate_per_click": rate_per_click,
        "unique_only": campaign.get("unique_clicks_only", True),
        "chart": chart,
        "clippers": clippers_data,
    }


@api_router.get("/campaigns/{campaign_id}/click-links")
async def get_click_links(campaign_id: str, user: dict = Depends(get_current_user)):
    """Agency: get all tracking links + click stats for a campaign."""
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    links = await db.click_links.find(
        {"campaign_id": campaign_id},
        {"_id": 0}
    ).sort("clipper_name", 1).to_list(500)

    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    rate = (campaign.get("rate_per_click", 0)) if campaign else 0
    dest = (campaign.get("destination_url", "")) if campaign else ""
    backend_url = os.environ.get("BACKEND_URL", "https://api.theclipdealtrack.com")
    for lnk in links:
        if not lnk.get("tracking_url"):
            lnk["tracking_url"] = f"{backend_url}/track/{lnk['short_code']}"

    total_clicks = sum(l.get("click_count", 0) for l in links)
    total_unique = sum(l.get("unique_click_count", 0) for l in links)
    total_earnings = round(sum(l.get("earnings", 0) for l in links), 2)

    return {
        "links": links,
        "destination_url": dest,
        "rate_per_click": rate,
        "totals": {"clicks": total_clicks, "unique_clicks": total_unique, "earnings": total_earnings}
    }

@api_router.get("/campaigns/{campaign_id}/my-click-link")
async def get_my_click_link(campaign_id: str, user: dict = Depends(get_current_user)):
    """Clipper: get their own tracking link for a click-based campaign."""
    link = await db.click_links.find_one(
        {"campaign_id": campaign_id, "clipper_id": user["user_id"], "is_active": True},
        {"_id": 0}
    )
    if not link:
        raise HTTPException(status_code=404, detail="Lien introuvable — demande à ton agence de générer les liens")
    backend_url = os.environ.get("BACKEND_URL", "https://api.theclipdealtrack.com")
    if not link.get("tracking_url"):
        link["tracking_url"] = f"{backend_url}/track/{link['short_code']}"
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0, "rate_per_click": 1, "destination_url": 1})
    link["rate_per_click"] = (campaign.get("rate_per_click", 0)) if campaign else 0
    return link

@api_router.post("/campaigns/{campaign_id}/regenerate-link/{clipper_id}")
async def regenerate_click_link(campaign_id: str, clipper_id: str, user: dict = Depends(get_current_user)):
    """Agency: invalidate old link + create a fresh one for a clipper."""
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    # Deactivate old link
    await db.click_links.update_many(
        {"campaign_id": campaign_id, "clipper_id": clipper_id},
        {"$set": {"is_active": False}}
    )
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    clipper = await db.users.find_one({"user_id": clipper_id}, {"_id": 0, "display_name": 1, "name": 1})
    for _ in range(10):
        short_code = _gen_short_code()
        if not await db.click_links.find_one({"short_code": short_code}):
            break
    link_id = f"lnk_{uuid.uuid4().hex[:12]}"
    backend_url = os.environ.get("BACKEND_URL", "https://api.theclipdealtrack.com")
    link_doc = {
        "link_id": link_id,
        "short_code": short_code,
        "campaign_id": campaign_id,
        "clipper_id": clipper_id,
        "clipper_name": (clipper or {}).get("display_name") or (clipper or {}).get("name", "?"),
        "destination_url": (campaign or {}).get("destination_url", ""),
        "is_active": True,
        "click_count": 0,
        "unique_click_count": 0,
        "earnings": 0.0,
        "created_at": datetime.now(timezone.utc).isoformat(),
        "last_clicked_at": None,
        "tracking_url": f"{backend_url}/track/{short_code}",
    }
    await db.click_links.insert_one(link_doc)
    link_doc.pop("_id", None)
    return link_doc

class AddBudgetRequest(BaseModel):
    amount: float  # montant en euros à ajouter

@api_router.patch("/campaigns/{campaign_id}/settings")
async def update_campaign_settings(campaign_id: str, body: dict, user: dict = Depends(get_current_user)):
    """Agency/Manager: edit campaign settings mid-flight or after budget exhaustion.
    - Always editable: name, description, destination_url, rate_per_click, click_window_hours, application_form_enabled, application_questions, platforms, max_clippers, min_views_payout, max_views_payout.
    - RPM editable ONLY when budget exhausted (budget_used >= budget_total) OR budget_unlimited.
    - Cannot change payment_model after creation.
    """
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    # ANTI-FRAUDE : agence bloquee ne peut pas modifier ses campagnes
    if user.get("role") == "agency":
        _check_agency_subscription(user)
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")
    if campaign.get("agency_id") != user.get("user_id") and user.get("role") != "manager":
        raise HTTPException(status_code=403, detail="Non autorisé")

    ALWAYS_EDITABLE = {
        "name", "description", "destination_url", "rate_per_click",
        "click_window_hours", "application_form_enabled", "application_questions",
        "platforms", "max_clippers", "min_view_payout", "max_view_payout",
        "max_strikes", "strike_days",  # Modifiables : combien de strikes max + jours d'inactivite avant strike
        "click_billing_mode",
        "cadence",  # posts/jour minimum
        "tracking_start_date",  # Date debut tracking videos (modifiable apres creation)
    }
    RPM_EDITABLE_WHEN_EXHAUSTED = {"rpm"}

    updates: dict = {}
    budget_total = campaign.get("budget_total") or 0
    budget_used = campaign.get("budget_used") or 0
    budget_unlimited = campaign.get("budget_unlimited", False)
    budget_exhausted = budget_unlimited or (budget_total > 0 and budget_used >= budget_total)

    for key, val in body.items():
        if key in ALWAYS_EDITABLE:
            updates[key] = val
        elif key in RPM_EDITABLE_WHEN_EXHAUSTED:
            if not budget_exhausted:
                raise HTTPException(
                    status_code=400,
                    detail="Le RPM ne peut être modifié qu'une fois la cagnotte épuisée. Rechargez le budget d'abord ou attendez l'épuisement."
                )
            if val is not None:
                updates["rpm"] = float(val)
        elif key == "payment_model":
            raise HTTPException(status_code=400, detail="Le modèle de paiement ne peut pas être modifié après création")

    if not updates:
        raise HTTPException(status_code=400, detail="Aucun champ modifiable fourni")

    # Bloque tracking_start_date > 2 mois en arriere
    if "tracking_start_date" in updates:
        err = _validate_tracking_start_date(updates.get("tracking_start_date"))
        if err:
            raise HTTPException(status_code=400, detail=err)

    # Détecte si tracking_start_date est reculée → besoin de backfill
    old_start = _parse_utc(campaign.get("tracking_start_date"))
    new_start = _parse_utc(updates.get("tracking_start_date")) if "tracking_start_date" in updates else None
    needs_backfill = (
        new_start is not None
        and (old_start is None or new_start < old_start)
    )

    updates["updated_at"] = datetime.now(timezone.utc).isoformat()
    await db.campaigns.update_one({"campaign_id": campaign_id}, {"$set": updates})

    # Si destination_url change, propage a tous les click_links existants
    # (le redirect /track/{code} prend deja campaign.destination_url en priorite,
    #  mais on synchronise les copies pour eviter incohérence dans les listings)
    if "destination_url" in updates:
        new_dest = updates["destination_url"] or ""
        try:
            res = await db.click_links.update_many(
                {"campaign_id": campaign_id},
                {"$set": {"destination_url": new_dest, "updated_at": datetime.now(timezone.utc).isoformat()}}
            )
            logger.info(f"destination_url propagated to {res.modified_count} click_links of campaign {campaign_id}")
        except Exception as e:
            logger.warning(f"Failed to propagate destination_url to click_links: {e}")

    # Backfill : re-scrape tous les comptes de la campagne sur la fenêtre adaptée
    if needs_backfill:
        async def _backfill_campaign(cid: str, cutoff: datetime):
            try:
                cam = await db.campaigns.find_one({"campaign_id": cid}, {"_id": 0})
                if not cam:
                    return
                days_back = max(2, int((datetime.now(timezone.utc) - cutoff).total_seconds() / 86400) + 2)
                # Cap a 730 jours (2 ans) — au-dela les videos sont rarement disponibles via Mobile Clips API
                since_days = min(days_back, 730)
                logger.info(f"Backfill campaign {cid} : tracking_start_date reculée, scrape sur {since_days} jours (cutoff={cutoff.isoformat()})")

                assignments = await db.campaign_social_accounts.find(
                    {"campaign_id": cid}, {"_id": 0}
                ).to_list(500)
                # Parallélise avec semaphore (max 5 simultanés)
                sem = asyncio.Semaphore(5)

                async def _backfill_one(a):
                    async with sem:
                        acc_id = a.get("account_id")
                        if not acc_id:
                            return
                        acc = await db.social_accounts.find_one({"account_id": acc_id}, {"_id": 0})
                        if not acc:
                            return
                        return await _scrape_one_account_into_campaign(
                            acc, cam, cutoff, since_days=since_days, wait_verification=False
                        )

                results = await asyncio.gather(*[_backfill_one(a) for a in assignments], return_exceptions=True)
                ok_count = sum(1 for r in results if isinstance(r, dict) and r.get("ok"))
                err_count = sum(1 for r in results if isinstance(r, Exception) or (isinstance(r, dict) and not r.get("ok")))
                logger.info(f"Backfill campaign {cid} terminé : {ok_count} succès, {err_count} échecs")
            except Exception as e:
                logger.error(f"Backfill campaign {cid} error: {e}")

        asyncio.create_task(_backfill_campaign(campaign_id, new_start))

    updated = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    return {"campaign": updated, "backfill_started": needs_backfill}


@api_router.post("/campaigns/{campaign_id}/leave")
async def leave_campaign(campaign_id: str, user: dict = Depends(get_current_user)):
    """Clipper voluntarily leaves a campaign."""
    if user.get("role") not in ["clipper"]:
        raise HTTPException(status_code=403, detail="Clippeurs uniquement")
    user_id = user["user_id"]
    member = await db.campaign_members.find_one(
        {"campaign_id": campaign_id, "user_id": user_id, "role": "clipper"},
        {"_id": 0}
    )
    if not member:
        raise HTTPException(status_code=404, detail="Vous n'êtes pas membre de cette campagne")
    if member.get("status") in ("left", "rejected"):
        raise HTTPException(status_code=400, detail="Vous avez déjà quitté cette campagne")

    await db.campaign_members.update_one(
        {"campaign_id": campaign_id, "user_id": user_id, "role": "clipper"},
        {"$set": {"status": "left", "left_at": datetime.now(timezone.utc).isoformat()}}
    )
    # Notify agency/manager via WebSocket
    try:
        campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
        if campaign:
            await manager.broadcast_to_campaign(campaign_id, {
                "type": "clipper_left",
                "campaign_id": campaign_id,
                "user_id": user_id,
                "display_name": user.get("display_name") or user.get("name", ""),
            })
    except Exception:
        pass
    return {"message": "Vous avez quitté la campagne"}


@api_router.delete("/campaigns/{campaign_id}")
async def delete_campaign(campaign_id: str, user: dict = Depends(get_current_user)):
    """Agency: delete a campaign.
    Conditions:
      1. Budget must be exhausted (used >= total) OR budget_unlimited=True.
      2. All active clippers must have been paid (no pending payments owed > 0).
    """
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")
    if campaign.get("agency_id") != user.get("user_id") and user.get("role") != "manager":
        raise HTTPException(status_code=403, detail="Non autorisé")

    budget_total = campaign.get("budget_total") or 0
    budget_used = campaign.get("budget_used") or 0
    budget_unlimited = campaign.get("budget_unlimited", False)

    if not budget_unlimited and budget_total > 0 and budget_used < budget_total:
        remaining = round(budget_total - budget_used, 2)
        raise HTTPException(
            status_code=400,
            detail=f"La cagnotte n'est pas encore épuisée. Il reste {remaining}€. Épuisez le budget ou passez en mode illimité avant de supprimer."
        )

    # Check all clippers are paid (total owed ≈ 0)
    active_members = await db.campaign_members.find(
        {"campaign_id": campaign_id, "role": "clipper", "status": {"$in": ["active", "left"]}},
        {"_id": 0, "user_id": 1}
    ).to_list(500)
    clipper_ids = [m["user_id"] for m in active_members]
    rpm = campaign.get("rpm") or 0
    unpaid_count = 0
    if clipper_ids:
        # Mongo aggregation : 2 queries au lieu de 2*N (passe de 2M docs à 2 reduce)
        try:
            views_agg = await db.tracked_videos.aggregate([
                {"$match": {"campaign_id": campaign_id, "user_id": {"$in": clipper_ids}}},
                {"$group": {"_id": "$user_id", "total_views": {"$sum": {"$ifNull": ["$views", 0]}}}}
            ]).to_list(len(clipper_ids))
            views_map = {r["_id"]: r["total_views"] for r in views_agg}
        except Exception as e:
            logger.warning(f"delete_campaign views agg error: {e}")
            views_map = {}
        try:
            paid_agg = await db.payments.aggregate([
                {"$match": {"campaign_id": campaign_id, "user_id": {"$in": clipper_ids}, "status": "confirmed"}},
                {"$group": {"_id": "$user_id", "total_paid": {"$sum": {"$ifNull": ["$amount_eur", 0]}}}}
            ]).to_list(len(clipper_ids))
            paid_map = {r["_id"]: r["total_paid"] for r in paid_agg}
        except Exception as e:
            logger.warning(f"delete_campaign payments agg error: {e}")
            paid_map = {}
        for clipper_user_id in clipper_ids:
            total_views = views_map.get(clipper_user_id, 0)
            owed = round((total_views / 1000) * rpm, 2) if rpm else 0
            paid = round(paid_map.get(clipper_user_id, 0), 2)
            if owed - paid > 0.5:  # 50 cent tolerance
                unpaid_count += 1

    if unpaid_count > 0:
        raise HTTPException(
            status_code=400,
            detail=f"{unpaid_count} clippeur(s) n'ont pas encore été payé(s). Confirmez tous les paiements avant de supprimer la campagne."
        )

    # All conditions met — delete campaign and ALL related data
    await db.campaigns.delete_one({"campaign_id": campaign_id})
    await db.campaign_members.delete_many({"campaign_id": campaign_id})
    await db.messages.delete_many({"campaign_id": campaign_id})
    await db.tracked_videos.delete_many({"campaign_id": campaign_id})
    await db.posts.delete_many({"campaign_id": campaign_id})
    # IMPORTANT : aussi supprimer les assignations de comptes (sinon orphelins
    # qui empechent d'ajouter ces comptes a une autre campagne)
    await db.campaign_social_accounts.delete_many({"campaign_id": campaign_id})
    # Et les liens click si campagne au clic
    await db.click_links.delete_many({"campaign_id": campaign_id})
    # Et l'historique de scraping
    try:
        await db.cascade_debug_log.delete_many({"_id": {"$regex": f"^.*{campaign_id}"}})
    except Exception:
        pass

    return {"message": "Campagne supprimée avec succès"}


@api_router.post("/campaigns/{campaign_id}/add-budget")
async def add_campaign_budget(campaign_id: str, body: AddBudgetRequest, user: dict = Depends(get_current_user)):
    """Agency: add more budget to an existing campaign."""
    if user.get("role") not in ["agency", "manager"]:
        raise HTTPException(status_code=403, detail="Agency/Manager uniquement")
    if body.amount <= 0:
        raise HTTPException(status_code=400, detail="Le montant doit être positif")
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne introuvable")
    if campaign.get("agency_id") != user.get("user_id") and user.get("role") != "manager":
        raise HTTPException(status_code=403, detail="Non autorisé")
    current_budget = campaign.get("budget_total") or 0
    new_budget = round(current_budget + body.amount, 2)
    set_fields: dict = {"budget_total": new_budget, "budget_unlimited": False}
    # Auto-reactivate if the campaign was paused due to budget exhaustion
    if campaign.get("status") == "paused" and campaign.get("paused_reason") == "budget_exhausted":
        set_fields["status"] = "active"
        set_fields["paused_reason"] = None
    await db.campaigns.update_one(
        {"campaign_id": campaign_id},
        {"$set": set_fields}
    )
    updated = await db.campaigns.find_one({"campaign_id": campaign_id}, {"_id": 0})
    return {"budget_total": new_budget, "budget_used": updated.get("budget_used", 0), "status": updated.get("status")}

# Include router
# ================== PROSPECTS SYSTEM (campagnes pré-remplies pour démarcher agences) ==================

def _norm_discord(name: str) -> str:
    """Normalise un pseudo Discord pour matching (lowercase, strip, remove #1234)."""
    if not name:
        return ""
    n = name.strip().lower().lstrip("@")
    # Strip discord discriminator (#1234) si present
    if "#" in n:
        n = n.split("#", 1)[0]
    return n


@api_router.post("/admin/prospects/create-campaign")
async def admin_create_prospect_campaign(request: Request, body: dict, _: bool = Depends(verify_admin_code)):
    """Cree une campagne 'prospect' (sans agence reelle) avec tokens uniques pour claim."""
    name = (body.get("name") or "").strip()
    agency_name = (body.get("agency_name") or "").strip()
    if not name or not agency_name:
        raise HTTPException(status_code=400, detail="name + agency_name requis")
    payment_model = body.get("payment_model") or "views"
    rpm = float(body.get("rpm") or 0)
    rate_per_click = float(body.get("rate_per_click") or 0)
    destination_url = body.get("destination_url") or ""
    platforms = body.get("platforms") or ["tiktok", "instagram", "youtube"]

    cid = f"camp_{uuid.uuid4().hex[:12]}"
    agency_token = secrets.token_urlsafe(16)
    clipper_token = secrets.token_urlsafe(16)
    prospect_user_id = f"prospect_{uuid.uuid4().hex[:8]}"
    now = datetime.now(timezone.utc).isoformat()

    # Cree un "ghost user" agency pour cette campagne prospect
    # (permet a l'admin d'impersonate et voir l'apercu agence avant claim)
    await db.users.insert_one({
        "user_id": prospect_user_id,
        "email": f"prospect+{prospect_user_id}@theclipdealtrack.local",
        "name": agency_name,
        "display_name": agency_name,
        "agency_name": agency_name,
        "role": "agency",
        "email_verified": True,
        "is_prospect_ghost": True,  # marqueur pour pouvoir filtrer/cleanup
        "created_at": now,
    })

    campaign_doc = {
        "campaign_id": cid,
        "name": name,
        "description": body.get("description") or "",
        "agency_id": prospect_user_id,  # placeholder - sera reassigne quand l'agence claim
        "agency_name": agency_name,
        "payment_model": payment_model,
        "rpm": rpm,
        "rate_per_click": rate_per_click,
        "destination_url": destination_url,
        "click_billing_mode": body.get("click_billing_mode") or "unique_24h",
        "unique_clicks_only": (body.get("click_billing_mode") or "unique_24h") != "all",
        "click_window_hours": int(body.get("click_window_hours") or 24),
        "platforms": platforms,
        "max_clippers": body.get("max_clippers") or None,
        "cadence": int(body.get("cadence") or 1),
        "max_strikes": int(body.get("max_strikes") or 3),
        "strike_days": int(body.get("strike_days") or 3),
        "budget_total": float(body.get("budget_total") or 0),
        "budget_used": 0,
        "budget_unlimited": bool(body.get("budget_unlimited", True)),
        # Application form (candidature) - identique a une vraie campagne agence
        "application_form_enabled": bool(body.get("application_form_enabled", True)),
        "application_questions": body.get("application_questions") or [],
        # Min/max payout
        "min_view_payout": int(body.get("min_view_payout") or 0),
        "max_view_payout": body.get("max_view_payout") or None,
        # Date debut tracking (modifiable apres creation)
        "tracking_start_date": body.get("tracking_start_date") or now,
        # Image de couverture
        "image_url": body.get("image_url") or "",
        "status": "active",
        "is_prospect": True,
        "prospect_agency_token": agency_token,
        "prospect_clipper_token": clipper_token,
        "created_at": now,
        "updated_at": now,
    }
    await db.campaigns.insert_one(campaign_doc)
    campaign_doc.pop("_id", None)
    return {
        "campaign": campaign_doc,
        "claim_links": {
            "agency": f"/claim/agency/{agency_token}",
            "clipper": f"/claim/clipper/{clipper_token}",
        }
    }


@api_router.post("/admin/prospects/{campaign_id}/add-clipper-account")
async def admin_add_prospect_clipper(campaign_id: str, body: dict, _: bool = Depends(verify_admin_code)):
    """Ajoute un compte social (TikTok/Insta/YT) avec pseudo Discord pour matching futur."""
    campaign = await db.campaigns.find_one({"campaign_id": campaign_id, "is_prospect": True})
    if not campaign:
        raise HTTPException(status_code=404, detail="Campagne prospect introuvable")
    discord_username = _norm_discord(body.get("discord_username") or "")
    platform = (body.get("platform") or "").lower()
    raw_username = (body.get("username") or "").strip()
    # Si l'admin a colle une URL au lieu d'un handle, on extrait le handle
    if _looks_like_url_or_dirty(raw_username):
        username = extract_handle_from_url(raw_username, platform)
    else:
        username = raw_username
    username = (username or "").strip().lstrip("@").strip("/")
    if not discord_username or not platform or not username:
        raise HTTPException(status_code=400, detail="discord_username + platform + username requis")
    if platform not in ("tiktok", "instagram", "youtube"):
        raise HTTPException(status_code=400, detail="platform invalide")

    # Cree un social_account "ghost" : pas encore claim par un user
    account_id = f"acc_{uuid.uuid4().hex[:12]}"
    now = datetime.now(timezone.utc).isoformat()
    account_doc = {
        "account_id": account_id,
        "user_id": None,  # pas encore claim
        "platform": platform,
        "username": username,
        "discord_username": discord_username,
        "status": "verified",
        "is_prospect": True,
        "prospect_campaign_id": campaign_id,
        "created_at": now,
        "verified_at": now,
    }
    await db.social_accounts.insert_one(account_doc)
    # Pre-assigne le compte a la campagne (sans user_id pour l'instant)
    await db.campaign_social_accounts.insert_one({
        "campaign_id": campaign_id,
        "account_id": account_id,
        "user_id": None,
        "discord_username": discord_username,
        "is_prospect": True,
        "assigned_at": now,
    })
    account_doc.pop("_id", None)
    return {"account": account_doc}


@api_router.get("/admin/prospects/{campaign_id}/clipper-accounts")
async def admin_list_prospect_accounts(campaign_id: str, _: bool = Depends(verify_admin_code)):
    """Liste tous les comptes sociaux pre-enregistres pour une campagne prospect."""
    accounts = await db.social_accounts.find(
        {"prospect_campaign_id": campaign_id, "is_prospect": True},
        {"_id": 0}
    ).sort("discord_username", 1).to_list(500)
    # Group by discord_username
    grouped = {}
    for acc in accounts:
        d = acc.get("discord_username") or "?"
        if d not in grouped:
            grouped[d] = []
        grouped[d].append({"account_id": acc["account_id"], "platform": acc["platform"], "username": acc["username"]})
    return {"by_discord": grouped, "total": len(accounts)}


@api_router.delete("/admin/prospects/clipper-accounts/{account_id}")
async def admin_delete_prospect_account(account_id: str, _: bool = Depends(verify_admin_code)):
    """Supprime un compte social pre-enregistre prospect (avant claim)."""
    res = await db.social_accounts.delete_one({"account_id": account_id, "is_prospect": True})
    if res.deleted_count == 0:
        raise HTTPException(status_code=404, detail="Compte introuvable ou deja claim")
    await db.campaign_social_accounts.delete_one({"account_id": account_id})
    return {"ok": True}


@api_router.get("/admin/prospects")
async def admin_list_prospects(request: Request, _: bool = Depends(verify_admin_code)):
    """Liste toutes les campagnes prospects avec leur stats."""
    campaigns = await db.campaigns.find({"is_prospect": True}, {"_id": 0}).sort("created_at", -1).to_list(200)
    out = []
    for c in campaigns:
        cid = c["campaign_id"]
        accounts = await db.social_accounts.count_documents({"prospect_campaign_id": cid, "is_prospect": True})
        videos = await db.tracked_videos.count_documents({"campaign_id": cid})
        views_agg = await db.tracked_videos.aggregate([
            {"$match": {"campaign_id": cid}},
            {"$group": {"_id": None, "total": {"$sum": "$views"}}}
        ]).to_list(1)
        total_views = views_agg[0]["total"] if views_agg else 0
        out.append({
            **c,
            "prospect_accounts_count": accounts,
            "tracked_videos_count": videos,
            "total_views": total_views,
        })
    return {"prospects": out}


@api_router.get("/claim/info/{token}")
async def claim_info(token: str):
    """Public : retourne infos minimales sur le claim (agence ou clipper)."""
    camp = await db.campaigns.find_one({
        "$or": [{"prospect_agency_token": token}, {"prospect_clipper_token": token}],
        "is_prospect": True
    }, {"_id": 0, "name": 1, "agency_name": 1, "payment_model": 1, "rpm": 1, "rate_per_click": 1, "prospect_agency_token": 1, "prospect_clipper_token": 1, "campaign_id": 1})
    if not camp:
        raise HTTPException(status_code=404, detail="Lien invalide ou expire")
    is_agency = camp.get("prospect_agency_token") == token
    return {
        "type": "agency" if is_agency else "clipper",
        "campaign_name": camp.get("name"),
        "agency_name": camp.get("agency_name"),
        "payment_model": camp.get("payment_model"),
        "rpm": camp.get("rpm"),
        "rate_per_click": camp.get("rate_per_click"),
    }


@api_router.post("/claim/agency/{token}")
async def claim_agency(token: str, body: dict, request: Request):
    """L'agence cree son compte via le lien magique et reprend la campagne."""
    camp = await db.campaigns.find_one({"prospect_agency_token": token, "is_prospect": True}, {"_id": 0})
    if not camp:
        raise HTTPException(status_code=404, detail="Lien invalide ou deja utilise")
    email = (body.get("email") or "").lower().strip()
    password = body.get("password") or ""
    display_name = (body.get("display_name") or camp.get("agency_name") or "Agence").strip()
    if not email or not password:
        raise HTTPException(status_code=400, detail="email + password requis")
    pwd_error = _validate_password(password)
    if pwd_error:
        raise HTTPException(status_code=400, detail=pwd_error)

    # Check email pas deja pris
    existing = await db.users.find_one({"email": email}, {"_id": 0})
    if existing:
        raise HTTPException(status_code=409, detail="Email deja utilise - connecte-toi puis recharge ce lien")

    # Cree l'agence avec trial 14j Business automatique
    user_id = f"user_{uuid.uuid4().hex[:12]}"
    now = datetime.now(timezone.utc).isoformat()
    await db.users.insert_one({
        "user_id": user_id,
        "email": email,
        "password_hash": _hash_password(password),
        "name": display_name,
        "display_name": display_name,
        "role": "agency",
        "agency_name": camp.get("agency_name") or display_name,
        "email_verified": True,  # claim direct = valide
        "created_at": now,
        "subscription_status": "trial",
        "trial_started_at": now,
    })

    # Reassigne la campagne a cette agence + retire le flag prospect
    old_agency_id = camp.get("agency_id")
    await db.campaigns.update_one(
        {"campaign_id": camp["campaign_id"]},
        {"$set": {"agency_id": user_id, "is_prospect": False},
         "$unset": {"prospect_agency_token": "", "prospect_clipper_token": ""}}
    )
    # Supprime le ghost user si c'etait un prospect ghost
    if old_agency_id and old_agency_id.startswith("prospect_"):
        await db.users.delete_one({"user_id": old_agency_id, "is_prospect_ghost": True})

    # Cree session immediate
    session_token = secrets.token_urlsafe(32)
    expires_at = datetime.now(timezone.utc) + timedelta(days=8)
    await db.user_sessions.insert_one({
        "session_token": session_token,
        "user_id": user_id,
        "expires_at": expires_at.isoformat(),
        "created_at": now,
    })
    return {"session_token": session_token, "user": {"user_id": user_id, "email": email, "role": "agency", "display_name": display_name}, "campaign_id": camp["campaign_id"]}


@api_router.post("/claim/agency/{token}/finalize")
async def claim_agency_finalize(token: str, user: dict = Depends(get_current_user)):
    """Finalise le claim agence pour un user DEJA cree (typiquement via Google OAuth).
    Reassigne la campagne prospect a cet user_id."""
    camp = await db.campaigns.find_one({"prospect_agency_token": token, "is_prospect": True}, {"_id": 0})
    if not camp:
        raise HTTPException(status_code=404, detail="Lien invalide ou deja utilise")
    # Promouvoir le user en agency si pas deja + active trial 14j Business si pas encore
    update_set = {"role": "agency"}
    if not user.get("subscription_status"):
        update_set["subscription_status"] = "trial"
        update_set["trial_started_at"] = datetime.now(timezone.utc).isoformat()
    await db.users.update_one({"user_id": user["user_id"]}, {"$set": update_set})
    old_agency_id = camp.get("agency_id")
    await db.campaigns.update_one(
        {"campaign_id": camp["campaign_id"]},
        {"$set": {"agency_id": user["user_id"], "is_prospect": False},
         "$unset": {"prospect_agency_token": "", "prospect_clipper_token": ""}}
    )
    if old_agency_id and old_agency_id.startswith("prospect_"):
        await db.users.delete_one({"user_id": old_agency_id, "is_prospect_ghost": True})
    return {"campaign_id": camp["campaign_id"]}


@api_router.post("/claim/clipper/{token}/finalize")
async def claim_clipper_finalize(token: str, body: dict, user: dict = Depends(get_current_user)):
    """Finalise le claim clipper pour un user DEJA cree (Google OAuth).
    Body: { discord_username }. Auto-link comptes pre-enregistres."""
    camp = await db.campaigns.find_one({"prospect_clipper_token": token}, {"_id": 0})
    if not camp:
        raise HTTPException(status_code=404, detail="Lien invalide")
    discord_username = _norm_discord(body.get("discord_username") or "")
    if not discord_username:
        raise HTTPException(status_code=400, detail="discord_username requis")
    user_id = user["user_id"]
    now = datetime.now(timezone.utc).isoformat()
    # Save discord_username sur user
    await db.users.update_one({"user_id": user_id}, {"$set": {"discord_username": discord_username, "role": "clipper"}})
    # Auto-link
    matching_accounts = await db.social_accounts.find(
        {"discord_username": discord_username, "is_prospect": True, "user_id": None}, {"_id": 0}
    ).to_list(50)
    linked = []
    for acc in matching_accounts:
        await db.social_accounts.update_one({"account_id": acc["account_id"]}, {"$set": {"user_id": user_id, "is_prospect": False}})
        await db.campaign_social_accounts.update_one({"account_id": acc["account_id"]}, {"$set": {"user_id": user_id, "is_prospect": False}})
        prospect_cid = acc.get("prospect_campaign_id")
        if prospect_cid:
            existing_member = await db.campaign_members.find_one({"campaign_id": prospect_cid, "user_id": user_id})
            if not existing_member:
                await db.campaign_members.insert_one({
                    "member_id": f"mem_{uuid.uuid4().hex[:12]}", "campaign_id": prospect_cid, "user_id": user_id,
                    "role": "clipper", "status": "active", "strikes": 0, "joined_at": now,
                })
        linked.append({"platform": acc["platform"], "username": acc["username"]})
    return {"linked_count": len(linked), "linked_accounts": linked, "campaign_id": camp.get("campaign_id")}


@api_router.post("/admin/preview-as/{user_id}")
async def admin_preview_as(user_id: str, response: Response, request: Request, _: bool = Depends(verify_admin_code)):
    """Pose un cookie session_token pour le user demande + retourne ok. Plus simple que Bearer."""
    target = await db.users.find_one({"user_id": user_id}, {"_id": 0, "user_id": 1, "role": 1, "display_name": 1, "name": 1, "email": 1})
    if not target and user_id.startswith("prospect_"):
        # Cree ghost user a la volee pour les anciennes campagnes prospects
        camp = await db.campaigns.find_one({"agency_id": user_id}, {"_id": 0, "agency_name": 1, "name": 1})
        if camp:
            agency_name = camp.get("agency_name") or camp.get("name") or "Agence prospect"
            now_iso = datetime.now(timezone.utc).isoformat()
            ghost = {
                "user_id": user_id, "email": f"prospect+{user_id}@theclipdealtrack.local",
                "name": agency_name, "display_name": agency_name, "agency_name": agency_name,
                "role": "agency", "email_verified": True, "is_prospect_ghost": True, "created_at": now_iso,
            }
            await db.users.insert_one(ghost)
            target = ghost
    if not target:
        raise HTTPException(status_code=404, detail=f"User {user_id} introuvable")
    session_token = secrets.token_urlsafe(32)
    expires_at = datetime.now(timezone.utc) + timedelta(hours=2)
    await db.user_sessions.insert_one({
        "session_token": session_token, "user_id": user_id,
        "expires_at": expires_at.isoformat(), "created_at": datetime.now(timezone.utc).isoformat(),
        "is_admin_impersonation": True,
    })
    # Set le cookie immediatement -> le navigateur le posera sur le domaine
    response.set_cookie(
        key="session_token", value=session_token,
        max_age=7200, samesite="lax", httponly=False,
        path="/", secure=request.url.scheme == "https",
    )
    return {"ok": True, "user": {"user_id": target["user_id"], "role": target.get("role"), "display_name": target.get("display_name") or target.get("name") or target.get("email")}}


@api_router.post("/admin/impersonate/{user_id}")
async def admin_impersonate(user_id: str, request: Request, _: bool = Depends(verify_admin_code)):
    """Cree une session temporaire en tant qu'un autre user. Permet a l'admin d'agir comme l'agence pour test."""
    target = await db.users.find_one({"user_id": user_id}, {"_id": 0, "user_id": 1, "email": 1, "role": 1, "display_name": 1, "name": 1})
    if not target:
        # Si c'est un prospect_xxx qui manque, on le cree a la volee depuis sa campagne
        if user_id.startswith("prospect_"):
            camp = await db.campaigns.find_one({"agency_id": user_id}, {"_id": 0, "agency_name": 1, "name": 1})
            if camp:
                agency_name = camp.get("agency_name") or camp.get("name") or "Agence prospect"
                now_iso = datetime.now(timezone.utc).isoformat()
                ghost_user = {
                    "user_id": user_id,
                    "email": f"prospect+{user_id}@theclipdealtrack.local",
                    "name": agency_name,
                    "display_name": agency_name,
                    "agency_name": agency_name,
                    "role": "agency",
                    "email_verified": True,
                    "is_prospect_ghost": True,
                    "created_at": now_iso,
                }
                await db.users.insert_one(ghost_user)
                target = {k: v for k, v in ghost_user.items() if k != "_id"}
        if not target:
            raise HTTPException(status_code=404, detail=f"User {user_id} introuvable et pas de campagne prospect associee")
    session_token = secrets.token_urlsafe(32)
    expires_at = datetime.now(timezone.utc) + timedelta(hours=2)  # session courte 2h
    await db.user_sessions.insert_one({
        "session_token": session_token,
        "user_id": user_id,
        "expires_at": expires_at.isoformat(),
        "created_at": datetime.now(timezone.utc).isoformat(),
        "is_admin_impersonation": True,
    })
    return {
        "session_token": session_token,
        "user": {"user_id": target["user_id"], "email": target.get("email"), "role": target.get("role"), "display_name": target.get("display_name") or target.get("name")},
        "expires_in_hours": 2,
    }


@api_router.post("/claim/clipper/{token}")
async def claim_clipper(token: str, body: dict, request: Request):
    """Le clippeur cree son compte via lien magique. Si pseudo Discord matche un compte pre-enregistre -> auto-link."""
    camp = await db.campaigns.find_one({"prospect_clipper_token": token}, {"_id": 0})
    if not camp:
        raise HTTPException(status_code=404, detail="Lien invalide")
    email = (body.get("email") or "").lower().strip()
    password = body.get("password") or ""
    display_name = (body.get("display_name") or "").strip()
    discord_username = _norm_discord(body.get("discord_username") or "")
    if not email or not password or not discord_username:
        raise HTTPException(status_code=400, detail="email + password + discord_username requis")
    pwd_error = _validate_password(password)
    if pwd_error:
        raise HTTPException(status_code=400, detail=pwd_error)

    existing = await db.users.find_one({"email": email}, {"_id": 0})
    if existing:
        raise HTTPException(status_code=409, detail="Email deja utilise")

    # Cree le clipper
    user_id = f"user_{uuid.uuid4().hex[:12]}"
    now = datetime.now(timezone.utc).isoformat()
    await db.users.insert_one({
        "user_id": user_id,
        "email": email,
        "password_hash": _hash_password(password),
        "name": display_name or discord_username,
        "display_name": display_name or discord_username,
        "discord_username": discord_username,
        "role": "clipper",
        "email_verified": True,
        "created_at": now,
    })

    # Auto-link : trouve TOUS les comptes pre-enregistres avec ce discord_username
    matching_accounts = await db.social_accounts.find(
        {"discord_username": discord_username, "is_prospect": True, "user_id": None},
        {"_id": 0}
    ).to_list(50)
    linked_accounts = []
    for acc in matching_accounts:
        # Reassigne le compte au nouveau user
        await db.social_accounts.update_one(
            {"account_id": acc["account_id"]},
            {"$set": {"user_id": user_id, "is_prospect": False}}
        )
        # Reassigne le campaign_social_account
        await db.campaign_social_accounts.update_one(
            {"account_id": acc["account_id"]},
            {"$set": {"user_id": user_id, "is_prospect": False}}
        )
        # Ajoute le user comme membre de la campagne associee
        prospect_cid = acc.get("prospect_campaign_id")
        if prospect_cid:
            existing_member = await db.campaign_members.find_one({"campaign_id": prospect_cid, "user_id": user_id})
            if not existing_member:
                await db.campaign_members.insert_one({
                    "member_id": f"mem_{uuid.uuid4().hex[:12]}",
                    "campaign_id": prospect_cid,
                    "user_id": user_id,
                    "role": "clipper",
                    "status": "active",
                    "strikes": 0,
                    "joined_at": now,
                })
        linked_accounts.append({"platform": acc["platform"], "username": acc["username"], "campaign_id": prospect_cid})

    # Session immediate
    session_token = secrets.token_urlsafe(32)
    expires_at = datetime.now(timezone.utc) + timedelta(days=8)
    await db.user_sessions.insert_one({
        "session_token": session_token,
        "user_id": user_id,
        "expires_at": expires_at.isoformat(),
        "created_at": now,
    })
    return {
        "session_token": session_token,
        "user": {"user_id": user_id, "email": email, "role": "clipper", "display_name": display_name or discord_username},
        "linked_accounts": linked_accounts,
        "linked_count": len(linked_accounts),
        "campaign_id": camp.get("campaign_id"),
    }


app.include_router(api_router)

ALLOWED_ORIGINS = os.environ.get("FRONTEND_URL", "http://localhost:3000")
_origins = [o.strip() for o in ALLOWED_ORIGINS.split(",") if o.strip()]

# CORS strict en prod : pas de localhost
if not _IS_PRODUCTION:
    if "http://localhost:3000" not in _origins:
        _origins.append("http://localhost:3000")
    if "http://localhost:3001" not in _origins:
        _origins.append("http://localhost:3001")
else:
    logger.info(f"CORS strict mode (production) : origines autorisees = {_origins}")

# Methodes autorisees (au lieu de "*") pour CORS strict
_ALLOWED_METHODS = ["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"]
# Headers : on autorise les headers usuels + ceux qu'on utilise reellement
_ALLOWED_HEADERS = [
    "Content-Type", "Authorization", "X-Admin-Code", "Accept", "Origin",
    "X-Requested-With", "Cookie", "Set-Cookie",
]

app.add_middleware(
    CORSMiddleware,
    allow_credentials=True,
    allow_origins=_origins,
    allow_methods=_ALLOWED_METHODS,
    allow_headers=_ALLOWED_HEADERS,
)

@app.on_event("startup")
async def startup_event():
    # ── MongoDB indexes — idempotent, safe to re-run ───────────────────────
    indexes = [
        # tracked_videos — unique per (account, campaign, platform_video_id) to allow same URL in multiple campaigns
        (db.tracked_videos, [("account_id", 1), ("campaign_id", 1), ("platform_video_id", 1)], {"unique": True, "sparse": True}),
        (db.tracked_videos, [("user_id", 1)], {}),
        (db.tracked_videos, [("campaign_id", 1)], {}),
        # messages
        (db.message_reads, [("user_id", 1), ("campaign_id", 1)], {"unique": True}),
        (db.messages, [("campaign_id", 1), ("created_at", 1)], {}),
        (db.messages, [("sender_id", 1)], {}),
        # click tracking
        (db.click_links, [("short_code", 1)], {"unique": True}),
        (db.click_links, [("campaign_id", 1), ("clipper_id", 1)], {}),
        (db.click_links, [("clipper_id", 1), ("is_active", 1)], {}),
        (db.click_events, [("link_id", 1), ("ip_hash", 1), ("clicked_at", 1)], {}),
        (db.click_events, [("campaign_id", 1), ("clicked_at", -1)], {}),
        (db.click_events, [("clipper_id", 1), ("clicked_at", -1)], {}),
        (db.click_events, [("campaign_id", 1), ("is_unique", 1)], {}),
        # click_dedup — atomic unique constraint pour prevention race condition (audit 200 clippeurs)
        (db.click_dedup, [("_dedup_key", 1)], {"unique": True, "name": "dedup_key_unique"}),
        # campaigns + members
        (db.campaigns, [("agency_id", 1)], {}),
        (db.campaigns, [("status", 1)], {}),
        (db.campaign_members, [("user_id", 1), ("status", 1)], {}),
        (db.campaign_members, [("campaign_id", 1), ("status", 1)], {}),
        # sessions — TTL: auto-delete expired sessions after 8 days
        (db.user_sessions, [("expires_at", 1)], {"expireAfterSeconds": 0, "name": "sessions_ttl"}),
        (db.user_sessions, [("session_token", 1)], {"unique": True}),
        # social accounts
        (db.social_accounts, [("user_id", 1)], {}),
        (db.social_accounts, [("status", 1)], {}),
        # announcements
        (db.announcements, [("created_at", -1)], {}),
        # message comments
        (db.message_comments, [("message_id", 1), ("created_at", 1)], {}),
        # posts (for views aggregation)
        (db.posts, [("campaign_id", 1), ("user_id", 1)], {}),
        (db.posts, [("user_id", 1)], {}),
        # advices (for manager reminder batch query)
        (db.advices, [("campaign_id", 1), ("recipient_ids", 1), ("created_at", -1)], {}),
        (db.advices, [("manager_id", 1), ("created_at", -1)], {}),
        # users (primary key lookup)
        (db.users, [("user_id", 1)], {"unique": True}),
        (db.users, [("email", 1)], {"unique": True}),
        # campaign_social_accounts
        (db.campaign_social_accounts, [("campaign_id", 1)], {}),
        (db.campaign_social_accounts, [("user_id", 1)], {}),
        # views_snapshots
        (db.views_snapshots, [("campaign_id", 1), ("date", -1)], {}),
        # views_snapshots_hourly (granularite horaire pour graph 24h)
        (db.views_snapshots_hourly, [("campaign_id", 1), ("scraped_at", -1)], {}),
        (db.views_snapshots_hourly, [("campaign_id", 1), ("hour_key", 1)], {"unique": True, "sparse": True}),
        # user_views_snapshots (per clipper, per campaign, per day)
        (db.user_views_snapshots, [("campaign_id", 1), ("user_id", 1), ("date", -1)], {}),
        # video_views_snapshots : evolution quotidienne PAR VIDEO (vraies donnees historiques)
        (db.video_views_snapshots, [("video_id", 1), ("date", -1)], {}),
        (db.video_views_snapshots, [("campaign_id", 1), ("date", -1)], {}),
        (db.video_views_snapshots, [("video_id", 1), ("date", 1)], {"unique": True, "name": "video_date_unique"}),
        # payments
        (db.payments, [("user_id", 1), ("campaign_id", 1)], {}),
        (db.payments, [("agency_id", 1)], {}),
        (db.payments, [("gc_payment_id", 1)], {"sparse": True}),
        # tracked_videos : index pour graph par published_at + agregation
        (db.tracked_videos, [("campaign_id", 1), ("published_at", -1)], {}),
        (db.tracked_videos, [("campaign_id", 1), ("user_id", 1), ("published_at", -1)], {}),
        # GoCardless flows
        (db.gocardless_flows, [("flow_id", 1)], {"unique": True, "sparse": True}),
        (db.gocardless_flows, [("user_id", 1), ("status", 1)], {}),
        # strikes (anti-doublon par jour)
        (db.strikes, [("strike_id", 1)], {"unique": True, "sparse": True}),
        (db.strikes, [("campaign_id", 1), ("user_id", 1), ("created_at", -1)], {}),
        # expulsion_requests
        (db.expulsion_requests, [("expulsion_id", 1)], {"unique": True, "sparse": True}),
        (db.expulsion_requests, [("campaign_id", 1), ("status", 1)], {}),
        # click_links / click_events / click_dedup
        (db.click_links, [("campaign_id", 1), ("clipper_id", 1), ("is_active", 1)], {}),
        (db.click_links, [("short_code", 1)], {"unique": True, "sparse": True}),
        (db.click_events, [("link_id", 1), ("clicked_at", -1)], {}),
        (db.click_events, [("campaign_id", 1), ("clicked_at", -1)], {}),
        # scraping_history (logs de chaque tentative pour traquer les usages Apify)
        (db.scraping_history, [("timestamp", -1)], {}),
        (db.scraping_history, [("source", 1), ("timestamp", -1)], {}),
        (db.scraping_history, [("is_apify", 1), ("timestamp", -1)], {}),
        (db.scraping_history, [("platform", 1), ("username", 1), ("timestamp", -1)], {}),
        # rate_limits (TTL auto pour rate limit persistant, survit aux restarts)
        (db.rate_limits, [("expireAt", 1)], {"expireAfterSeconds": 0, "name": "rate_limits_ttl"}),
        (db.rate_limits, [("key", 1), ("timestamp", -1)], {}),
    ]
    for collection, keys, opts in indexes:
        try:
            await collection.create_index(keys, **opts)
        except Exception as e:
            logger.debug(f"Index already exists or minor error: {e}")

    # ── Drop old bad index: (account_id, platform_video_id) was unique, caused
    #    DuplicateKeyError when adding same YouTube/Instagram URL to 2 campaigns ──
    try:
        existing = await db.tracked_videos.index_information()
        for name, info in existing.items():
            key_fields = [k[0] for k in info.get("key", [])]
            if key_fields == ["account_id", "platform_video_id"] and info.get("unique"):
                await db.tracked_videos.drop_index(name)
                logger.info(f"Startup: dropped old unique index '{name}' on tracked_videos")
    except Exception as e:
        logger.debug(f"Old index cleanup: {e}")

    # ── Clean up expired sessions (belt + suspenders alongside TTL index) ──
    try:
        now_iso = datetime.now(timezone.utc).isoformat()
        res = await db.user_sessions.delete_many({"expires_at": {"$lt": now_iso}})
        if res.deleted_count:
            logger.info(f"Startup: purged {res.deleted_count} expired sessions.")
    except Exception as e:
        logger.warning(f"Session cleanup failed: {e}")

    # Purge all simulated/fake videos that may have been inserted by old code versions.
    # Simulated videos have simulated=True OR platform_video_id starting with "sim_".
    try:
        result = await db.tracked_videos.delete_many({
            "$or": [
                {"simulated": True},
                {"platform_video_id": {"$regex": "^sim_"}},
            ]
        })
        if result.deleted_count > 0:
            logger.info(f"Startup: purged {result.deleted_count} simulated/fake videos from DB.")
    except Exception as e:
        logger.warning(f"Startup simulated video purge failed: {e}")

    asyncio.create_task(auto_strike_loop())
    asyncio.create_task(track_videos_loop())
    # Watchdog : surveille la sante des APIs (Insta/TikTok/YouTube) toutes les heures
    # Si 3 echecs consecutifs sur une plateforme = alerte critique admin
    asyncio.create_task(watchdog_loop())

    # ═══ HEALTH CHECK STARTUP : log CLAIREMENT ce qui est configure ═══
    # Permet de voir au boot Railway ce qui marche et ce qui manque
    config_status = []
    config_status.append(f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
    config_status.append(f"  CONFIG SCRAPING — verifie au demarrage Railway")
    config_status.append(f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
    config_status.append(f"  YOUTUBE_API_KEY              : {'✅ SET' if YOUTUBE_API_KEY else '❌ MISSING — YouTube ne marchera PAS'}")
    config_status.append(f"  APIFY_TOKEN                  : {'✅ SET' if APIFY_TOKEN else '❌ MISSING — fallback paye indispo'}")
    config_status.append(f"  APIFY_INSTA_FORCE_OFF        : {'⚠️ ON (kill switch)' if _APIFY_INSTA_KILL_SWITCH else '✅ OFF (Apify Insta dispo)'}")
    config_status.append(f"  BACKEND_PROXY_URL            : {'✅ SET' if BACKEND_PROXY_URL else '⚠️ MISSING — Insta sans proxy fragile'}")
    config_status.append(f"  CLIP_SCRAPER_URL             : {'✅ SET' if CLIP_SCRAPER_URL else '⚠️ MISSING — VPS scraper indisponible'}")
    config_status.append(f"  CLIP_SCRAPER_KEY             : {'✅ SET' if CLIP_SCRAPER_KEY else '⚠️ MISSING'}")
    config_status.append(f"  TIKWM_API_KEY                : {'✅ SET' if TIKWM_API_KEY else '⚠️ MISSING — TikWm indispo'}")
    config_status.append(f"  RAPIDAPI_KEY                 : {'✅ SET' if RAPIDAPI_KEY else '⚠️ MISSING'}")
    config_status.append(f"  INSTAGRAM_SESSIONS           : {'✅ ' + str(len(INSTAGRAM_SESSIONS)) + ' sessions' if INSTAGRAM_SESSIONS else '⚠️ MISSING'}")
    config_status.append(f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
    # Verdict
    has_youtube = bool(YOUTUBE_API_KEY)
    has_apify = bool(APIFY_TOKEN) and not _APIFY_INSTA_KILL_SWITCH
    has_proxy_or_vps = bool(BACKEND_PROXY_URL or (CLIP_SCRAPER_URL and CLIP_SCRAPER_KEY))
    if has_youtube and has_apify:
        config_status.append(f"  VERDICT : ✅ Scraping operationnel")
        if not has_proxy_or_vps:
            config_status.append(f"            (Insta/TikTok via Apify uniquement = paye)")
    elif has_apify:
        config_status.append(f"  VERDICT : ⚠️ YouTube manquant (set YOUTUBE_API_KEY gratuit)")
    elif has_proxy_or_vps:
        config_status.append(f"  VERDICT : ⚠️ Pas de fallback Apify (set APIFY_TOKEN)")
    else:
        config_status.append(f"  VERDICT : 🚨 AUCUNE source configuree — scraping IMPOSSIBLE")
        config_status.append(f"            URGENT : configure YOUTUBE_API_KEY (gratuit) +")
        config_status.append(f"            APIFY_TOKEN ou BACKEND_PROXY_URL ou CLIP_SCRAPER_URL")
    config_status.append(f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
    for line in config_status:
        logger.info(line)

    # Test TikWm API key at startup and log the result
    if TIKWM_API_KEY:
        try:
            async with httpx.AsyncClient(timeout=10) as c:
                r = await c.get(
                    "https://www.tikwm.com/api/user/posts",
                    params={"unique_id": "tiktok", "count": 1, "cursor": 0, "key": TIKWM_API_KEY},
                    headers={"User-Agent": "Mozilla/5.0", "Referer": "https://www.tikwm.com/"},
                )
                if r.status_code == 200 and r.json().get("code") == 0:
                    logger.info("✅ TikWm API key is valid — full automatic TikTok tracking enabled.")
                else:
                    logger.warning(f"⚠️ TikWm API key may be invalid (HTTP {r.status_code}, code={r.json().get('code')})")
        except Exception as e:
            logger.warning(f"⚠️ TikWm API key test failed: {e}")
    else:
        logger.warning(
            "⚠️ TIKWM_API_KEY not set. TikTok tracking limited to search results (~2-3 videos/account). "
            "Get a free key at tikwm.com and add TIKWM_API_KEY to Railway env vars."
        )

@app.on_event("shutdown")
async def shutdown_db_client():
    client.close()

# ================= AUTO STRIKE BACKGROUND TASK =================

async def auto_strike_loop():
    """Run every hour — check cadence violations and issue strikes automatically."""
    while True:
        try:
            await check_and_issue_strikes()
        except Exception as e:
            logger.error(f"Auto strike check failed: {e}")
        await asyncio.sleep(3600)  # every hour

async def check_and_issue_strikes():
    now = datetime.now(timezone.utc)
    campaigns = await db.campaigns.find({"status": "active"}, {"_id": 0}).to_list(500)

    # Pre-fetch agencies pour verifier le plan (strikes auto desactives sur plans click-only)
    # Inclut email + subscription_bypass pour _is_bypass_account
    agency_ids = list({c.get("agency_id") for c in campaigns if c.get("agency_id")})
    agencies = await db.users.find(
        {"user_id": {"$in": agency_ids}},
        {"_id": 0, "user_id": 1, "subscription_status": 1, "subscription_plan": 1,
         "trial_started_at": 1, "subscription_bypass": 1, "email": 1, "role": 1}
    ).to_list(len(agency_ids)) if agency_ids else []
    agency_map = {a["user_id"]: a for a in agencies}

    for campaign in campaigns:
        campaign_id = campaign["campaign_id"]

        # Skip si l'agence est sur un plan click-only (pas de strikes auto sur ces plans)
        agency = agency_map.get(campaign.get("agency_id"))
        if agency:
            limits = _get_plan_limits(agency)
            if limits.get("click_only"):
                continue  # Plans click-only n'ont pas de strikes auto

        strike_days = campaign.get("strike_days", 3)
        max_strikes = campaign.get("max_strikes", 3)
        is_clicks_campaign = campaign.get("payment_model") in ("clicks", "both")

        members = await db.campaign_members.find(
            {"campaign_id": campaign_id, "role": "clipper", "status": "active"},
            {"_id": 0}
        ).to_list(500)

        for member in members:
            user_id = member["user_id"]
            # Pour les campagnes au clic : "last_post_at" = max(last_post, last click_link cree, last click recu)
            # Pour les campagnes au vue : "last_post_at" classique (ou tracked_videos recente)
            last_activity = None
            lp = member.get("last_post_at")
            if lp:
                try:
                    last_activity = datetime.fromisoformat(lp.replace("Z", "+00:00")) if isinstance(lp, str) else lp
                    if last_activity.tzinfo is None:
                        last_activity = last_activity.replace(tzinfo=timezone.utc)
                except (ValueError, AttributeError):
                    pass

            # Pour TOUS les types de campagne (vue ET clic) : check derniere video postee
            # Le strike se base sur l'activite "poster une video" peu importe le payment_model
            try:
                last_vid = await db.tracked_videos.find_one(
                    {"campaign_id": campaign_id, "user_id": user_id},
                    {"_id": 0, "fetched_at": 1, "published_at": 1},
                    sort=[("published_at", -1)]
                )
                if last_vid:
                    for k in ("published_at", "fetched_at"):
                        v = last_vid.get(k)
                        if v:
                            try:
                                dt = datetime.fromisoformat(v.replace("Z", "+00:00")) if isinstance(v, str) else v
                                if dt.tzinfo is None:
                                    dt = dt.replace(tzinfo=timezone.utc)
                                if not last_activity or dt > last_activity:
                                    last_activity = dt
                            except Exception:
                                pass
            except Exception:
                pass

            if not last_activity:
                # Aucune activite -> check joined_at
                joined_at = member.get("joined_at")
                if not joined_at:
                    continue
                try:
                    if isinstance(joined_at, str):
                        joined_at = datetime.fromisoformat(joined_at.replace("Z", "+00:00"))
                    if joined_at.tzinfo is None:
                        joined_at = joined_at.replace(tzinfo=timezone.utc)
                except (ValueError, AttributeError):
                    continue
                days_inactive = (now - joined_at).days
            else:
                days_inactive = (now - last_activity).days

            if days_inactive >= strike_days:
                # Strike ID déterministe basé sur date du jour : empêche les doublons même sous race condition
                strike_day_key = now.strftime("%Y%m%d")
                strike_id = f"auto_{campaign_id}_{member['user_id']}_{strike_day_key}"

                # Upsert atomique : si déjà un strike auto aujourd'hui, ne crée rien
                upsert_result = await db.strikes.update_one(
                    {"strike_id": strike_id},
                    {"$setOnInsert": {
                        "strike_id": strike_id,
                        "campaign_id": campaign_id,
                        "user_id": member["user_id"],
                        "reason": f"Inactivité de {days_inactive} jours (seuil : {strike_days} jours)",
                        "auto": True,
                        "created_at": now.isoformat(),
                    }},
                    upsert=True
                )
                # Si pas inserted, c'est un doublon → skip
                if upsert_result.upserted_id is None:
                    continue

                # Compteur de strikes en atomique via $inc — évite race condition
                from pymongo import ReturnDocument
                updated_member = await db.campaign_members.find_one_and_update(
                    {"member_id": member["member_id"]},
                    {"$inc": {"strikes": 1}},
                    return_document=ReturnDocument.AFTER
                )
                new_strikes = (updated_member or {}).get("strikes", member.get("strikes", 0) + 1)

                if new_strikes >= max_strikes:
                    # Au lieu de suspendre auto, on cree une demande d'expulsion en attente
                    # que l'agence valide/refuse depuis l'onglet Candidatures
                    expulsion_id = f"expel_{campaign_id}_{member['user_id']}"
                    expulsion_doc = {
                        "expulsion_id": expulsion_id,
                        "campaign_id": campaign_id,
                        "user_id": member["user_id"],
                        "reason": f"Max strikes atteint ({new_strikes}/{max_strikes}) - inactivite {days_inactive}j",
                        "strikes_at_request": new_strikes,
                        "status": "pending",  # pending | approved | rejected
                        "created_at": now.isoformat(),
                    }
                    await db.expulsion_requests.update_one(
                        {"expulsion_id": expulsion_id, "status": "pending"},
                        {"$setOnInsert": expulsion_doc},
                        upsert=True
                    )
                    logger.info(f"Clipper {member['user_id']} - expulsion request created for campaign {campaign_id} (waiting agency approval)")

                # Notify clipper via WebSocket
                await manager.send_to_user(member["user_id"], {
                    "type": "strike_issued",
                    "campaign_id": campaign_id,
                    "campaign_name": campaign.get("name", ""),
                    "strikes": new_strikes,
                    "suspended": new_strikes >= max_strikes
                })

                # Notify agency/creator via WebSocket
                campaign_creator_id = campaign.get("agency_id") or campaign.get("created_by") or campaign.get("user_id")
                if campaign_creator_id:
                    clipper_user = await db.users.find_one({"user_id": member["user_id"]}, {"_id": 0, "display_name": 1, "name": 1})
                    clipper_name = (clipper_user or {}).get("display_name") or (clipper_user or {}).get("name") or member["user_id"]
                    await manager.send_to_user(campaign_creator_id, {
                        "type": "agency_strike_notification",
                        "campaign_id": campaign_id,
                        "campaign_name": campaign.get("name", ""),
                        "clipper_id": member["user_id"],
                        "clipper_name": clipper_name,
                        "strikes": new_strikes,
                        "suspended": new_strikes >= max_strikes,
                        "reason": f"Inactivité de {days_inactive} jours (seuil : {strike_days} jours)"
                    })
